    function normalizeHscale(n) {
      return Math.round(n);
    }

    function hscaleEqual(a, b) {
      return Math.abs(a - b) < HSCALE_EPS;
    }

    function formatHscaleValue(n) {
      const normalized = normalizeHscale(n);
      return Number.isInteger(normalized) ? String(normalized) : String(normalized);
    }

    function clampHscale(value) {
      let n = typeof value === 'number' ? value : parseFloat(String(value).trim());
      if (!Number.isFinite(n)) n = 1;
      return normalizeHscale(Math.min(HSCALE_MAX, Math.max(HSCALE_MIN, n)));
    }

    function readHscaleFromSource(source) {
      const h = source && source.config && source.config.hscale;
      if (typeof h === 'number' && Number.isFinite(h) && h > 0) return clampHscale(h);
      return 1;
    }

    function readHscaleFromJsonText(jsonText) {
      try {
        return readHscaleFromSource(JSON.parse(jsonText));
      } catch (e) {
        return 1;
      }
    }

    function getWaveUnitWidth(jsonText, parsedSource) {
      const hscale = parsedSource ? readHscaleFromSource(parsedSource) : readHscaleFromJsonText(jsonText);
      return WAVE_UNIT_WIDTH * hscale;
    }

    function updateHscaleInSource(text, newHscale) {
      const h = clampHscale(newHscale);
      try {
        JSON.parse(text);
      } catch (e) {
        return null;
      }

      const block = findTopLevelKeyBlock(text, 'config');
      if (block) {
        const slice = text.slice(block.start, block.end);
        const hscaleRe = /"hscale"\s*:\s*-?[\d.]+/;
        const m = slice.match(hscaleRe);
        if (m) {
          const abs = block.start + m.index;
          return text.slice(0, abs) + '"hscale": ' + h + text.slice(abs + m[0].length);
        }
        const configIndent = getIndentAt(text, block.start);
        const propIndent = configIndent + '  ';
        const insertBefore = block.end - 1;
        const inner = text.slice(block.start + 1, block.end - 1).trim();
        const prefix = inner ? ',\n' + propIndent : '\n' + propIndent;
        const insertion = prefix + '"hscale": ' + h + '\n' + configIndent;
        return text.slice(0, insertBefore) + insertion + text.slice(insertBefore);
      }

      const rootClose = text.lastIndexOf('}');
      if (rootClose < 0) return null;
      const rootIndent = getIndentAt(text, rootClose) || '  ';
      const beforeClose = text.slice(0, rootClose).replace(/\s*$/, '');
      const hasContent = /"\w+"\s*:/.test(beforeClose);
      const insertion = (hasContent ? ',\n' : '\n') + rootIndent + '"config": { "hscale": ' + h + ' }\n';
      return beforeClose + insertion + text.slice(rootClose);
    }

    function syncHscaleInputFromJson(jsonText, parsedSource) {
      if (!hscaleInput) return;
      const h = parsedSource ? readHscaleFromSource(parsedSource) : readHscaleFromJsonText(jsonText);
      const current = parseFloat(hscaleInput.value);
      if (Number.isFinite(current) && hscaleEqual(current, h)) return;
      isUpdatingHscaleFromJson = true;
      hscaleInput.value = formatHscaleValue(h);
      isUpdatingHscaleFromJson = false;
    }

    function applyHscaleFromInput() {
      if (isUpdatingHscaleFromJson || !hscaleInput) return;
      const newH = clampHscale(hscaleInput.value);
      hscaleInput.value = formatHscaleValue(newH);
      const current = readHscaleFromJsonText(editor.value);
      if (hscaleEqual(newH, current)) return;

      const newText = updateHscaleInSource(editor.value, newH);
      if (!newText || newText === editor.value) {
        setStatus(false, 'JSON 错误，无法更新 hscale');
        return;
      }

      pushUndoBeforeChange();
      applyEditorChange(newText, editor.selectionStart, editor.selectionEnd);
      scheduleFormatAfterWaveChange();
    }

    function flushUndoDebounce() {
      clearTimeout(saveTimer);
      saveTimer = null;
    }

    function nextHistorySequence() {
      historySequence += 1;
      return historySequence;
    }

    function getHistorySequence(entry) {
      return entry && Number.isFinite(entry.sequence) ? entry.sequence : 0;
    }

    function getEditorHistoryContent(entry) {
      return entry && typeof entry === 'object' && typeof entry.content === 'string'
        ? entry.content
        : String(entry == null ? '' : entry);
    }

    function setEditorHistoryBaseline(text) {
      const value = text == null ? '' : String(text);
      editorHistoryBaseline = value;
      lastSavedContent = value;
      directJsonEditDirty = false;
      undoBurstCaptured = false;
    }

    function markDirectJsonEdit() {
      if (isApplyingHistory) return;
      directJsonEditDirty = editor.value !== editorHistoryBaseline;
      updateUndoRedoButtons();
    }

    function pushEditorUndoSnapshot(content, reason) {
      undoStack.push({
        content: String(content == null ? '' : content),
        sequence: nextHistorySequence(),
        reason: reason || 'editor-change'
      });
      if (undoStack.length > 100) undoStack.shift();
      redoStack = [];
      waveLibraryRedoStack = [];
    }

    function checkpointDirectJsonEdit(reason) {
      if (isApplyingHistory) return false;
      const current = editor.value;
      if (current === editorHistoryBaseline) {
        directJsonEditDirty = false;
        return false;
      }
      const previous = editorHistoryBaseline;
      pushEditorUndoSnapshot(previous, reason || 'direct-json-interval');
      setEditorHistoryBaseline(current);
      updateUndoRedoButtons();
      vwdDebugLog('history', {
        phase: 'json-checkpoint',
        reason: reason || 'direct-json-interval',
        documentName: editingWaveDocumentName || '',
        previousLength: previous.length,
        currentLength: current.length,
        undoDepth: undoStack.length
      });
      return true;
    }

    function startDirectJsonEditMonitor() {
      if (directJsonEditMonitorTimer !== null) clearInterval(directJsonEditMonitorTimer);
      directJsonEditMonitorTimer = setInterval(() => {
        checkpointDirectJsonEdit('direct-json-interval');
      }, DIRECT_JSON_HISTORY_INTERVAL_MS);
    }

    function finalizeUndoBurst() {
      checkpointDirectJsonEdit('editor-blur');
    }

    function captureUndoIfNeeded() {
      markDirectJsonEdit();
    }

    function pushUndoBeforeChange() {
      if (isApplyingHistory) return;
      flushUndoDebounce();
      checkpointDirectJsonEdit('before-toolbar-change');
      pushEditorUndoSnapshot(editor.value, 'toolbar-change');
      setEditorHistoryBaseline(editor.value);
      updateUndoRedoButtons();
    }

    function replaceFieldInSource(text, entry, field, newValue, dataIdx) {
      const slice = text.slice(entry.start, entry.end);
      if (field === 'name') {
        const re = /"name"\s*:\s*"([^"\\]|\\.)*"/;
        const m = slice.match(re);
        if (!m) return text;
        const abs = entry.start + m.index;
        return text.slice(0, abs) + '"name": ' + JSON.stringify(newValue) + text.slice(abs + m[0].length);
      }
      if (field === 'wave') {
        const re = /"wave"\s*:\s*"([^"\\]|\\.)*"/;
        const m = slice.match(re);
        if (!m) return text;
        const abs = entry.start + m.index;
        return text.slice(0, abs) + '"wave": ' + JSON.stringify(newValue) + text.slice(abs + m[0].length);
      }
      if (field === 'data') {
        const re = /"data"\s*:\s*\[[^\]]*\]/;
        const m = slice.match(re);
        let dataArr = entry.signal.data ? entry.signal.data.slice() : [];
        while (dataArr.length <= dataIdx) dataArr.push('');
        dataArr[dataIdx] = newValue;
        if (m) {
          const abs = entry.start + m.index;
          return text.slice(0, abs) + '"data": ' + JSON.stringify(dataArr) + text.slice(abs + m[0].length);
        }
        const waveRe = /"wave"\s*:\s*"([^"\\]|\\.)*"/;
        const wm = slice.match(waveRe);
        if (!wm) return text;
        const abs = entry.start + wm.index + wm[0].length;
        const inner = getIndentAt(text, entry.start) + '  ';
        return text.slice(0, abs) + ',\n' + inner + '"data": ' + JSON.stringify(dataArr) + text.slice(abs);
      }
      if (field === 'description') {
        const descRe = /"(?:description|describe)"\s*:\s*"([^"\\]|\\.)*"/;
        const existing = slice.match(descRe);
        if (existing) {
          const key = '"description"';
          const abs = entry.start + existing.index;
          return text.slice(0, abs) + key + ': ' + JSON.stringify(newValue) + text.slice(abs + existing[0].length);
        }

        const insertionRefs = [
          /"node"\s*:\s*"([^"\\]|\\.)*"/,
          /"wave"\s*:\s*"([^"\\]|\\.)*"/,
          /"name"\s*:\s*"([^"\\]|\\.)*"/
        ];
        let insertAt = -1;
        for (let i = 0; i < insertionRefs.length; i++) {
          const m = slice.match(insertionRefs[i]);
          if (m) {
            insertAt = entry.start + m.index + m[0].length;
            break;
          }
        }
        if (insertAt < 0) {
          insertAt = Math.max(entry.start + 1, entry.end - 1);
        }
        if (insertAt < entry.start || insertAt > entry.end) return text;
        const beforeInsert = text.slice(0, insertAt);
        const afterInsert = text.slice(insertAt);
        const needsComma = !/,\s*$/.test(beforeInsert.slice(entry.start, insertAt));
        const indent = getIndentAt(text, entry.start) + '  ';
        const insertion = (needsComma ? ',\n' : '\n') + indent + '"description": ' + JSON.stringify(newValue);
        return beforeInsert + insertion + afterInsert;
      }
      return text;
    }

    function applyWaveTemplateToSignal(existing, template) {
      const merged = Object.assign({}, existing, { wave: template.wave });
      if (template.data) merged.data = template.data.slice();
      else delete merged.data;
      return merged;
    }

    function getUseTranslateX(useEl) {
      const x = useEl.getAttribute('x');
      if (x != null && x !== '') return parseFloat(x) || 0;
      const tr = useEl.getAttribute('transform') || '';
      const m = tr.match(/translate\(\s*([\d.+-]+)/);
      return m ? parseFloat(m[1]) : 0;
    }

    function getDrawUses(drawGroup) {
      return [...drawGroup.querySelectorAll('use')]
        .sort((a, b) => getUseTranslateX(a) - getUseTranslateX(b));
    }

    function getEffectiveWaveChar(wave, index) {
      let eff = 'x';
      for (let i = 0; i <= index; i++) {
        if (wave[i] !== '.') eff = wave[i];
      }
      return eff;
    }

    function reserveUsesForChar(wave, index) {
      const raw = wave[index];
      const eff = raw === '.' ? getEffectiveWaveChar(wave, index) : raw;
      if (eff === '|') {
        const prevEff = index > 0 ? getEffectiveWaveChar(wave, index - 1) : 'x';
        if (prevEff === 'p' || prevEff === 'n') return 0;
        return 2;
      }
      if (eff === 'p' || eff === 'n') return 2;
      return 2;
    }

    function allocateUsesToWaveChars(wave, useCount) {
      const n = wave.length;
      if (n === 0) return [];
      const alloc = new Array(n).fill(0);
      let ui = 0;

      for (let i = 0; i < n; i++) {
        const usesLeft = useCount - ui;
        if (usesLeft <= 0) break;

        let take = reserveUsesForChar(wave, i);
        const remainingChars = n - i - 1;

        if (i === n - 1) {
          take = usesLeft;
        } else {
          let reserve = 0;
          for (let j = i + 1; j < n; j++) {
            reserve += reserveUsesForChar(wave, j);
          }
          if (reserve > usesLeft) reserve = remainingChars * 2;
          take = Math.min(Math.max(take, 0), Math.max(0, usesLeft - reserve));
          if (take === 0 && usesLeft > 0) {
            take = Math.max(1, Math.floor(usesLeft / (remainingChars + 1)));
          }
        }

        alloc[i] = take;
        ui += take;
      }

      if (ui < useCount) alloc[n - 1] += useCount - ui;
      if (ui > useCount) {
        let excess = ui - useCount;
        for (let i = n - 1; i >= 0 && excess > 0; i--) {
          const drop = Math.min(alloc[i], excess);
          alloc[i] -= drop;
          excess -= drop;
        }
      }
      return alloc;
    }

    function getDrawGroupContentWidth(drawGroup, unitWidth) {
      const step = unitWidth || WAVE_UNIT_WIDTH;
      try {
        const bbox = drawGroup.getBBox();
        if (bbox.width > step * 0.25) return bbox.width;
      } catch (e) { /* ignore */ }
      try {
        const lane = drawGroup.closest('[id^="wavelane_"]');
        if (lane) {
          const laneBbox = lane.getBBox();
          const drawBbox = drawGroup.getBBox();
          const nameWidth = drawBbox.x - laneBbox.x;
          const contentWidth = laneBbox.width - nameWidth;
          if (contentWidth > step * 0.25) return contentWidth;
        }
      } catch (e) { /* ignore */ }
      return step * 8;
    }

    function getWaveColumnWidth(unitWidth) {
      return (unitWidth || WAVE_UNIT_WIDTH) * 2;
    }

    function buildVirtualColumnMap(numCols, unitWidth) {
      const step = getWaveColumnWidth(unitWidth);
      const cols = [];
      for (let i = 0; i < numCols; i++) {
        cols.push({ charIndex: i, char: '', x0: i * step, x1: (i + 1) * step });
      }
      return cols;
    }

    function columnIndexFromLocalX(localX, unitWidth) {
      const step = getWaveColumnWidth(unitWidth);
      if (localX < 0) return 0;
      return Math.floor(localX / step);
    }

    function buildWaveColumnMap(drawGroup, wave, unitWidth) {
      const columnWidth = getWaveColumnWidth(unitWidth);
      const n = wave.length;
      if (n === 0) {
        return buildVirtualColumnMap(MIN_CONNECTION_PICK_BOUNDARIES, unitWidth);
      }
      return [...wave].map((char, i) => ({
        charIndex: i,
        char,
        x0: i * columnWidth,
        x1: (i + 1) * columnWidth
      }));
    }

    function clampPickColumnIndex(colIndex, wave, cols) {
      const minCol = 0;
      let maxCol = Math.max((wave || '').length, cols.length);
      if (!wave.length && cols.length > 0) {
        maxCol = cols.length;
      } else if (maxCol > 0) {
        maxCol += 1;
      } else {
        maxCol = 8;
      }
      return Math.min(Math.max(minCol, colIndex), maxCol);
    }

    function columnIndexFromClick(drawGroup, wave, svgRoot, clientX, unitWidth) {
      const pt = svgRoot.createSVGPoint();
      pt.x = clientX;
      pt.y = 0;
      const ctm = drawGroup.getScreenCTM();
      if (!ctm) return 0;
      const local = pt.matrixTransform(ctm.inverse());
      const cols = buildWaveColumnMap(drawGroup, wave, unitWidth);
      if (!cols.length) {
        return clampPickColumnIndex(columnIndexFromLocalX(local.x, unitWidth), wave, cols);
      }

      for (const col of cols) {
        if (col.x1 <= col.x0) continue;
        if (local.x >= col.x0 && local.x < col.x1) {
          return clampPickColumnIndex(col.charIndex, wave, cols);
        }
      }

      if (local.x >= cols[cols.length - 1].x1) {
        return clampPickColumnIndex(columnIndexFromLocalX(local.x, unitWidth), wave, cols);
      }

      let best = cols[0].charIndex;
      let bestDist = Infinity;
      cols.forEach((col) => {
        const mid = col.x1 > col.x0 ? (col.x0 + col.x1) / 2 : col.x0;
        const d = Math.abs(local.x - mid);
        if (d < bestDist) {
          bestDist = d;
          best = col.charIndex;
        }
      });
      return clampPickColumnIndex(best, wave, cols);
    }

    function paintColumnIndexFromClick(drawGroup, wave, svgRoot, clientX, unitWidth, maxColumnCount) {
      const regularIndex = columnIndexFromClick(drawGroup, wave, svgRoot, clientX, unitWidth);
      const ctm = drawGroup.getScreenCTM();
      if (!ctm) return regularIndex;

      const pt = svgRoot.createSVGPoint();
      pt.x = clientX;
      pt.y = 0;
      const local = pt.matrixTransform(ctm.inverse());
      const cols = buildWaveColumnMap(drawGroup, wave, unitWidth);
      const last = cols.length ? cols[cols.length - 1] : null;
      const contentEnd = last && last.x1 > last.x0 ? last.x1 : 0;
      const rawIndex = (!wave.length || local.x >= contentEnd)
        ? columnIndexFromLocalX(local.x, unitWidth)
        : regularIndex;
      const maxIndex = Math.max(0, Math.max(1, maxColumnCount || 1) - 1);
      return Math.min(Math.max(0, rawIndex), maxIndex);
    }

    function getMaxWaveBoundaryIndex(sourceMap) {
      return (sourceMap || []).reduce((max, entry) => {
        const wave = entry && entry.signal ? (entry.signal.wave || '') : '';
        return Math.max(max, wave.length);
      }, 0);
    }

    function getConnectionPickBoundaryIndex(sourceMap) {
      return Math.max(MIN_CONNECTION_PICK_BOUNDARIES, getMaxWaveBoundaryIndex(sourceMap));
    }

    function getWaveBoundaryPositions(drawGroup, wave, unitWidth, maxBoundaryIndex) {
      const step = getWaveColumnWidth(unitWidth);
      const cols = buildWaveColumnMap(drawGroup, wave || '', unitWidth);
      const targetIndex = Math.max(0, maxBoundaryIndex || 0, (wave || '').length, cols.length);
      if (!cols.length) {
        const boundaries = [];
        for (let i = 0; i <= Math.max(1, targetIndex); i++) {
          boundaries.push({ index: i, x: i * step });
        }
        return boundaries;
      }
      const boundaries = [];
      cols.forEach((col) => {
        if (col.x1 <= col.x0) return;
        boundaries.push({ index: col.charIndex, x: col.x0 });
      });
      const last = cols[cols.length - 1];
      const lastIndex = Math.max((wave || '').length, cols.length);
      const lastX = last && last.x1 > last.x0 ? last.x1 : lastIndex * step;
      boundaries.push({ index: lastIndex, x: lastX });
      for (let i = lastIndex + 1; i <= targetIndex; i++) {
        boundaries.push({ index: i, x: lastX + (i - lastIndex) * step });
      }
      return boundaries;
    }

    function boundaryIndexFromClick(drawGroup, wave, svgRoot, clientX, unitWidth, maxBoundaryIndex) {
      const pt = svgRoot.createSVGPoint();
      pt.x = clientX;
      pt.y = 0;
      const ctm = drawGroup.getScreenCTM();
      if (!ctm) return 0;
      const local = pt.matrixTransform(ctm.inverse());
      const boundaries = getWaveBoundaryPositions(drawGroup, wave, unitWidth, maxBoundaryIndex);
      let best = boundaries[0] || { index: 0, x: 0 };
      let bestDist = Infinity;
      boundaries.forEach((boundary) => {
        const d = Math.abs(local.x - boundary.x);
        if (d < bestDist) {
          bestDist = d;
          best = boundary;
        }
      });
      return Math.max(0, best.index);
    }

    function virtualLaneIndexFromClick(lane, svgRoot, clientX, unitWidth, maxCount, isBoundary) {
      const ctm = lane && lane.getScreenCTM ? lane.getScreenCTM() : null;
      if (!ctm) return 0;
      const pt = svgRoot.createSVGPoint();
      pt.x = clientX;
      pt.y = 0;
      const local = pt.matrixTransform(ctm.inverse());
      const step = getWaveColumnWidth(unitWidth);
      const rawIndex = isBoundary
        ? Math.round(Math.max(0, local.x) / step)
        : Math.floor(Math.max(0, local.x) / step);
      const maxIndex = isBoundary
        ? Math.max(0, maxCount || 0)
        : Math.max(0, Math.max(1, maxCount || 1) - 1);
      return Math.min(rawIndex, maxIndex);
    }

    function getBoundaryXForColumn(drawGroup, wave, colIndex, unitWidth, maxBoundaryIndex) {
      const boundaries = getWaveBoundaryPositions(drawGroup, wave, unitWidth, maxBoundaryIndex);
      const exact = boundaries.find((boundary) => boundary.index === colIndex);
      if (exact) return exact.x;
      const step = getWaveColumnWidth(unitWidth);
      return Math.max(0, colIndex) * step;
    }

    function replaceWaveCharAt(wave, colIndex, char) {
      if (colIndex < 0) return wave;
      if (colIndex >= wave.length) return wave + char;
      return wave.slice(0, colIndex) + char + wave.slice(colIndex + 1);
    }

    function getWaveContinuationSourceChar(wave, colIndex) {
      for (let i = Math.min(colIndex, wave.length - 1); i >= 0; i--) {
        const current = wave[i];
        if (current !== '.' && current !== '|') return current;
      }
      return 'x';
    }

    function replaceWaveCharPreservingContinuation(wave, colIndex, char) {
      if (colIndex < 0 || colIndex >= wave.length) return replaceWaveCharAt(wave, colIndex, char);
      const originalContinuation = getWaveContinuationSourceChar(wave, colIndex);
      const replacementContinuation = char === '.' || char === '|'
        ? getWaveContinuationSourceChar(wave, colIndex - 1)
        : char;
      let updated = replaceWaveCharAt(wave, colIndex, char);
      if (colIndex + 1 < wave.length
          && wave[colIndex + 1] === '.'
          && originalContinuation !== replacementContinuation) {
        updated = updated.slice(0, colIndex + 1)
          + originalContinuation
          + updated.slice(colIndex + 2);
      }
      return updated;
    }

    function replaceWaveRangePreservingContinuation(wave, startCol, replacement) {
      const originalWave = typeof wave === 'string' ? wave : '';
      const chars = typeof replacement === 'string' ? replacement : '';
      if (!chars) return originalWave;

      const safeStart = Math.max(0, Math.floor(startCol));
      const endCol = safeStart + chars.length;
      const preservesFollowingContinuation = endCol < originalWave.length && originalWave[endCol] === '.';
      const followingContinuation = preservesFollowingContinuation
        ? getWaveContinuationSourceChar(originalWave, endCol)
        : '';
      let paddedWave = originalWave.padEnd(safeStart, EMPTY_WAVE_FILL_CHAR);
      paddedWave = paddedWave.padEnd(endCol, EMPTY_WAVE_FILL_CHAR);
      let updated = paddedWave.slice(0, safeStart) + chars + paddedWave.slice(endCol);

      if (preservesFollowingContinuation
          && getWaveContinuationSourceChar(updated, endCol) !== followingContinuation) {
        updated = replaceWaveCharAt(updated, endCol, followingContinuation);
      }
      return updated;
    }

    function insertWaveCharAt(wave, colIndex, char) {
      const pos = colIndex < 0 ? 0 : Math.min(colIndex, wave.length);
      return wave.slice(0, pos) + char + wave.slice(pos);
    }

    function deleteWaveCharAt(wave, colIndex) {
      if (colIndex < 0 || colIndex >= wave.length) return wave;
      return wave.slice(0, colIndex) + wave.slice(colIndex + 1);
    }

    function resolveLegendColumnIndex(wave, forInsert) {
      if (selectedWaveColumnIndex >= 0) return selectedWaveColumnIndex;
      return forInsert ? wave.length : 0;
    }

    function applyWaveCharAtColumn(rowIndex, colIndex, char) {
      if (rowIndex < 0) {
        setStatus(false, '波形为空，无法删除');
        return false;
      }

      let parsed;
      try {
        parsed = JSON.parse(editor.value);
      } catch (e) {
        setStatus(false, '波形为空，无法删除');
        return false;
      }

      const text = editor.value;
      const sourceMap = buildSignalSourceMap(text);
      const entry = sourceMap[rowIndex];
      if (!entry) {
        setStatus(false, '波形为空，无法删除');
        setSelectedSignal(rowIndex, -1);
        return false;
      }

      const wave = entry.signal.wave || '';
      const safeCol = colIndex < 0 ? 0 : Math.floor(colIndex);
      const wasEmpty = wave.length === 0;
      const targetsEmptyPosition = safeCol >= wave.length;
      const paddedWave = targetsEmptyPosition
        ? wave.padEnd(safeCol, EMPTY_WAVE_FILL_CHAR)
        : wave;
      const newWave = targetsEmptyPosition
        ? paddedWave + char
        : replaceWaveCharPreservingContinuation(paddedWave, safeCol, char);
      if (newWave === wave) return false;

      pushUndoBeforeChange();
      const updatedSignal = Object.assign({}, entry.signal, { wave: newWave });
      const indent = getIndentAt(text, entry.start);
      const newObjStr = formatSignalObject(updatedSignal, indent);
      const newText = text.slice(0, entry.start) + newObjStr + text.slice(entry.end);
      vwdDebugLog('wave-edit', { phase: 'replace', rowIndex, sourceStart: entry.start, sourceEnd: entry.end, oldWave: wave, newWave });
      const nextCol = newWave.length > 0 ? Math.min(safeCol + 1, newWave.length - 1) : -1;
      setSelectedSignal(rowIndex, nextCol);
      applyEditorChange(newText, entry.start, entry.start + newObjStr.length);
      scheduleFormatAfterWaveChange();
      if (wasEmpty || targetsEmptyPosition) {
        setStatus(
          true,
          waveEditModeLabel()
            + ' · 已填充空位置 ' + updatedSignal.name + ' [' + safeCol + ']=' + JSON.stringify(char)
        );
      } else {
        setStatus(
          true,
          waveEditModeLabel()
            + ' · 已修改 ' + updatedSignal.name + ' [' + safeCol + ']=' + JSON.stringify(char)
            + ' · 当前列 [' + nextCol + ']=' + JSON.stringify(newWave[nextCol] || '')
        );
      }
      return true;
    }

    function applyWavePaintCharAtColumn(rowIndex, colIndex, char) {
      if (rowIndex < 0 || colIndex < 0 || !char) return false;

      try {
        JSON.parse(editor.value);
      } catch (e) {
        setStatus(false, 'JSON 错误，无法使用画笔');
        return false;
      }

      const text = editor.value;
      const sourceMap = buildSignalSourceMap(text);
      const entry = sourceMap[rowIndex];
      if (!entry) {
        setStatus(false, '未找到要绘制的信号行');
        return false;
      }

      const wave = entry.signal.wave || '';
      const paintCol = Math.max(0, Math.floor(colIndex));
      const paddedWave = paintCol >= wave.length ? wave.padEnd(paintCol, EMPTY_WAVE_FILL_CHAR) : wave;
      const newWave = paintCol >= paddedWave.length
        ? paddedWave + char
        : replaceWaveCharPreservingContinuation(paddedWave, paintCol, char);
      if (newWave === wave) {
        setStatus(true, '该格已经是 ' + JSON.stringify(char) + '，画笔模式保持开启');
        return false;
      }

      pushUndoBeforeChange();
      const updatedSignal = Object.assign({}, entry.signal, { wave: newWave });
      const indent = getIndentAt(text, entry.start);
      const newObjStr = formatSignalObject(updatedSignal, indent);
      const newText = text.slice(0, entry.start) + newObjStr + text.slice(entry.end);
      setSelectedSignal(rowIndex, paintCol);
      applyEditorChange(newText, entry.start, entry.start + newObjStr.length);
      scheduleFormatAfterWaveChange();
      vwdDebugLog('wave-paint', {
        phase: 'paint',
        rowIndex,
        colIndex: paintCol,
        char,
        oldWave: wave,
        newWave
      });
      setStatus(
        true,
        '画笔已修改第 ' + (rowIndex + 1) + ' 行第 ' + (paintCol + 1) + ' 格，画笔模式保持开启'
      );
      return true;
    }

    function applyWaveCharInsertAtColumn(rowIndex, colIndex, char) {
      if (rowIndex < 0) {
        setStatus(false, '波形为空，无法删除');
        return false;
      }

      let parsed;
      try {
        parsed = JSON.parse(editor.value);
      } catch (e) {
        setStatus(false, '波形为空，无法删除');
        return false;
      }

      const text = editor.value;
      const sourceMap = buildSignalSourceMap(text);
      const entry = sourceMap[rowIndex];
      if (!entry) {
        setStatus(false, '波形为空，无法删除');
        setSelectedSignal(rowIndex, -1);
        return false;
      }

      const wave = entry.signal.wave || '';
      const insertCol = colIndex < 0 ? wave.length : Math.max(0, Math.floor(colIndex));
      const paddedWave = insertCol > wave.length
        ? wave.padEnd(insertCol, EMPTY_WAVE_FILL_CHAR)
        : wave;
      const newWave = insertWaveCharAt(paddedWave, insertCol, char);
      if (newWave === wave) return false;

      pushUndoBeforeChange();
      const updatedSignal = Object.assign({}, entry.signal, { wave: newWave });
      const indent = getIndentAt(text, entry.start);
      const newObjStr = formatSignalObject(updatedSignal, indent);
      const newText = text.slice(0, entry.start) + newObjStr + text.slice(entry.end);
      applyEditorChange(newText, entry.start, entry.start + newObjStr.length);
      scheduleFormatAfterWaveChange();
      setSelectedSignal(rowIndex, insertCol);
      setStatus(true, waveEditModeLabel() + ' · 已插入 ' + updatedSignal.name + ' [' + insertCol + ']=' + JSON.stringify(char));
      return true;
    }

    function deleteWaveRangeAtColumns(rowIndex, startCol, endCol) {
      if (rowIndex < 0) {
        setStatus(false, '波形为空，无法删除');
        return false;
      }
      if (startCol < 0) {
        setStatus(false, '波形为空，无法删除');
        return false;
      }

      let parsed;
      try {
        parsed = JSON.parse(editor.value);
      } catch (e) {
        setStatus(false, '波形为空，无法删除');
        return false;
      }

      const text = editor.value;
      const sourceMap = buildSignalSourceMap(text);
      const entry = sourceMap[rowIndex];
      if (!entry) {
        setStatus(false, '请先在波形区点击选中一行');
        setSelectedSignal(rowIndex, -1);
        return false;
      }

      const wave = entry.signal.wave || '';
      if (wave.length === 0) {
        setStatus(false, '请先在波形区点击选中一行');
        return false;
      }

      const safeStart = Math.max(0, Math.floor(Math.min(startCol, endCol)));
      const safeEnd = Math.min(wave.length - 1, Math.floor(Math.max(startCol, endCol)));
      if (safeStart >= wave.length || safeEnd < safeStart) {
        setStatus(false, '选中的空位置没有可删除波形');
        return false;
      }

      let suffix = wave.slice(safeEnd + 1);
      let continuationOffset = 0;
      while (continuationOffset < suffix.length && suffix[continuationOffset] === '|') {
        continuationOffset++;
      }
      if (suffix[continuationOffset] === '.') {
        const continuationChar = getWaveContinuationSourceChar(
          wave,
          safeEnd + 1 + continuationOffset
        );
        suffix = suffix.slice(0, continuationOffset)
          + continuationChar
          + suffix.slice(continuationOffset + 1);
      }
      const newWave = wave.slice(0, safeStart) + suffix;
      if (newWave === wave) return false;

      pushUndoBeforeChange();
      const updatedSignal = Object.assign({}, entry.signal, { wave: newWave });
      const indent = getIndentAt(text, entry.start);
      const newObjStr = formatSignalObject(updatedSignal, indent);
      const newText = text.slice(0, entry.start) + newObjStr + text.slice(entry.end);
      const nextCol = newWave.length > 0 ? Math.min(safeStart, newWave.length - 1) : -1;
      setSelectedSignal(rowIndex, nextCol);
      applyEditorChange(newText, entry.start, entry.start + newObjStr.length);
      scheduleFormatAfterWaveChange();
      const deletedCount = safeEnd - safeStart + 1;
      setStatus(true, '已删除 ' + deletedCount + ' 个波形格');
      vwdDebugLog('wave-selection', {
        phase: 'delete-range',
        rowIndex,
        startCol: safeStart,
        endCol: safeEnd,
        deletedCount,
        oldWave: wave,
        newWave
      });
      return true;
    }

    function deleteSelectedWaveRange() {
      const range = getSelectedWaveRange();
      if (!range) {
        setStatus(false, '请先点击或拖动选择波形格');
        return false;
      }
      return deleteWaveRangeAtColumns(selectedSignalIndex, range.start, range.end);
    }

    function waveEditModeLabel() {
      return waveEditMode === 'insert' ? '模式: 插入' : '模式: 修改';
    }

    function toggleWaveEditMode() {
      exitWavePaintMode('wave-edit-mode');
      setWaveEditMode(waveEditMode === 'insert' ? 'modify' : 'insert');
    }

    function setWaveEditMode(mode) {
      if (mode !== 'modify' && mode !== 'insert') return;
      if (textEditModeActive && mode === 'insert') {
        setStatus(false, '请先退出文本编辑模式');
        updateWaveEditModeUI();
        return false;
      }
      waveEditMode = mode;
      try {
        localStorage.setItem(WAVE_EDIT_MODE_KEY, mode);
      } catch (e) { /* ignore */ }
      updateWaveEditModeUI();
      clearActiveTagIfModified();
      setStatus(true, waveEditModeLabel());
      return true;
    }

    function loadWaveEditMode() {
      try {
        const saved = localStorage.getItem(WAVE_EDIT_MODE_KEY);
        if (saved === 'modify' || saved === 'insert') waveEditMode = saved;
      } catch (e) { /* ignore */ }
      updateWaveEditModeUI();
    }

    function updateWaveEditModeUI() {
      const btn = document.getElementById('btn-wave-edit-mode');
      if (!btn) return;
      const labelEl = btn.querySelector('.wave-edit-mode-label');
      const isInsert = waveEditMode === 'insert';
      btn.classList.toggle('mode-modify', !isInsert);
      btn.classList.toggle('mode-insert', isInsert);
      if (labelEl) labelEl.textContent = isInsert ? '插入模式' : '修改模式';
      btn.title = isInsert
        ? '点击在选中列位置插入波形字符'
        : '点击替换选中列的波形字符';
      btn.setAttribute('aria-label', isInsert ? '插入模式' : '修改模式');
      btn.setAttribute('aria-pressed', isInsert ? 'true' : 'false');
      updateTextEditModeUI();
      updateLegendAvailability();
    }

    function isTextEditModeActive() {
      return textEditModeActive
        && waveEditMode === 'modify'
        && !app.classList.contains('reading-mode');
    }

    function updateTextEditModeUI() {
      const btn = document.getElementById('btn-wave-text-edit-mode');
      const waveModeBtn = document.getElementById('btn-wave-edit-mode');
      const paintModeBtn = document.getElementById('btn-wave-paint-mode');
      const canActivate = waveEditMode === 'modify';
      if (btn) {
        const labelEl = btn.querySelector('.wave-text-edit-mode-label');
        btn.disabled = !canActivate;
        btn.classList.toggle('active', textEditModeActive);
        btn.setAttribute('aria-pressed', String(textEditModeActive));
        btn.setAttribute('aria-label', textEditModeActive ? '退出文本编辑模式' : '文本编辑模式');
        btn.title = textEditModeActive
          ? '退出文本编辑模式'
          : (canActivate ? '开启后，单击波形中的文本进行编辑' : '仅修改模式下可用');
        if (labelEl) labelEl.textContent = textEditModeActive ? '退出文本编辑' : '文本编辑';
      }
      if (waveModeBtn) waveModeBtn.disabled = textEditModeActive;
      if (paintModeBtn) paintModeBtn.disabled = textEditModeActive;
      app.classList.toggle('text-edit-mode', isTextEditModeActive());
      updateConnectionPropertiesUI();
      if (editingWaveDocumentName) refreshWaveDocumentCard(editingWaveDocumentName);
    }

    function setTextEditMode(active) {
      const nextActive = !!active;
      if (nextActive && waveEditMode !== 'modify') {
        setStatus(false, '文本编辑模式仅可在修改模式下使用');
        updateTextEditModeUI();
        return false;
      }
      if (nextActive === textEditModeActive) {
        updateTextEditModeUI();
        return false;
      }
      if (nextActive) exitWavePaintMode('text-edit-mode');
      textEditModeActive = nextActive;
      updateTextEditModeUI();
      setStatus(true, textEditModeActive ? '文本编辑模式已开启' : '文本编辑模式已退出');
      vwdDebugLog('text-edit-mode', { active: textEditModeActive });
      return true;
    }

    function applyWaveRangeReplacement(rowIndex, startCol, replacement, actionLabel) {
      if (rowIndex < 0 || startCol < 0 || !replacement) {
        setStatus(false, '请先选择要修改的波形格');
        return false;
      }

      let sourceMap;
      try {
        JSON.parse(editor.value);
        sourceMap = buildSignalSourceMap(editor.value);
      } catch (e) {
        setStatus(false, 'JSON 错误，无法批量修改波形');
        return false;
      }

      const entry = sourceMap[rowIndex];
      if (!entry) {
        setStatus(false, '未找到要修改的信号行');
        return false;
      }

      const text = editor.value;
      const wave = entry.signal.wave || '';
      const safeStart = Math.max(0, Math.floor(startCol));
      const newWave = replaceWaveRangePreservingContinuation(wave, safeStart, replacement);
      const endCol = safeStart + replacement.length - 1;
      setSelectedWaveRange(rowIndex, safeStart, endCol);
      if (newWave === wave) {
        setStatus(true, (actionLabel || '批量修改') + '完成，波形内容未变化');
        return false;
      }

      pushUndoBeforeChange();
      const updatedSignal = Object.assign({}, entry.signal, { wave: newWave });
      const indent = getIndentAt(text, entry.start);
      const newObjStr = formatSignalObject(updatedSignal, indent);
      const newText = text.slice(0, entry.start) + newObjStr + text.slice(entry.end);
      applyEditorChange(newText, entry.start, entry.start + newObjStr.length);
      scheduleFormatAfterWaveChange();
      vwdDebugLog('wave-selection', {
        phase: 'replace-range',
        action: actionLabel || 'replace',
        rowIndex,
        startCol: safeStart,
        endCol,
        replacement,
        oldWave: wave,
        newWave
      });
      setStatus(
        true,
        (actionLabel || '批量修改') + '：第 ' + (safeStart + 1) + ' 至 ' + (endCol + 1) + ' 格'
      );
      return true;
    }

    function copySelectedWaveRange() {
      const range = getSelectedWaveRange();
      if (!range) {
        setStatus(false, '请先点击或拖动选择波形格');
        return false;
      }

      let entry;
      try {
        entry = buildSignalSourceMap(editor.value)[selectedSignalIndex];
      } catch (e) { /* handled below */ }
      if (!entry) {
        setStatus(false, '未找到要复制的信号行');
        return false;
      }

      const wave = entry.signal.wave || '';
      const length = range.end - range.start + 1;
      let copied = wave.padEnd(range.end + 1, EMPTY_WAVE_FILL_CHAR)
        .slice(range.start, range.end + 1);
      if (copied[0] === '.') {
        copied = getWaveContinuationSourceChar(wave, range.start) + copied.slice(1);
      }
      copiedWaveSelection = copied;
      waveClipboardShortcutActive = true;
      updateLegendAvailability();
      vwdDebugLog('wave-selection', {
        phase: 'copy',
        rowIndex: selectedSignalIndex,
        startCol: range.start,
        endCol: range.end,
        length,
        copied
      });
      setStatus(true, '已复制 ' + length + ' 个波形格');
      return true;
    }

    function pasteCopiedWaveRange() {
      const range = getSelectedWaveRange();
      if (!range) {
        setStatus(false, '请先选择粘贴起点');
        return false;
      }
      if (!copiedWaveSelection) {
        setStatus(false, '请先复制波形');
        return false;
      }
      waveClipboardShortcutActive = true;
      return applyWaveRangeReplacement(
        selectedSignalIndex,
        range.start,
        copiedWaveSelection,
        '覆盖粘贴'
      );
    }

    function setWaveClipboardShortcutActive(active, reason) {
      const next = !!active;
      if (waveClipboardShortcutActive === next) return;
      waveClipboardShortcutActive = next;
      vwdDebugLog('wave-selection', {
        phase: 'clipboard-shortcut-context',
        active: next,
        reason: reason || ''
      });
    }

    function handleWaveClipboardShortcut(e) {
      const key = String(e.key || '').toLowerCase();
      if ((key === 'c' || key === 'v') && isModKey(e)) {
        vwdDebugLog('wave-selection', {
          phase: 'clipboard-keydown',
          key,
          ctrlKey: e.ctrlKey,
          metaKey: e.metaKey,
          shiftKey: e.shiftKey,
          altKey: e.altKey,
          active: waveClipboardShortcutActive,
          targetId: e.target && e.target.id ? e.target.id : '',
          hasRange: !!getSelectedWaveRange()
        });
      }
      if (!waveClipboardShortcutActive || !isModKey(e) || e.altKey || e.shiftKey) return false;
      if (key !== 'c' && key !== 'v') return false;
      if (!getSelectedWaveRange()) return false;

      if (!canUseWaveClipboardForTarget(e.target)) return false;

      e.preventDefault();
      e.stopPropagation();
      const handled = key === 'c' ? copySelectedWaveRange() : pasteCopiedWaveRange();
      vwdDebugLog('wave-selection', {
        phase: 'clipboard-shortcut',
        key,
        handled,
        copiedLength: copiedWaveSelection.length
      });
      return true;
    }

    function canUseWaveClipboardForTarget(target) {
      const isEditableTarget = !!(target && target.closest
        && target.closest('input, textarea, [contenteditable="true"]'));
      return !isEditableTarget || target === editor;
    }

    function handleWaveClipboardEvent(e) {
      if (!waveClipboardShortcutActive || !getSelectedWaveRange()) return false;
      if (!canUseWaveClipboardForTarget(e.target)) return false;
      if (e.type !== 'copy' && e.type !== 'paste') return false;

      e.preventDefault();
      e.stopPropagation();
      let handled = false;
      if (e.type === 'copy') {
        handled = copySelectedWaveRange();
        if (handled && e.clipboardData && copiedWaveSelection) {
          e.clipboardData.setData('text/plain', copiedWaveSelection);
        }
      } else {
        handled = pasteCopiedWaveRange();
      }
      vwdDebugLog('wave-selection', {
        phase: 'clipboard-event',
        type: e.type,
        handled,
        copiedLength: copiedWaveSelection.length
      });
      return true;
    }

    function setGroupDeleteShortcutActive(active, reason) {
      const next = !!active;
      if (groupDeleteShortcutActive === next) return;
      groupDeleteShortcutActive = next;
      vwdDebugLog('group-label', {
        phase: 'delete-shortcut-context',
        active: next,
        reason: reason || ''
      });
    }

    function handleSelectionDeleteShortcut(e) {
      if (e.key !== 'Delete' || e.ctrlKey || e.metaKey || e.altKey || e.shiftKey) return false;
      if (!canUseWaveClipboardForTarget(e.target) || inlineEditActive) return false;

      let action = '';
      if (groupDeleteShortcutActive && selectedGroupIndex >= 0) {
        action = 'group';
      } else if (waveClipboardShortcutActive && getSelectedWaveRange()) {
        action = 'wave-range';
      } else {
        return false;
      }

      e.preventDefault();
      e.stopPropagation();
      const handled = action === 'group'
        ? deleteSelectedGroup()
        : deleteSelectedWaveRange();
      vwdDebugLog('selection-delete', { action, handled });
      return true;
    }

    function toggleTextEditMode() {
      setTextEditMode(!textEditModeActive);
    }

    function updateWavePaintModeUI() {
      const btn = document.getElementById('btn-wave-paint-mode');
      if (btn) {
        const labelEl = btn.querySelector('.wave-paint-mode-label');
        btn.classList.toggle('active', wavePaintModeActive);
        btn.setAttribute('aria-pressed', String(wavePaintModeActive));
        btn.setAttribute('aria-label', wavePaintModeActive ? '退出画笔模式' : '画笔模式');
        btn.title = wavePaintModeActive
          ? '退出画笔模式'
          : '进入画笔模式后，先选择波形，再连续点击格子';
        if (labelEl) labelEl.textContent = wavePaintModeActive ? '退出画笔' : '画笔模式';
      }
      app.classList.toggle('wave-paint-mode', wavePaintModeActive);
      updateLegendAvailability();
    }

    function setWavePaintMode(active, reason) {
      const nextActive = !!active;
      if (nextActive && textEditModeActive) {
        setStatus(false, '请先退出文本编辑模式');
        updateWavePaintModeUI();
        return false;
      }
      if (nextActive === wavePaintModeActive) {
        updateWavePaintModeUI();
        return false;
      }

      if (nextActive) {
        if (groupPickActive) {
          const svg = waveContainer.querySelector('svg');
          clearGroupPickStartMark(svg ? getWaveLaneGroups(svg) : []);
          groupPickActive = false;
          groupPickStartIndex = -1;
        }
        if (connectionAddSessionActive) endConnectionAddSession();
        else if (connectionPickActive) setConnectionPickActive(false);
        if (connectionSelectActive) setConnectionSelectActive(false);
      }

      wavePaintModeActive = nextActive;
      if (!wavePaintModeActive) wavePaintChar = '';
      updateWavePaintModeUI();
      vwdDebugLog('wave-paint', {
        phase: 'mode',
        active: wavePaintModeActive,
        reason: reason || 'button'
      });
      setStatus(
        true,
        wavePaintModeActive ? '画笔模式：请选择一个波形按钮' : '已退出画笔模式'
      );
      return true;
    }

    function toggleWavePaintMode() {
      setWavePaintMode(!wavePaintModeActive, 'button');
    }

    function exitWavePaintMode(reason) {
      if (!wavePaintModeActive) return false;
      return setWavePaintMode(false, reason || 'automatic');
    }

    function selectWavePaintChar(char) {
      if (!wavePaintModeActive) return false;
      if (!LEGEND_ITEMS.some((item) => item.char === char)) return false;
      wavePaintChar = char;
      updateWavePaintModeUI();
      vwdDebugLog('wave-paint', { phase: 'select-char', char });
      setStatus(true, '画笔已选择 ' + JSON.stringify(char) + '，可连续点击波形格子');
      return true;
    }

    function updateLegendAvailability() {
      let signalCount = 0;
      let hasRow = false;
      let hasCol = selectedWaveColumnIndex >= 0;
      const selectedRange = getSelectedWaveRange();
      const selectedWaveCount = selectedRange ? selectedRange.end - selectedRange.start + 1 : 0;
      let waveLen = 0;
      let sourceMap = [];
      let groupMap = [];
      try {
        sourceMap = buildSignalSourceMap(editor.value);
        signalCount = sourceMap.length;
        const rowEntry = sourceMap[selectedSignalIndex];
        hasRow = !!rowEntry;
        if (rowEntry) waveLen = (rowEntry.signal.wave || '').length;
      } catch (e) { /* ignore */ }
      try {
        groupMap = buildGroupSourceMap(editor.value);
      } catch (e) { /* ignore */ }

      const hasGroup = selectedGroupIndex >= 0 && selectedGroupIndex < groupMap.length;
      const hasSelection = hasRow || hasGroup;
      const hasSelectedConnection = connectionSelectActive && selectedEdgeIndex >= 0;

      const selectedExistingWaveCount = selectedRange
        ? Math.max(0, Math.min(selectedRange.end, waveLen - 1) - selectedRange.start + 1)
        : 0;
      const canDeleteCol = hasRow && hasCol && selectedExistingWaveCount > 0;
      const deleteColBtn = document.getElementById('btn-delete-wave-col');
      if (deleteColBtn) {
        deleteColBtn.disabled = !hasSelectedConnection && !canDeleteCol;
        deleteColBtn.title = hasSelectedConnection
          ? '删除当前选中的连接线，并清理不再使用的端点'
          : (canDeleteCol
            ? '删除当前选中的 ' + selectedExistingWaveCount + ' 个波形格 (Delete)'
            : (!hasRow ? '请先在波形区点击选中一行' : (!hasCol ? '请先选中列' : '波形为空，无法删除')));
      }

      const deleteSignalBtn = document.getElementById('btn-delete-signal');
      if (deleteSignalBtn) {
        deleteSignalBtn.disabled = !hasSelection;
        deleteSignalBtn.title = hasGroup
          ? '将当前选中的信号行下移'
          : (hasRow ? '删除当前选中行' : '请先点击波形区选中行');
        deleteSignalBtn.textContent = hasGroup ? '删除分组' : '删除行';
      }

      const copySignalBtn = document.getElementById('btn-copy-signal');
      if (copySignalBtn) {
        copySignalBtn.disabled = !hasRow;
        copySignalBtn.title = hasRow
          ? '复制当前选中行到其下方（不复制 node 字段）'
          : '请先在波形区点击选中一行';
      }

      const copyWaveBtn = document.getElementById('btn-copy-wave-selection');
      if (copyWaveBtn) {
        copyWaveBtn.disabled = !hasRow || !selectedRange;
        copyWaveBtn.title = selectedRange
          ? '复制当前选中的 ' + selectedWaveCount + ' 个波形格 (Ctrl+C)'
          : '请先点击或拖动选择波形格';
      }
      const pasteWaveBtn = document.getElementById('btn-paste-wave-selection');
      if (pasteWaveBtn) {
        pasteWaveBtn.disabled = !hasRow || !selectedRange || !copiedWaveSelection;
        pasteWaveBtn.title = !copiedWaveSelection
          ? '请先复制波形 (Ctrl+C)'
          : (selectedRange ? '从所选起点覆盖粘贴 ' + copiedWaveSelection.length + ' 个波形格 (Ctrl+V)' : '请先选择粘贴起点');
      }

      const groupSignalBtn = document.getElementById('btn-group-signal');
      if (groupSignalBtn) {
        groupSignalBtn.disabled = signalCount === 0;
        groupSignalBtn.classList.toggle('group-pick-active', groupPickActive);
        groupSignalBtn.title = groupPickActive
          ? '已进入分组模式，请点击起始行与结束行'
          : '先点击分组，再点击起始行与结束行';
      }

      const canMoveUp = hasRow && selectedSignalIndex > 0;
      const canMoveDown = hasRow && selectedSignalIndex >= 0 && selectedSignalIndex < signalCount - 1;
      const moveUpBtn = document.getElementById('btn-move-signal-up');
      if (moveUpBtn) {
        moveUpBtn.disabled = !canMoveUp;
        moveUpBtn.title = canMoveUp ? '输入行数后上移当前选中行' : '请先选中可上移的信号行';
      }
      const moveDownBtn = document.getElementById('btn-move-signal-down');
      if (moveDownBtn) {
        moveDownBtn.disabled = !canMoveDown;
        moveDownBtn.title = canMoveDown ? '输入行数后下移当前选中行' : '请先选中可下移的信号行';
      }

      const actionHint = wavePaintModeActive
        ? (wavePaintChar
          ? '画笔已选择 ' + JSON.stringify(wavePaintChar) + '，点击格子连续绘制'
          : '点击选择画笔波形')
        : (selectedWaveCount > 1
          ? '替换当前选中的 ' + selectedWaveCount + ' 个波形格'
          : (waveEditMode === 'insert'
          ? '点击在选中列位置插入波形字符'
          : '点击替换选中列的波形字符'));
      const canUseLegend = wavePaintModeActive || hasRow;
      document.querySelectorAll('.legend-item').forEach(item => {
        item.classList.toggle('legend-disabled', !canUseLegend);
        item.classList.toggle(
          'paint-selected',
          wavePaintModeActive && !!wavePaintChar && item.dataset.waveChar === wavePaintChar
        );
        item.title = canUseLegend ? actionHint : '请先在波形区点击选中一行';
      });
    }

    function getSelectedWaveRange(rowIndex) {
      const targetRow = Number.isFinite(rowIndex) ? rowIndex : selectedSignalIndex;
      if (targetRow < 0 || targetRow !== selectedSignalIndex || selectedWaveColumnIndex < 0) return null;
      if (selectedWaveRangeRowIndex !== targetRow
          || selectedWaveRangeStart < 0
          || selectedWaveRangeEnd < 0) {
        return { start: selectedWaveColumnIndex, end: selectedWaveColumnIndex };
      }
      return {
        start: Math.min(selectedWaveRangeStart, selectedWaveRangeEnd),
        end: Math.max(selectedWaveRangeStart, selectedWaveRangeEnd)
      };
    }

    function setSelectedWaveRange(rowIndex, startCol, endCol, options) {
      const opts = options || {};
      const hasFilter = isNavFilteringActive();
      const visibleSet = getNavVisibleRowSet();
      if (hasFilter && Number.isFinite(rowIndex) && rowIndex >= 0 && !visibleSet.has(rowIndex)) {
        rowIndex = -1;
      }
      if (rowIndex < 0) {
        setSelectedSignal(-1, -1);
        return;
      }

      const safeStart = Math.max(0, Math.floor(startCol));
      const safeEnd = Math.max(0, Math.floor(endCol));
      selectedSignalIndex = rowIndex;
      selectedWaveColumnIndex = Math.min(safeStart, safeEnd);
      selectedWaveRangeRowIndex = rowIndex;
      selectedWaveRangeStart = safeStart;
      selectedWaveRangeEnd = safeEnd;
      selectedGroupIndex = -1;
      if (!opts.deferGroupRefresh) {
        const svg = waveContainer.querySelector('svg');
        if (svg) refreshGroupSelection(svg, buildGroupSourceMap(editor.value || ''));
      }
      if (!opts.deferControls) updateLegendAvailability();
    }

    function setSelectedSignal(rowIndex, colIndex) {
      const hasFilter = isNavFilteringActive();
      const visibleSet = getNavVisibleRowSet();
      if (hasFilter && Number.isFinite(rowIndex) && rowIndex >= 0 && !visibleSet.has(rowIndex)) {
        rowIndex = -1;
        colIndex = -1;
      }
      selectedSignalIndex = rowIndex;
      if (rowIndex < 0) {
        selectedWaveColumnIndex = -1;
        selectedWaveRangeRowIndex = -1;
        selectedWaveRangeStart = -1;
        selectedWaveRangeEnd = -1;
      } else if (colIndex !== undefined) {
        selectedWaveColumnIndex = colIndex;
        if (colIndex >= 0) {
          selectedWaveRangeRowIndex = rowIndex;
          selectedWaveRangeStart = colIndex;
          selectedWaveRangeEnd = colIndex;
        } else {
          selectedWaveRangeRowIndex = -1;
          selectedWaveRangeStart = -1;
          selectedWaveRangeEnd = -1;
        }
      }
      selectedGroupIndex = -1;
      const svg = waveContainer.querySelector('svg');
      if (svg) {
        refreshGroupSelection(svg, buildGroupSourceMap(editor.value || ''));
      }
      updateLegendAvailability();
    }

    function setSelectedSignalIndex(index) {
      setSelectedSignal(index, index >= 0 ? (selectedWaveColumnIndex >= 0 ? selectedWaveColumnIndex : 0) : -1);
    }

    function appendColumnHighlight(drawGroup, wave, colIndex, unitWidth, highlightClass, maxBoundaryIndex) {
      if (!drawGroup || colIndex < 0) return;
      const step = getWaveColumnWidth(unitWidth);
      const cls = highlightClass || 'wave-col-highlight';
      const isConnectionPoint = cls === 'wave-col-highlight-from' || cls === 'wave-col-highlight-to';

      let x0;
      let x1;
      if (isConnectionPoint) {
        const x = getBoundaryXForColumn(drawGroup, wave || '', colIndex, unitWidth, maxBoundaryIndex);
        x0 = x - 1.5;
        x1 = x + 1.5;
      } else {
        const cols = buildWaveColumnMap(drawGroup, wave || '', unitWidth);
        const col = cols[colIndex];
        if (col && col.x1 > col.x0) {
          x0 = col.x0;
          x1 = col.x1;
        } else {
          x0 = colIndex * step;
          x1 = (colIndex + 1) * step;
        }
      }

      let height = 24;
      try {
        height = Math.max(20, drawGroup.getBBox().height + 4);
      } catch (e) { /* ignore */ }

      const rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
      rect.setAttribute('class', cls);
      rect.setAttribute('x', x0);
      rect.setAttribute('y', -2);
      rect.setAttribute('width', Math.max(1, x1 - x0));
      rect.setAttribute('height', height);
      rect.setAttribute('pointer-events', 'none');
      drawGroup.appendChild(rect);
    }

    function appendVirtualLaneHighlight(lane, colIndex, unitWidth, highlightClass) {
      if (!lane || colIndex < 0) return;
      const step = getWaveColumnWidth(unitWidth);
      const cls = highlightClass || 'wave-col-highlight';
      const isConnectionPoint = cls === 'wave-col-highlight-from' || cls === 'wave-col-highlight-to';
      const hoverRect = lane.querySelector('rect.lane-hover-bg');
      const y = hoverRect ? parseFloat(hoverRect.getAttribute('y') || '-2') : -2;
      const height = hoverRect ? parseFloat(hoverRect.getAttribute('height') || '24') : 24;
      const x = colIndex * step;
      const rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
      rect.setAttribute('class', cls);
      rect.setAttribute('x', isConnectionPoint ? x - 1.5 : x);
      rect.setAttribute('y', y);
      rect.setAttribute('width', isConnectionPoint ? 3 : step);
      rect.setAttribute('height', Math.max(20, height));
      rect.setAttribute('pointer-events', 'none');
      lane.appendChild(rect);
    }

    function appendColumnRangeHighlight(drawGroup, wave, startCol, endCol, unitWidth) {
      if (!drawGroup || startCol < 0 || endCol < 0) return;
      const first = Math.min(startCol, endCol);
      const last = Math.max(startCol, endCol);
      const step = getWaveColumnWidth(unitWidth);
      const cols = buildWaveColumnMap(drawGroup, wave || '', unitWidth);
      const firstCol = cols[first];
      const lastCol = cols[last];
      const x0 = firstCol && firstCol.x1 > firstCol.x0 ? firstCol.x0 : first * step;
      const x1 = lastCol && lastCol.x1 > lastCol.x0 ? lastCol.x1 : (last + 1) * step;
      let height = 24;
      try {
        height = Math.max(20, drawGroup.getBBox().height + 4);
      } catch (e) { /* ignore */ }

      const rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
      rect.setAttribute('class', 'wave-col-highlight');
      rect.setAttribute('x', x0);
      rect.setAttribute('y', -2);
      rect.setAttribute('width', Math.max(1, x1 - x0));
      rect.setAttribute('height', height);
      rect.setAttribute('pointer-events', 'none');
      drawGroup.appendChild(rect);
    }

    function appendVirtualLaneRangeHighlight(lane, startCol, endCol, unitWidth) {
      if (!lane || startCol < 0 || endCol < 0) return;
      const first = Math.min(startCol, endCol);
      const last = Math.max(startCol, endCol);
      const step = getWaveColumnWidth(unitWidth);
      const hoverRect = lane.querySelector('rect.lane-hover-bg');
      const y = hoverRect ? parseFloat(hoverRect.getAttribute('y') || '-2') : -2;
      const height = hoverRect ? parseFloat(hoverRect.getAttribute('height') || '24') : 24;
      const rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
      rect.setAttribute('class', 'wave-col-highlight');
      rect.setAttribute('x', first * step);
      rect.setAttribute('y', y);
      rect.setAttribute('width', Math.max(1, (last - first + 1) * step));
      rect.setAttribute('height', Math.max(20, height));
      rect.setAttribute('pointer-events', 'none');
      lane.appendChild(rect);
    }

    function updateColumnHighlight(lane, drawGroup, wave, colIndex, unitWidth, highlightClass) {
      if (!drawGroup) return;
      drawGroup.querySelectorAll('.wave-col-highlight, .wave-col-highlight-from, .wave-col-highlight-to')
        .forEach(el => el.remove());
      appendColumnHighlight(drawGroup, wave, colIndex, unitWidth, highlightClass);
    }

    function isConnectionPickFlow() {
      return connectionAddSessionActive && connectionPickActive;
    }

    function areConnectionPresetsEnabledForInsert() {
      return connectionAddSessionActive && connectionFromPoint && connectionToPoint;
    }

    function getConnectionArrowToken(arrowStyle, lineStyle) {
      const lineToken = lineStyle === 'curve'
        ? '~'
        : (lineStyle === 'orthogonal' ? '-|' : '-');
      // WaveDrom has no native start-only arrow token. Keep its valid path token
      // and add the start marker from edgeOptions after rendering.
      if (arrowStyle === 'start') return lineToken;
      if (arrowStyle === 'both') return '<' + lineToken + '>';
      return lineToken + '>';
    }

    function buildConnectionTemplate(arrowStyle, lineStyle) {
      return '{from}' + getConnectionArrowToken(arrowStyle, lineStyle) + '{to} {label}';
    }

    function getEdgeLineStyleOption(source, index) {
      if (!source || !Array.isArray(source.edgeOptions)) return '';
      const option = source.edgeOptions[index];
      return option && typeof option === 'object' ? (option.lineStyle || '') : '';
    }

    function setEdgeLineStyleOption(source, index, lineStyle, arrowStyle) {
      const options = Array.isArray(source.edgeOptions) ? source.edgeOptions.slice() : [];
      while (options.length <= index) options.push(null);
      const option = options[index] && typeof options[index] === 'object'
        ? Object.assign({}, options[index])
        : {};
      if (lineStyle === 'dashed') option.lineStyle = 'dashed';
      else delete option.lineStyle;
      if (arrowStyle === 'start') option.arrowStyle = 'start';
      else delete option.arrowStyle;
      options[index] = Object.keys(option).length ? option : null;
      while (options.length && !options[options.length - 1]) options.pop();
      if (options.some(Boolean)) source.edgeOptions = options;
      else delete source.edgeOptions;
    }

    function getEdgePresentation(edgeStr, source, index) {
      const parsedEdge = parseEdgeString(edgeStr);
      const arrow = parsedEdge.arrow || '';
      let arrowStyle = 'end';
      if (arrow.includes('<') && arrow.includes('>')) arrowStyle = 'both';
      else if (arrow.includes('<')) arrowStyle = 'start';
      const option = source && Array.isArray(source.edgeOptions) ? source.edgeOptions[index] : null;
      if (option && CONNECTION_ARROW_STYLES.includes(option.arrowStyle)) arrowStyle = option.arrowStyle;

      let lineStyle = 'straight';
      if (arrow.includes('~')) lineStyle = 'curve';
      else if (arrow.includes('|')) lineStyle = 'orthogonal';
      if (getEdgeLineStyleOption(source, index) === 'dashed') lineStyle = 'dashed';
      return { arrowStyle, lineStyle };
    }

    function findPresetIndexForEdge(edgeStr) {
      let source = null;
      try { source = JSON.parse(editor.value); } catch (e) { /* ignore */ }
      const edges = source && Array.isArray(source.edge) ? source.edge : [];
      const index = edges.indexOf(edgeStr);
      return CONNECTION_LINE_STYLES.indexOf(getEdgePresentation(edgeStr, source, index).lineStyle);
    }

    function updateConnectionPropertiesUI() {
      const addBtn = document.getElementById('btn-add-connection');
      const selectBtn = document.getElementById('btn-select-connection');
      if (addBtn) {
        addBtn.classList.toggle('active', connectionAddSessionActive);
        addBtn.setAttribute('aria-pressed', String(connectionAddSessionActive));
      }
      if (selectBtn) {
        const labelEl = selectBtn.querySelector('.connection-select-label');
        const hasSelectedEdge = connectionSelectActive && selectedEdgeIndex >= 0;
        selectBtn.classList.toggle('active', connectionSelectActive);
        selectBtn.setAttribute('aria-pressed', String(connectionSelectActive));
        selectBtn.setAttribute('aria-label', hasSelectedEdge ? '取消选择' : '选择连接线');
        selectBtn.title = hasSelectedEdge
          ? '取消当前连接线选择并退出选择模式'
          : '进入选择连接线模式，点击图中的连接线查看和修改属性';
        if (labelEl) labelEl.textContent = hasSelectedEdge ? '取消选择' : '选择连接线';
      }
      app.classList.toggle('connection-select-mode', connectionSelectActive);
      app.classList.toggle(
        'connection-add-mode',
        connectionAddSessionActive && connectionPickActive
      );

      const canEditArrow = connectionAddSessionActive || selectedEdgeIndex >= 0;
      const canChooseLine = areConnectionPresetsEnabledForInsert() || selectedEdgeIndex >= 0;
      document.querySelectorAll('#connection-arrow-controls [data-arrow-style]').forEach((button) => {
        const active = button.dataset.arrowStyle === connectionArrowStyle;
        button.classList.toggle('active', active);
        button.setAttribute('aria-pressed', String(active));
        button.disabled = !canEditArrow;
      });
      document.querySelectorAll('#connection-list [data-line-style]').forEach((button) => {
        const active = button.dataset.lineStyle === connectionLineStyle;
        button.classList.toggle('active', active);
        button.setAttribute('aria-pressed', String(active));
        button.disabled = !canChooseLine;
      });

      const input = document.getElementById('connection-label-input');
      const applyBtn = document.getElementById('btn-apply-edge-label');
      const labelEnabled = connectionAddSessionActive || selectedEdgeIndex >= 0;
      if (input) input.disabled = !labelEnabled;
      if (applyBtn) applyBtn.disabled = !labelEnabled;
    }

    function updateConnectionPresetSelection() {
      updateConnectionPropertiesUI();
    }

    function updateConnectionPresetDisabledState() {
      updateConnectionPropertiesUI();
    }

    function shouldKeepConnectionSelectionForButton(button) {
      if (!button) return false;
      if (button.id === 'btn-select-connection') return true;
      if (button.id === 'btn-wave-text-edit-mode') return true;
      if (button.id === 'btn-delete-wave-col') return true;
      if (button.closest('#connection-properties')) return true;
      if (button.closest('#connection-edge-list')) return true;
      return false;
    }

    function cancelConnectionSelectionForOtherButton(event) {
      if (!connectionSelectActive) return;
      const button = event.target && event.target.closest
        ? event.target.closest('button, .legend-item')
        : null;
      if (!button || shouldKeepConnectionSelectionForButton(button)) return;
      const previousIndex = selectedEdgeIndex;
      setConnectionSelectActive(false);
      vwdDebugLog('connection', {
        phase: 'selection-cancelled-by-button',
        buttonId: button.id || '',
        previousIndex
      });
    }

    function endConnectionAddSession() {
      connectionAddSessionActive = false;
      connectionPickActive = false;
      pendingEdgeTemplate = null;
      clearConnectionPoints();
      updateConnectionPresetDisabledState();
    }

    function finishConnectionAddSessionFast() {
      connectionAddSessionActive = false;
      connectionPickActive = false;
      pendingEdgeTemplate = null;
      connectionFromPoint = null;
      connectionToPoint = null;
      updateEdgeLabelEditUI();
      updateConnectionPointStatusUI();
      updateConnectionPresetDisabledState();
    }
    function scheduleConnectionHighlightUpdate(lanes, sourceMap) {
      pendingHighlightLanes = lanes;
      pendingHighlightSourceMap = sourceMap;
      if (connectionHighlightRaf !== null) return;
      connectionHighlightRaf = requestAnimationFrame(() => {
        connectionHighlightRaf = null;
        const lanesRef = pendingHighlightLanes;
        const mapRef = pendingHighlightSourceMap;
        pendingHighlightLanes = null;
        pendingHighlightSourceMap = null;
        if (lanesRef && mapRef) {
          updateConnectionPointHighlights(lanesRef, mapRef);
        }
      });
    }

    function refreshConnectionHighlightsFromDom() {
      const svg = waveContainer.querySelector('svg');
      if (!svg) return;
      const lanes = getWaveLaneGroups(svg);
      let sourceMap = [];
      try {
        sourceMap = buildSignalSourceMap(editor.value);
      } catch (e) { /* ignore */ }
      scheduleConnectionHighlightUpdate(lanes, sourceMap);
    }

    function updateConnectionPointHighlights(lanes, sourceMap) {
      const unitWidth = getWaveUnitWidth(editor.value);
      const maxBoundaryIndex = getConnectionPickBoundaryIndex(sourceMap);
      lanes.forEach((lane, idx) => {
        const drawGroup = lane.querySelector('[id^="wavelane_draw_"]');
        if (!sourceMap[idx]) return;
        const wave = sourceMap[idx].signal.wave || '';

        const isFrom = connectionFromPoint && connectionFromPoint.rowIndex === idx;
        const isTo = connectionToPoint && connectionToPoint.rowIndex === idx;
        const isSelected = selectedSignalIndex === idx;
        const selectedRange = isSelected ? getSelectedWaveRange(idx) : null;

        const highlightRoot = drawGroup || lane;
        highlightRoot.querySelectorAll('.wave-col-highlight, .wave-col-highlight-from, .wave-col-highlight-to')
          .forEach(el => el.remove());

        if (isFrom) {
          if (drawGroup) appendColumnHighlight(drawGroup, wave, connectionFromPoint.colIndex, unitWidth, 'wave-col-highlight-from', maxBoundaryIndex);
          else appendVirtualLaneHighlight(lane, connectionFromPoint.colIndex, unitWidth, 'wave-col-highlight-from');
        }
        if (isTo) {
          if (drawGroup) appendColumnHighlight(drawGroup, wave, connectionToPoint.colIndex, unitWidth, 'wave-col-highlight-to', maxBoundaryIndex);
          else appendVirtualLaneHighlight(lane, connectionToPoint.colIndex, unitWidth, 'wave-col-highlight-to');
        }
        if (isSelected && selectedRange && !isFrom && !isTo) {
          if (drawGroup) {
            appendColumnRangeHighlight(drawGroup, wave, selectedRange.start, selectedRange.end, unitWidth);
          } else {
            appendVirtualLaneRangeHighlight(lane, selectedRange.start, selectedRange.end, unitWidth);
          }
        }
      });
    }

    function restoreWaveSelection(lanes, sourceMap) {
      if (selectedSignalIndex < 0 && selectedGroupIndex < 0 && !connectionFromPoint && !connectionToPoint) return;
      const visibleSet = getNavVisibleRowSet();
      const hasFilter = isNavFilteringActive();
      if (selectedSignalIndex >= lanes.length || (selectedSignalIndex >= 0 && !sourceMap[selectedSignalIndex])) {
        setSelectedSignal(-1, -1);
      } else if (hasFilter && !visibleSet.has(selectedSignalIndex)) {
        setSelectedSignal(-1, -1);
      }

      lanes.forEach((lane, idx) => {
        lane.classList.toggle('wave-lane-selected', idx === selectedSignalIndex);
      });

      updateConnectionPointHighlights(lanes, sourceMap);
      const svg = waveContainer.querySelector('svg');
      if (svg) {
        refreshGroupSelection(svg, buildGroupSourceMap(editor.value || ''));
      }
      updateLegendAvailability();
    }

    function applyNavVisibilityToWave() {
      const svg = waveContainer.querySelector('svg');
      if (!svg) return;
      const lanes = getWaveLaneGroups(svg);
      const visibleSet = getNavVisibleRowSet();
      const hasFilter = isNavFilteringActive();
      lanes.forEach((lane, idx) => {
        const visible = !hasFilter || visibleSet.has(idx);
        lane.classList.toggle('wave-lane-hidden', !visible);
        lane.style.display = visible ? '' : 'none';
      });
      if (selectedSignalIndex >= 0 && !hasFilter) return;
      if (selectedSignalIndex >= 0 && !visibleSet.has(selectedSignalIndex)) {
        setSelectedSignal(-1, -1);
      }
      updateConnectionPointStatusUI();
    }

    function applyLegendCharToSelection(char) {
      if (selectedSignalIndex < 0) {
        setStatus(false, '请先在波形区点击选中一行');
        return;
      }

      const selectedRange = getSelectedWaveRange();
      if (selectedRange && selectedRange.end > selectedRange.start) {
        const count = selectedRange.end - selectedRange.start + 1;
        applyWaveRangeReplacement(
          selectedSignalIndex,
          selectedRange.start,
          char.repeat(count),
          '批量替换'
        );
        return;
      }

      let wave = '';
      try {
        const sourceMap = buildSignalSourceMap(editor.value);
        const entry = sourceMap[selectedSignalIndex];
        if (entry) wave = entry.signal.wave || '';
      } catch (e) { /* use defaults below */ }

      const forInsert = waveEditMode === 'insert';
      const col = resolveLegendColumnIndex(wave, forInsert);
      if (forInsert) {
        applyWaveCharInsertAtColumn(selectedSignalIndex, col, char);
      } else {
        applyWaveCharAtColumn(selectedSignalIndex, col, char);
      }
    }

    function insertSignalAfterFlatIndex(signals, targetIndex, newSignal, state) {
      if (!Array.isArray(signals) || targetIndex < 0) return false;
      const cursor = state || { index: 0 };
      const startIndex = typeof signals[0] === 'string' ? 1 : 0;
      for (let i = startIndex; i < signals.length; i++) {
        const item = signals[i];
        if (Array.isArray(item)) {
          if (insertSignalAfterFlatIndex(item, targetIndex, newSignal, cursor)) return true;
          continue;
        }
        if (!item || typeof item !== 'object') continue;
        if (cursor.index === targetIndex) {
          signals.splice(i + 1, 0, newSignal);
          return true;
        }
        cursor.index += 1;
      }
      return false;
    }

    function insertNewSignalRow(template) {
      const tpl = Object.assign({}, template || DEFAULT_NEW_SIGNAL_TEMPLATE);

      let parsed;
      try {
        parsed = JSON.parse(editor.value);
      } catch (e) {
        setStatus(false, 'JSON 错误，新增行失败');
        return false;
      }
      if (!Array.isArray(parsed.signal)) parsed.signal = [];

      pushUndoBeforeChange();
      const oldMap = buildSignalSourceMap(editor.value);
      const hasSelectedRow = selectedSignalIndex >= 0 && selectedSignalIndex < oldMap.length;
      const insertedAfterSelection = hasSelectedRow
        && insertSignalAfterFlatIndex(parsed.signal, selectedSignalIndex, tpl);
      if (!insertedAfterSelection) parsed.signal.push(tpl);

      const newText = JSON.stringify(parsed, null, 2);
      const newMap = buildSignalSourceMap(newText);
      const newIndex = insertedAfterSelection ? selectedSignalIndex + 1 : newMap.length - 1;
      const insertedEntry = newMap[newIndex];
      const selStart = insertedEntry ? insertedEntry.start : newText.length;
      const selEnd = insertedEntry ? insertedEntry.end : selStart;
      if (!tpl.name) pendingNameEditSignalIndex = newIndex;
      setSelectedSignal(newIndex, 0);
      applyEditorChange(newText, selStart, selEnd);
      scheduleFormatAfterWaveChange();
      setStatus(true, tpl.name ? ('已插入信号: ' + tpl.name) : '已插入空白信号行');
      return true;
    }

    function copySelectedSignalRow() {
      const text = editor.value;
      const sourceMap = buildSignalSourceMap(text);
      const sourceEntry = sourceMap[selectedSignalIndex];
      if (!sourceEntry) {
        setStatus(false, '请先在波形区点击选中一行');
        updateLegendAvailability();
        return false;
      }

      let parsed;
      try {
        parsed = JSON.parse(text);
      } catch (e) {
        setStatus(false, 'JSON 错误，复制行失败');
        return false;
      }
      if (!parsed || !Array.isArray(parsed.signal)) {
        setStatus(false, 'JSON 错误，复制行失败');
        return false;
      }

      const copiedSignal = JSON.parse(JSON.stringify(sourceEntry.signal || {}));
      delete copiedSignal.node;
      const sourceIndex = selectedSignalIndex;
      const selectedColumn = selectedWaveColumnIndex;
      if (!insertSignalAfterFlatIndex(parsed.signal, sourceIndex, copiedSignal)) {
        setStatus(false, '未找到要复制的信号行');
        return false;
      }

      pushUndoBeforeChange();
      const newText = JSON.stringify(parsed, null, 2);
      const newIndex = sourceIndex + 1;
      const newMap = buildSignalSourceMap(newText);
      const insertedEntry = newMap[newIndex];
      adjustConnectionPointAfterRowInsert(newIndex);
      adjustPendingNameEditAfterRowInsert(newIndex);
      setSelectedSignal(newIndex, selectedColumn >= 0 ? selectedColumn : 0);
      applyEditorChange(
        newText,
        insertedEntry ? insertedEntry.start : editor.selectionStart,
        insertedEntry ? insertedEntry.end : editor.selectionEnd
      );
      scheduleFormatAfterWaveChange();
      setStatus(true, '已复制信号行: ' + (copiedSignal.name || ('第 ' + (sourceIndex + 1) + ' 行')) + '（未复制 node）');
      return true;
    }

    function removeSignalFromText(text, index) {
      const sourceMap = buildSignalSourceMap(text);
      if (index < 0 || index >= sourceMap.length) return text;

      const entry = sourceMap[index];
      const absStart = entry.start;
      const absEnd = entry.end;
      const bounds = findSignalArrayBounds(text);
      if (!bounds) return text;

      const before = text.slice(bounds.arrStart, absStart);
      const after = text.slice(absEnd, bounds.arrEnd);

      let start = absStart;
      let end = absEnd;
      const trailingComma = after.match(/^\s*,\s*/);
      const leadingComma = before.match(/,\s*$/);
      if (trailingComma) {
        end = absEnd + trailingComma[0].length;
      } else if (leadingComma) {
        start = absStart - leadingComma[0].length;
      }
      return text.slice(0, start) + text.slice(end);
    }

    function collectSignalLocations(signals, locations) {
      const result = locations || [];
      if (!Array.isArray(signals)) return result;
      const startIndex = typeof signals[0] === 'string' ? 1 : 0;
      for (let i = startIndex; i < signals.length; i++) {
        const item = signals[i];
        if (Array.isArray(item)) {
          collectSignalLocations(item, result);
        } else if (item && typeof item === 'object') {
          result.push({ signal: item, parent: signals, index: i });
        }
      }
      return result;
    }

    function moveSignalToFlatIndex(signals, fromIndex, toIndex) {
      const locations = collectSignalLocations(signals);
      const source = locations[fromIndex];
      const target = locations[toIndex];
      if (!source || !target || fromIndex === toIndex) return false;

      source.parent.splice(source.index, 1);
      const liveTargetIndex = target.parent.indexOf(target.signal);
      if (liveTargetIndex < 0) {
        source.parent.splice(source.index, 0, source.signal);
        return false;
      }
      const insertIndex = toIndex < fromIndex ? liveTargetIndex : liveTargetIndex + 1;
      target.parent.splice(insertIndex, 0, source.signal);
      return true;
    }

    function adjustConnectionPointAfterRowDelete(deletedIndex) {
      function adjust(pt) {
        if (!pt) return null;
        if (pt.rowIndex === deletedIndex) return null;
        if (pt.rowIndex > deletedIndex) return { rowIndex: pt.rowIndex - 1, colIndex: pt.colIndex };
        return pt;
      }
      connectionFromPoint = adjust(connectionFromPoint);
      connectionToPoint = adjust(connectionToPoint);
      updateConnectionPointStatusUI();
    }

    function adjustConnectionPointAfterRowInsert(insertedIndex) {
      function adjust(pt) {
        if (!pt || pt.rowIndex < insertedIndex) return pt;
        return Object.assign({}, pt, { rowIndex: pt.rowIndex + 1 });
      }
      connectionFromPoint = adjust(connectionFromPoint);
      connectionToPoint = adjust(connectionToPoint);
      updateConnectionPointStatusUI();
    }

    function mapRowIndexAfterMove(rowIndex, fromIndex, toIndex) {
      if (rowIndex === fromIndex) return toIndex;
      if (fromIndex < toIndex && rowIndex > fromIndex && rowIndex <= toIndex) return rowIndex - 1;
      if (toIndex < fromIndex && rowIndex >= toIndex && rowIndex < fromIndex) return rowIndex + 1;
      return rowIndex;
    }

    function adjustConnectionPointAfterRowMove(fromIndex, toIndex) {
      function adjust(pt) {
        if (!pt) return null;
        return Object.assign({}, pt, { rowIndex: mapRowIndexAfterMove(pt.rowIndex, fromIndex, toIndex) });
      }
      connectionFromPoint = adjust(connectionFromPoint);
      connectionToPoint = adjust(connectionToPoint);
      updateConnectionPointStatusUI();
    }

    function adjustPendingNameEditAfterRowDelete(deletedIndex) {
      if (pendingNameEditSignalIndex < 0) return;
      if (pendingNameEditSignalIndex === deletedIndex) {
        pendingNameEditSignalIndex = -1;
      } else if (pendingNameEditSignalIndex > deletedIndex) {
        pendingNameEditSignalIndex--;
      }
    }

    function adjustPendingNameEditAfterRowInsert(insertedIndex) {
      if (pendingNameEditSignalIndex >= insertedIndex) pendingNameEditSignalIndex++;
    }

    function adjustPendingNameEditAfterRowMove(fromIndex, toIndex) {
      if (pendingNameEditSignalIndex < 0) return;
      pendingNameEditSignalIndex = mapRowIndexAfterMove(pendingNameEditSignalIndex, fromIndex, toIndex);
    }

    function indentJsonBlock(block, fromIndent, toIndent) {
      return block.split('\n').map((line) => {
        if (!line) return line;
        if (fromIndent && line.startsWith(fromIndent)) {
          return toIndent + line.slice(fromIndent.length);
        }
        return toIndent + line;
      }).join('\n');
    }

    function groupSelectedSignalRow() {
      beginGroupPick();
    }

    function clearSelectedGroupState() {
      selectedGroupIndex = -1;
      setGroupDeleteShortcutActive(false, 'clear-group-selection');
      groupPickActive = false;
      groupPickStartIndex = -1;
    }

    function beginGroupPick() {
      exitWavePaintMode('group-mode');
      if (groupPickActive) {
        clearSelectedGroupState();
        updateLegendAvailability();
        setStatus(true, '已重选分组起点，请选择结束行');
        return;
      }

      try {
        JSON.parse(editor.value);
      } catch (e) {
        setStatus(false, 'JSON 错误，删除失败');
        return;
      }

      const sourceMap = buildSignalSourceMap(editor.value);
      if (!sourceMap.length) {
        setStatus(false, 'JSON 错误，删除失败');
        return;
      }

      if (isConnectionPickFlow()) {
        setConnectionPickActive(false);
      }
      if (connectionAddSessionActive) {
        endConnectionAddSession();
      }

      clearSelectedGroupState();
      groupPickActive = true;
      selectedSignalIndex = -1;
      selectedWaveColumnIndex = -1;
      groupPickStartIndex = -1;
      updateLegendAvailability();
      setStatus(true, '已进入分组模式，请先点击起始行');
    }

    function setSelectedGroup(index) {
      clearSelectedGroupState();
      const groupIndex = Number.isFinite(index) ? index : -1;
      selectedGroupIndex = groupIndex;
      selectedSignalIndex = -1;
      selectedWaveColumnIndex = -1;
      const svg = waveContainer.querySelector('svg');
      if (svg && selectedGroupIndex >= 0) {
        const groupMap = buildGroupSourceMap(editor.value || '');
        const group = groupMap[selectedGroupIndex];
        if (group) {
          refreshGroupSelection(svg, groupMap);
          requestAnimationFrame(() => scrollEditorToGroup(group));
        } else {
          selectedGroupIndex = -1;
          refreshGroupSelection(svg, groupMap);
        }
      }
      updateLegendAvailability();
      setGroupDeleteShortcutActive(selectedGroupIndex >= 0, 'select-group');
      return selectedGroupIndex >= 0;
    }

    function beginHandleGroupPickFromRow(rowIndex, lanes) {
      if (!groupPickActive) return;
      if (groupPickStartIndex < 0) {
        groupPickStartIndex = rowIndex;
        if (lanes) {
          lanes.forEach((lane, idx) => lane.classList.toggle('wave-group-pick-start', idx === rowIndex));
        }
        setStatus(true, '已选择起始行: ' + (rowIndex + 1) + '，请点击结束行');
        return;
      }

      const start = Math.min(groupPickStartIndex, rowIndex);
      const end = Math.max(groupPickStartIndex, rowIndex);
      clearGroupPickStartMark(lanes);
      groupPickActive = false;
      if (!app.classList.contains('reading-mode')) {
        setStatus(true, '已选择起始行: ' + (Math.min(groupPickStartIndex, rowIndex) + 1) + ' 到 ' + (end + 1));
      }
      createGroupFromSignalRows(start, end);
    }

    function clearGroupPickStartMark(lanes) {
      if (!lanes) return;
      lanes.forEach((lane) => lane.classList.remove('wave-group-pick-start'));
    }

    function createGroupFromSignalRows(startIndex, endIndex) {
      const text = editor.value;
      const sourceMap = buildSignalSourceMap(text);
      if (!sourceMap.length || startIndex < 0 || endIndex < 0) {
        setStatus(false, 'JSON 错误，删除失败');
        return;
      }

      const startSignal = sourceMap[startIndex];
      const endSignal = sourceMap[endIndex];
      if (!startSignal || !endSignal) {
        setStatus(false, 'JSON 错误，删除失败');
        return;
      }

      const groupMap = buildGroupSourceMap(text);
      const startGroup = getInnermostGroupByRowIndex(groupMap, startIndex);
      const endGroup = getInnermostGroupByRowIndex(groupMap, endIndex);
      const startBoundaryGroup = startGroup && !isRowIndexInGroup(endIndex, startGroup) ? startGroup : null;
      const endBoundaryGroup = endGroup && !isRowIndexInGroup(startIndex, endGroup) ? endGroup : null;

      const replaceStart = startBoundaryGroup ? startBoundaryGroup.start : startSignal.start;
      const replaceEnd = endBoundaryGroup ? endBoundaryGroup.end : endSignal.end;

      if (replaceEnd < replaceStart) {
        setStatus(false, 'JSON 错误，删除失败');
        return;
      }

      const replaceRows = sourceMap.filter((row) => row.start >= replaceStart && row.end <= replaceEnd);
      if (replaceRows.length === 0) {
        setStatus(false, 'JSON 错误，无法修改标签');
        return;
      }

      const rowBlocks = replaceRows.map((row) => text.slice(row.start, row.end).trimEnd());
      const blockBody = rowBlocks.join(',\n');
      const indent = getIndentAt(text, replaceStart);
      const childIndent = indent + '  ';
      const groupBlock = indent + '[' + JSON.stringify('分组') + ',\n'
        + childIndent + blockBody.replace(/\n/g, '\n' + childIndent)
        + '\n' + indent + ']';
      const newText = text.slice(0, replaceStart) + groupBlock + text.slice(replaceEnd);

      if (newText === text) {
        setStatus(false, 'JSON 错误，删除失败');
        return;
      }

      pushUndoBeforeChange();
      const newGroupIndex = buildGroupSourceMap(newText).findIndex((g) => g.start === replaceStart);
      selectedGroupIndex = newGroupIndex;
      setGroupDeleteShortcutActive(newGroupIndex >= 0, 'create-group');
      selectedSignalIndex = -1;
      selectedWaveColumnIndex = -1;
      applyEditorChange(newText, replaceStart, replaceStart + groupBlock.length);
      scheduleFormatAfterWaveChange();
      setStatus(true, '已生成分组（第 ' + (startIndex + 1) + ' - ' + (endIndex + 1) + ' 行）');
    }

    function deleteSelectedGroup() {
      const text = editor.value;
      const groupMap = buildGroupSourceMap(text);
      const group = groupMap[selectedGroupIndex];
      if (!group) {
        selectedGroupIndex = -1;
        updateLegendAvailability();
        setStatus(false, 'JSON 错误，删除失败');
        return;
      }

      const bounds = findSignalArrayBounds(text);
      if (!bounds) {
        setStatus(false, 'JSON 错误，删除失败');
        return;
      }

      const newText = unwrapGroupWithoutLabelFromSource(text, group);
      if (newText === text) {
        setStatus(false, 'JSON 错误，删除失败');
        return;
      }

      try {
        JSON.parse(newText);
      } catch (e) {
        setStatus(false, 'JSON 错误，无法修改连接');
        return;
      }

      pushUndoBeforeChange();
      selectedGroupIndex = -1;
      setGroupDeleteShortcutActive(false, 'delete-group');
      selectedSignalIndex = -1;
      selectedWaveColumnIndex = -1;
      applyEditorChange(newText, Math.max(0, Math.min(group.start, Math.max(0, newText.length - 1))), group.start);
      scheduleFormatAfterWaveChange();
      setStatus(true, '已删除分组：' + (group.label || '分组'));
    }

    async function moveSelectedSignalRow(delta) {
      if (selectedSignalIndex < 0) {
        setStatus(false, '请先在波形区点击选中一行');
        return;
      }
      if (delta !== -1 && delta !== 1) return;

      let parsed;
      try {
        parsed = JSON.parse(editor.value);
      } catch (e) {
        setStatus(false, 'JSON 错误，移动行失败');
        return;
      }

      const sourceMap = buildSignalSourceMap(editor.value);
      const fromIndex = selectedSignalIndex;
      if (!sourceMap[fromIndex]) {
        setSelectedSignal(-1, -1);
        setStatus(false, '未找到要移动的信号行');
        return;
      }
      const moveCount = await requestMoveDistance(delta < 0 ? 'up' : 'down', '行');
      if (moveCount === null) return;
      const toIndex = delta < 0
        ? Math.max(0, fromIndex - moveCount)
        : Math.min(sourceMap.length - 1, fromIndex + moveCount);
      if (toIndex === fromIndex) return;

      const entry = sourceMap[fromIndex];
      const signalName = entry ? (entry.signal.name || ('row' + fromIndex)) : ('row' + fromIndex);
      const selectedColumn = selectedWaveColumnIndex;

      if (!parsed || !Array.isArray(parsed.signal)
          || !moveSignalToFlatIndex(parsed.signal, fromIndex, toIndex)) {
        setStatus(false, '移动信号行失败');
        return;
      }

      pushUndoBeforeChange();
      const newText = JSON.stringify(parsed, null, 2);
      const movedEntry = buildSignalSourceMap(newText)[toIndex];
      adjustConnectionPointAfterRowMove(fromIndex, toIndex);
      adjustPendingNameEditAfterRowMove(fromIndex, toIndex);
      setSelectedSignal(toIndex, selectedColumn >= 0 ? selectedColumn : 0);
      applyEditorChange(
        newText,
        movedEntry ? movedEntry.start : editor.selectionStart,
        movedEntry ? movedEntry.end : editor.selectionEnd
      );
      scheduleFormatAfterWaveChange();
      setStatus(
        true,
        (delta < 0 ? '已上移 ' : '已下移 ') + Math.abs(toIndex - fromIndex) + ' 行: ' + signalName
      );
    }

    function deleteSelectedSignalRow() {
      if (selectedGroupIndex >= 0) {
        deleteSelectedGroup();
        return;
      }
      if (selectedSignalIndex < 0) {
        setStatus(false, 'JSON 错误，无法修改连接');
        return;
      }

      try {
        JSON.parse(editor.value);
      } catch (e) {
        setStatus(false, 'JSON 错误，无法修改连接');
        return;
      }

      const text = editor.value;
      const sourceMap = buildSignalSourceMap(text);
      const deletedIndex = selectedSignalIndex;
      const entry = sourceMap[deletedIndex];
      if (!entry) {
        setSelectedSignal(-1, -1);
        setStatus(false, 'JSON 错误，无法修改连接');
        return;
      }

      const signalName = entry.signal.name || ('row' + deletedIndex);
      const deletedNodeChars = new Set();
      const nodeStr = entry.signal.node || '';
      for (let i = 0; i < nodeStr.length; i++) {
        if (nodeStr[i] !== '.') deletedNodeChars.add(nodeStr[i]);
      }

      pushUndoBeforeChange();
      let newText = removeSignalFromText(text, deletedIndex);
      if (newText === text) {
        setStatus(false, 'JSON 错误，无法修改连接');
        return;
      }

      let parsed;
      try {
        parsed = JSON.parse(newText);
      } catch (e) {
        setStatus(false, 'JSON 错误，无法修改连接');
        return;
      }

      const nodeUpdates = cleanupOrphanedNodeUpdates(parsed);
      if (nodeUpdates.length) {
        newText = applySignalUpdatesInText(newText, nodeUpdates);
        parsed = JSON.parse(newText);
      }

      const newCount = flattenSignals(parsed.signal || []).length;
      adjustConnectionPointAfterRowDelete(deletedIndex);
      adjustPendingNameEditAfterRowDelete(deletedIndex);

      let newSelectedIndex = -1;
      if (newCount > 0) {
        newSelectedIndex = deletedIndex >= newCount ? newCount - 1 : deletedIndex;
      }
      setSelectedSignal(newSelectedIndex, newSelectedIndex >= 0 ? 0 : -1);
      applyEditorChange(newText, editor.selectionStart, editor.selectionEnd);
      scheduleFormatAfterWaveChange();

      let statusMsg = '已删除信号行: ' + signalName;
      const affectedEdges = (parsed.edge || []).filter((edgeStr) => {
        const { from, to } = parseEdgeString(edgeStr);
        return deletedNodeChars.has(from) || deletedNodeChars.has(to);
      });
      if (affectedEdges.length) {
        statusMsg += ' , affected edges: ' + affectedEdges.length + ' related connections removed';
      }
      setStatus(true, statusMsg);
    }

    function findEdgeArrayBounds(text) {
      const match = text.match(/"edge"\s*:\s*\[/);
      if (!match) return null;
      const arrStart = match.index + match[0].length;
      let depth = 1;
      let inString = false;
      let escape = false;
      for (let i = arrStart; i < text.length; i++) {
        const c = text[i];
        if (inString) {
          if (escape) escape = false;
          else if (c === '\\') escape = true;
          else if (c === '"') inString = false;
          continue;
        }
        if (c === '"') { inString = true; continue; }
        if (c === '[') depth++;
        if (c === ']') {
          depth--;
          if (depth === 0) return { arrStart, arrEnd: i, insertBefore: i };
        }
      }
      return null;
    }

    function ensureEdgeArrayInText(text) {
      const existing = findEdgeArrayBounds(text);
      if (existing) return { text, bounds: existing };

      const signalBounds = findSignalArrayBounds(text);
      if (!signalBounds) return null;

      const indent = getIndentAt(text, signalBounds.arrStart) || '  ';
      const edgeBlock = ',\n' + indent + '"edge": [\n' + indent + ']';
      const insertPos = signalBounds.arrEnd + 1;
      const newText = text.slice(0, insertPos) + edgeBlock + text.slice(insertPos);
      const bounds = findEdgeArrayBounds(newText);
      return bounds ? { text: newText, bounds } : null;
    }

    const NODE_ID_POOL = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';

    function connectionPointLabel(point, sourceMap) {
      if (!point) return '—';
      const entry = sourceMap && sourceMap[point.rowIndex];
      const name = entry ? (entry.signal.name || ('row' + point.rowIndex)) : ('row' + point.rowIndex);
      return name + '[' + point.colIndex + ']';
    }

    function clearConnectionPoints() {
      connectionFromPoint = null;
      connectionToPoint = null;
      updateConnectionPointStatusUI();
    }

    function setConnectionPickActive(active) {
      connectionPickActive = !!active;
      updateConnectionPointStatusUI();
      updateConnectionPresetDisabledState();
      refreshConnectionHighlightsFromDom();
    }

    function setConnectionSelectActive(active) {
      connectionSelectActive = !!active;
      if (connectionSelectActive) {
        connectionAddSessionActive = false;
        connectionPickActive = false;
        clearConnectionPoints();
      } else {
        clearEdgeSelection();
      }
      updateConnectionPointStatusUI();
      updateConnectionPropertiesUI();
      vwdDebugLog('connection', { phase: 'select-mode', active: connectionSelectActive });
    }

    function updateConnectionPointStatusUI() {
      const el = document.getElementById('connection-point-status');
      if (!el) return;
      let sourceMap = [];
      try {
        sourceMap = buildSignalSourceMap(editor.value);
      } catch (e) { /* ignore */ }

      const fromLabel = connectionFromPoint
        ? connectionPointLabel(connectionFromPoint, sourceMap)
        : '未选择';
      const toLabel = connectionToPoint
        ? connectionPointLabel(connectionToPoint, sourceMap)
        : '未选择';

      let hint = '';
      if (connectionAddSessionActive && connectionPickActive) {
        if (!connectionFromPoint) hint = ' · 请在波形上点击连接起点';
        else if (!connectionToPoint) hint = ' · 请点击连接终点';
        else hint = ' · 请选择连接样式';
      } else if (connectionPickActive && !connectionAddSessionActive) {
        hint = ' · 请先点击「新增连接」';
      } else if (connectionSelectActive) {
        hint = selectedEdgeIndex >= 0 ? ' · 可修改下方属性' : ' · 请点击图中的连接线';
      }

      el.textContent = '';
      el.appendChild(document.createTextNode('起点 '));
      const fromSpan = document.createElement('span');
      fromSpan.className = 'pt-from';
      fromSpan.textContent = fromLabel;
      el.appendChild(fromSpan);
      el.appendChild(document.createTextNode(' → 终点 '));
      const toSpan = document.createElement('span');
      toSpan.className = 'pt-to';
      toSpan.textContent = toLabel;
      el.appendChild(toSpan);
      if (hint) el.appendChild(document.createTextNode(hint));
    }

    function handleConnectionPointClick(rowIndex, colIndex, svgPoint) {
      if (!connectionAddSessionActive || !connectionPickActive) return false;

      if (!connectionFromPoint) {
        connectionFromPoint = Object.assign({ rowIndex, colIndex }, svgPoint || {});
        setStatus(true, '已选连接起点 [' + rowIndex + ',' + colIndex + ']，请选择终点');
      } else if (!connectionToPoint) {
        connectionToPoint = Object.assign({ rowIndex, colIndex }, svgPoint || {});
        setStatus(true, '已选连接终点 [' + rowIndex + ',' + colIndex + ']，请选择连接线样式');
      } else {
        connectionFromPoint = Object.assign({ rowIndex, colIndex }, svgPoint || {});
        connectionToPoint = null;
        setStatus(true, '已重选连接起点，请选择终点');
      }

      queueMicrotask(updateConnectionPointStatusUI);
      updateConnectionPresetDisabledState();
      vwdDebugLog('connection', {
        phase: 'point-picked',
        rowIndex,
        colIndex,
        hasFrom: !!connectionFromPoint,
        hasTo: !!connectionToPoint
      });
      return true;
    }

    function padNodeToWaveLength(node, waveLen) {
      let out = node || '';
      while (out.length < waveLen) out += '.';
      if (out.length > waveLen) out = out.slice(0, waveLen);
      return out;
    }

    function getNodeAtColumn(signal, colIndex) {
      const node = signal && typeof signal.node === 'string' ? signal.node : '';
      if (colIndex >= 0 && colIndex < node.length && node[colIndex] !== '.') {
        return node[colIndex];
      }
      return null;
    }

    function ensureNodeCharAtColumn(signal, colIndex, nodeChar) {
      const safeCol = colIndex < 0 ? 0 : Math.floor(colIndex);
      const baseSignal = signal && typeof signal === 'object' ? signal : {};
      let node = typeof baseSignal.node === 'string' ? baseSignal.node : '';
      if (node.length <= safeCol) node = node.padEnd(safeCol + 1, '.');
      node = node.slice(0, safeCol) + nodeChar + node.slice(safeCol + 1);
      return Object.assign({}, baseSignal, { node });
    }

    function collectUsedNodeIds(parsed) {
      const used = new Set();
      flattenSignals(parsed.signal || []).forEach((sig) => {
        const node = sig.node || '';
        for (let i = 0; i < node.length; i++) {
          const ch = node[i];
          if (ch !== '.') used.add(ch);
        }
      });
      (parsed.edge || []).forEach((edgeStr) => {
        const firstWord = String(edgeStr).trim().split(/\s+/)[0] || '';
        for (let i = 0; i < firstWord.length; i++) {
          const ch = firstWord[i];
          if (/[a-zA-Z0-9]/.test(ch)) used.add(ch);
        }
      });
      return used;
    }

    function collectUsedNodeIdsFromTextFast(text, points) {
      const used = new Set();
      (points || []).forEach((point) => {
        const signal = point && point.entry && point.entry.signal;
        const node = signal ? (signal.node || '') : '';
        for (let i = 0; i < node.length; i++) {
          const ch = node[i];
          if (ch !== '.') used.add(ch);
        }
      });
      const edgeBounds = findEdgeArrayBounds(text);
      if (edgeBounds) {
        const inner = text.slice(edgeBounds.arrStart, edgeBounds.arrEnd);
        const re = /"((?:\\.|[^"\\])*)"/g;
        let match;
        while ((match = re.exec(inner))) {
          let edgeStr = '';
          try { edgeStr = JSON.parse(match[0]); } catch (e) { edgeStr = match[1]; }
          const firstWord = String(edgeStr).trim().split(/\s+/)[0] || '';
          for (let i = 0; i < firstWord.length; i++) {
            const ch = firstWord[i];
            if (/[a-zA-Z0-9]/.test(ch)) used.add(ch);
          }
        }
      }
      return used;
    }

    function prepareEdgeEndpointsFast(text, fromPoint, toPoint) {
      if (!fromPoint.entry || !toPoint.entry) return null;
      if (fromPoint.rowIndex === toPoint.rowIndex && fromPoint.colIndex === toPoint.colIndex) {
        return { error: '起点与终点不能使用同一 node 锚点' };
      }
      const used = collectUsedNodeIdsFromTextFast(text, [fromPoint, toPoint]);
      let fromNode = getNodeAtColumn(fromPoint.entry.signal, fromPoint.colIndex);
      let toNode = getNodeAtColumn(toPoint.entry.signal, toPoint.colIndex);
      if (!fromNode) {
        fromNode = allocateNodeId(used);
        if (!fromNode) return { error: 'cannot allocate from-node id (a-zA-Z0-9 only)' };
        used.add(fromNode);
      }
      if (!toNode) {
        toNode = allocateNodeId(used);
        if (!toNode) return { error: 'cannot allocate to-node id (a-zA-Z0-9 only)' };
      }
      if (fromNode === toNode) return { error: '起点与终点不能使用同一 node 锚点' };
      let updates;
      if (fromPoint.rowIndex === toPoint.rowIndex) {
        let updated = ensureNodeCharAtColumn(fromPoint.entry.signal, fromPoint.colIndex, fromNode);
        updated = ensureNodeCharAtColumn(updated, toPoint.colIndex, toNode);
        updates = [{ rowIndex: fromPoint.rowIndex, signal: updated }];
      } else {
        updates = [
          { rowIndex: fromPoint.rowIndex, signal: ensureNodeCharAtColumn(fromPoint.entry.signal, fromPoint.colIndex, fromNode) },
          { rowIndex: toPoint.rowIndex, signal: ensureNodeCharAtColumn(toPoint.entry.signal, toPoint.colIndex, toNode) }
        ];
      }
      return { fromNode, toNode, updates };
    }
    function allocateNodeId(used) {
      for (let i = 0; i < NODE_ID_POOL.length; i++) {
        const ch = NODE_ID_POOL[i];
        if (!used.has(ch)) return ch;
      }
      return null;
    }

    function applySignalUpdatesInText(text, updates, sourceMap) {
      if (!updates.length) return text;
      const latestByRow = new Map();
      updates.forEach((update) => latestByRow.set(update.rowIndex, update.signal));
      const map = sourceMap || buildSignalSourceMap(text);
      const replacements = [...latestByRow.entries()]
        .map(([rowIndex, signal]) => {
          const entry = map[rowIndex];
          if (!entry) return null;
          const indent = getIndentAt(text, entry.start);
          return {
            start: entry.start,
            end: entry.end,
            value: formatSignalObjectPreservingFields(signal, indent)
          };
        })
        .filter(Boolean)
        .sort((a, b) => a.start - b.start);
      if (!replacements.length) return text;
      let out = '';
      let last = 0;
      replacements.forEach((item) => {
        out += text.slice(last, item.start) + item.value;
        last = item.end;
      });
      return out + text.slice(last);
    }

    function hasNonWhitespaceBetween(text, start, end) {
      for (let i = start; i < end; i++) {
        if (/\S/.test(text[i])) return true;
      }
      return false;
    }

    function resolveConnectionEndpoints() {
      if (connectionFromPoint && connectionToPoint) {
        return { from: connectionFromPoint, to: connectionToPoint };
      }
      return null;
    }

    function prepareEdgeEndpoints(parsed, fromPoint, toPoint, sourceMap) {
      if (fromPoint.rowIndex === toPoint.rowIndex && fromPoint.colIndex === toPoint.colIndex) {
        return { error: '起点与终点不能使用同一 node 锚点' };
      }

      const map = sourceMap || buildSignalSourceMap(editor.value);
      const fromEntry = map[fromPoint.rowIndex];
      const toEntry = map[toPoint.rowIndex];
      if (!fromEntry || !toEntry) {
        return { error: '起点与终点不能使用同一 node 锚点' };
      }

      const used = collectUsedNodeIds(parsed);
      let fromNode = getNodeAtColumn(fromEntry.signal, fromPoint.colIndex);
      let toNode = getNodeAtColumn(toEntry.signal, toPoint.colIndex);

      if (!fromNode) {
        fromNode = allocateNodeId(used);
        if (!fromNode) return { error: 'cannot allocate from-node id (a-zA-Z0-9 only)' };
        used.add(fromNode);
      }
      if (!toNode) {
        toNode = allocateNodeId(used);
        if (!toNode) return { error: 'cannot allocate to-node id (a-zA-Z0-9 only)' };
      }

      if (fromNode === toNode) {
        return { error: '起点与终点不能使用同一 node 锚点' };
      }

      let updates;
      if (fromPoint.rowIndex === toPoint.rowIndex) {
        let updated = ensureNodeCharAtColumn(fromEntry.signal, fromPoint.colIndex, fromNode);
        updated = ensureNodeCharAtColumn(updated, toPoint.colIndex, toNode);
        updates = [{ rowIndex: fromPoint.rowIndex, signal: updated }];
      } else {
        updates = [
          { rowIndex: fromPoint.rowIndex, signal: ensureNodeCharAtColumn(fromEntry.signal, fromPoint.colIndex, fromNode) },
          { rowIndex: toPoint.rowIndex, signal: ensureNodeCharAtColumn(toEntry.signal, toPoint.colIndex, toNode) }
        ];
      }

      return { fromNode, toNode, updates };
    }

    function parseEdgeString(edgeStr) {
      const trimmed = String(edgeStr).trim();
      const spaceIdx = trimmed.indexOf(' ');
      const firstWord = spaceIdx >= 0 ? trimmed.slice(0, spaceIdx) : trimmed;
      let label = '';
      if (spaceIdx >= 0) {
        const rest = trimmed.slice(spaceIdx + 1).trim();
        label = rest.replace(/^:\s*/, '');
      }

      const nodeIds = [];
      for (let i = 0; i < firstWord.length; i++) {
        if (/[a-zA-Z0-9]/.test(firstWord[i])) nodeIds.push(firstWord[i]);
      }

      if (nodeIds.length < 2) {
        return {
          from: nodeIds[0] || '',
          to: nodeIds[nodeIds.length - 1] || '',
          prefix: '',
          arrow: firstWord,
          label,
          firstWord
        };
      }

      const from = nodeIds[0];
      const to = nodeIds[nodeIds.length - 1];
      const fromIdx = firstWord.indexOf(from);
      const toIdx = firstWord.lastIndexOf(to);
      const prefix = firstWord.slice(0, fromIdx);
      const arrow = firstWord.slice(fromIdx + from.length, toIdx);
      return { from, to, prefix, arrow, label, firstWord };
    }

    function formatEdgeFromParts(from, to, prefix, arrow, label) {
      let result = prefix + from + arrow + to;
      const trimmedLabel = (label || '').trim();
      if (trimmedLabel) result += ' ' + trimmedLabel;
      return result;
    }

    function buildEdgeFromTemplate(template, fromNode, toNode, label) {
      const trimmedLabel = (label || '').trim();
      let result = template
        .replace(/\{from\}/g, fromNode)
        .replace(/\{to\}/g, toNode);
      if (trimmedLabel) {
        result = result.replace(/\{label\}/g, trimmedLabel);
      } else {
        result = result.replace(/\s*(?::\s*)?\{label\}\s*$/, '').trim();
      }
      return result;
    }

    function getConnectionLabelInputValue() {
      const input = document.getElementById('connection-label-input');
      return input ? input.value.trim() : '';
    }

    function updateEdgeLabelEditUI() {
      const titleEl = document.getElementById('connection-label-edit-title');
      const hintEl = document.getElementById('connection-label-edit-hint');
      const input = document.getElementById('connection-label-input');
      if (!input) return;

      if (selectedEdgeIndex >= 0) {
        if (titleEl) titleEl.textContent = '已选连接的标签';
        if (hintEl) hintEl.textContent = '修改箭头、线型或标签会立即更新当前连接';
        try {
          const parsed = JSON.parse(editor.value);
          const edges = parsed.edge || [];
          if (selectedEdgeIndex < edges.length) {
            input.value = parseEdgeString(edges[selectedEdgeIndex]).label;
            const presentation = getEdgePresentation(edges[selectedEdgeIndex], parsed, selectedEdgeIndex);
            connectionArrowStyle = presentation.arrowStyle;
            connectionLineStyle = presentation.lineStyle;
          }
        } catch (e) { /* ignore */ }
      } else {
        if (titleEl) titleEl.textContent = '连接标签';
        if (hintEl) hintEl.textContent = connectionAddSessionActive
          ? '标签将在选择连接线样式并生成时使用'
          : '先点击“新增连接”或进入“选择连接线”模式';
      }
      updateConnectionPropertiesUI();
    }

    function findEdgeIndexByNodes(from, to, edges) {
      for (let i = 0; i < edges.length; i++) {
        const parsed = parseEdgeString(edges[i]);
        if (parsed.from === from && parsed.to === to) return i;
      }
      return -1;
    }

    function findEdgePositionInText(text, index) {
      const { bounds, edges } = parseEdgeArraySlice(text);
      if (!bounds || index < 0 || index >= edges.length) return null;

      const target = edges[index];
      const edgeJson = JSON.stringify(target);
      const inner = text.slice(bounds.arrStart, bounds.arrEnd);

      let occurrence = 0;
      for (let i = 0; i < index; i++) {
        if (edges[i] === target) occurrence++;
      }

      let pos = 0;
      while (pos < inner.length) {
        const idx = inner.indexOf(edgeJson, pos);
        if (idx < 0) break;
        if (occurrence === 0) {
          return {
            bounds,
            absStart: bounds.arrStart + idx,
            absEnd: bounds.arrStart + idx + edgeJson.length,
            edgeStr: target
          };
        }
        occurrence--;
        pos = idx + edgeJson.length;
      }
      return null;
    }

    function replaceEdgeAtIndex(text, index, newEdgeStr) {
      const pos = findEdgePositionInText(text, index);
      if (!pos) return text;
      const newEdgeJson = JSON.stringify(newEdgeStr);
      return text.slice(0, pos.absStart) + newEdgeJson + text.slice(pos.absEnd);
    }

    function selectEdge(index) {
      selectedEdgeIndex = index;
      updateEdgeLabelEditUI();
      renderConnectionEdgeList();
      updateConnectionPresetDisabledState();
      highlightSelectedEdgeInSvg();
      if (index >= 0) {
        try {
          const edges = JSON.parse(editor.value).edge || [];
          if (index < edges.length) {
            setStatus(true, '已选中连接: ' + edges[index]);
            vwdDebugLog('connection', { phase: 'edge-selected', index, edge: edges[index] });
          }
        } catch (e) { /* ignore */ }
      }
      updateConnectionPointStatusUI();
      updateLegendAvailability();
    }

    function clearEdgeSelection() {
      selectedEdgeIndex = -1;
      renderConnectionEdgeList();
      updateEdgeLabelEditUI();
      updateConnectionPresetDisabledState();
      highlightSelectedEdgeInSvg();
      updateLegendAvailability();
    }

    function clearEdgeSelectionBlink(svg) {
      if (!svg) return;
      svg.querySelectorAll('.wave-edge-label-blink').forEach((el) => {
        el.classList.remove('wave-edge-label-blink');
      });
      svg.querySelectorAll('.wave-edge-blink').forEach((el) => {
        el.classList.remove('wave-edge-blink');
      });
    }

    function textDistanceToGmark(textEl, gmark) {
      try {
        const tb = textEl.getBBox();
        const gb = gmark.getBBox();
        const tx = tb.x + tb.width / 2;
        const ty = tb.y + tb.height / 2;
        const gx = gb.x + gb.width / 2;
        const gy = gb.y + gb.height / 2;
        const dx = tx - gx;
        const dy = ty - gy;
        return Math.sqrt(dx * dx + dy * dy);
      } catch (e) {
        return Infinity;
      }
    }

    function findEdgeLabelTextElements(svg, gmark, label) {
      const trimmed = String(label || '').trim();
      if (!trimmed) return [];

      const candidates = [...svg.querySelectorAll('text')].filter((el) => {
        if (el.classList.contains('wave-headfoot-text')) return false;
        if (el.classList.contains('info')) return false;
        return el.textContent.trim() === trimmed;
      });

      if (candidates.length === 0) return [];

      if (gmark && candidates.length > 1) {
        candidates.sort((a, b) => textDistanceToGmark(a, gmark) - textDistanceToGmark(b, gmark));
      }

      return [candidates[0]];
    }

    function applyEdgeSelectionBlink(svg, gmark, label) {
      clearEdgeSelectionBlink(svg);
      if (!gmark) return;

      const labelEls = findEdgeLabelTextElements(svg, gmark, label);
      if (labelEls.length > 0) {
        labelEls.forEach((el) => el.classList.add('wave-edge-label-blink'));
        return;
      }

      gmark.classList.add('wave-edge-blink');
    }

    function highlightSelectedEdgeInSvg() {
      const svg = waveContainer.querySelector('svg');
      if (!svg) return;

      svg.querySelectorAll('.wave-edge-selected').forEach((el) => {
        el.classList.remove('wave-edge-selected');
      });
      clearEdgeSelectionBlink(svg);

      if (selectedEdgeIndex < 0) return;

      let parsed;
      try {
        parsed = JSON.parse(editor.value);
      } catch (e) {
        return;
      }

      const edges = parsed.edge || [];
      if (selectedEdgeIndex >= edges.length) return;

      const edgeParsed = parseEdgeString(edges[selectedEdgeIndex]);
      const { from, to, label } = edgeParsed;
      if (!from || !to) return;

      const gmark = svg.querySelector('#gmark_' + from + '_' + to);
      if (gmark) {
        gmark.classList.add('wave-edge-selected');
        applyEdgeSelectionBlink(svg, gmark, label);
      }
    }

    function modifyEdgeAtIndex(index, newEdgeStr, lineStyle, arrowStyle) {
      let parsed;
      try {
        parsed = JSON.parse(editor.value);
      } catch (e) {
        setStatus(false, 'JSON 错误，无法修改连接');
        return false;
      }

      const edges = parsed.edge || [];
      if (index < 0 || index >= edges.length) return false;

      const text = editor.value;
      const edgeTextChanged = newEdgeStr !== edges[index];
      let newText = edgeTextChanged ? replaceEdgeAtIndex(text, index, newEdgeStr) : text;
      if (edgeTextChanged && newText === text) {
        setStatus(false, 'JSON 错误，无法修改连接');
        return false;
      }

      try {
        const updated = JSON.parse(newText);
        if (lineStyle || arrowStyle) {
          setEdgeLineStyleOption(updated, index, lineStyle || connectionLineStyle, arrowStyle || connectionArrowStyle);
        }
        newText = JSON.stringify(updated, null, 2);
      } catch (e) {
        setStatus(false, '连接修改后 JSON 校验失败');
        return false;
      }

      pushUndoBeforeChange();
      const pos = findEdgePositionInText(newText, index);
      if (!pos) {
        setStatus(false, 'JSON 错误，无法修改连接');
        return false;
      }
      applyEditorChange(newText, pos.absStart, pos.absEnd);
      scrollEditorToEdge(newText, newEdgeStr);
      vwdDebugLog('connection', {
        phase: 'edge-modified',
        index,
        edge: newEdgeStr,
        lineStyle: lineStyle || null,
        arrowStyle: arrowStyle || null
      });
      return true;
    }

    function modifySelectedEdgeProperties() {
      if (selectedEdgeIndex < 0) return false;

      let parsed;
      try {
        parsed = JSON.parse(editor.value);
      } catch (e) {
        setStatus(false, 'JSON 错误，无法修改连接');
        return false;
      }

      const edges = parsed.edge || [];
      if (selectedEdgeIndex >= edges.length) return false;

      const current = parseEdgeString(edges[selectedEdgeIndex]);
      const newEdgeStr = formatEdgeFromParts(
        current.from,
        current.to,
        current.prefix,
        getConnectionArrowToken(connectionArrowStyle, connectionLineStyle),
        current.label
      );

      const currentPresentation = getEdgePresentation(edges[selectedEdgeIndex], parsed, selectedEdgeIndex);
      if (newEdgeStr === edges[selectedEdgeIndex]
          && currentPresentation.lineStyle === connectionLineStyle
          && currentPresentation.arrowStyle === connectionArrowStyle) {
        updateConnectionPropertiesUI();
        return true;
      }

      if (modifyEdgeAtIndex(selectedEdgeIndex, newEdgeStr, connectionLineStyle, connectionArrowStyle)) {
        setStatus(true, '已修改连接样式: ' + newEdgeStr);
        updateEdgeLabelEditUI();
        return true;
      }
      return false;
    }

    function applyEdgeLabelFromInput() {
      const label = getConnectionLabelInputValue();

      if (selectedEdgeIndex >= 0) {
        let parsed;
        try {
          parsed = JSON.parse(editor.value);
        } catch (e) {
          setStatus(false, '请先在波形上选择起点与终点');
          return;
        }

        const edges = parsed.edge || [];
        if (selectedEdgeIndex >= edges.length) return;

        const current = parseEdgeString(edges[selectedEdgeIndex]);
        const newEdgeStr = formatEdgeFromParts(
          current.from, current.to, current.prefix, current.arrow, label
        );

        if (newEdgeStr === edges[selectedEdgeIndex]) {
          setStatus(true, '连接标签未变化');
          return;
        }

        if (modifyEdgeAtIndex(selectedEdgeIndex, newEdgeStr, connectionLineStyle, connectionArrowStyle)) {
          setStatus(true, label ? ('已更新连接标签: ' + label) : '已清除连接标签');
          updateEdgeLabelEditUI();
        }
        return;
      }

      setStatus(true, label ? ('新连接将使用标签: ' + label) : '新连接将不带标签');
    }

    function handleConnectionArrowStyleClick(arrowStyle) {
      if (!CONNECTION_ARROW_STYLES.includes(arrowStyle)) return;
      if (!connectionAddSessionActive && selectedEdgeIndex < 0) {
        setStatus(false, '请先新增连接或选择一条连接线');
        return;
      }
      connectionArrowStyle = arrowStyle;
      pendingEdgeTemplate = buildConnectionTemplate(connectionArrowStyle, connectionLineStyle);
      if (selectedEdgeIndex >= 0) modifySelectedEdgeProperties();
      else updateConnectionPropertiesUI();
      vwdDebugLog('connection', { phase: 'arrow-style', arrowStyle, selectedEdgeIndex });
    }

    function handleConnectionLineStyleClick(lineStyle) {
      if (!CONNECTION_LINE_STYLES.includes(lineStyle)) return;
      connectionLineStyle = lineStyle;
      const template = buildConnectionTemplate(connectionArrowStyle, connectionLineStyle);
      pendingEdgeTemplate = template;
      if (areConnectionPresetsEnabledForInsert()) {
        if (isInsertingEdge) return;
        updateConnectionPresetSelection();
        insertEdgeFromTemplate(template, lineStyle);
        return;
      }
      if (selectedEdgeIndex >= 0) {
        modifySelectedEdgeProperties();
        return;
      }
      if (isInsertingEdge) return;
      if (!connectionAddSessionActive) {
        setStatus(false, '请先点击“新增连接”或“选择连接线”');
      } else if (!connectionFromPoint) {
        setStatus(false, '请先选择连接起点');
      } else if (!connectionToPoint) {
        setStatus(false, '请继续选择连接终点');
      }
    }

    function beginEdgeAddSession() {
      exitWavePaintMode('connection-add');
      if (isInsertingEdge) return;
      endConnectionAddSession();
      connectionSelectActive = false;
      app.classList.remove('connection-select-mode');
      clearEdgeSelection();
      connectionAddSessionActive = true;
      connectionArrowStyle = 'end';
      connectionLineStyle = 'straight';
      pendingEdgeTemplate = buildConnectionTemplate(connectionArrowStyle, connectionLineStyle);
      const labelInput = document.getElementById('connection-label-input');
      if (labelInput) labelInput.value = '';
      setConnectionPickActive(true);
      updateEdgeLabelEditUI();
      updateConnectionPointStatusUI();
      updateConnectionPresetDisabledState();
      setStatus(true, '新增连接：请依次点击起点与终点');
      vwdDebugLog('connection', { phase: 'add-mode', active: true });
    }

    function beginEdgeSelectSession() {
      exitWavePaintMode('connection-select');
      if (isInsertingEdge) return;
      endConnectionAddSession();
      connectionSelectActive = true;
      app.classList.add('connection-select-mode');
      clearEdgeSelection();
      updateConnectionPointStatusUI();
      updateConnectionPropertiesUI();
      setStatus(true, '选择连接线：请点击波形图中的连接线');
      vwdDebugLog('connection', { phase: 'select-mode', active: true });
    }

    function scrollEditorToEdge(text, edgeStr) {
      if (app.classList.contains('reading-mode')) return;
      const edgeJson = JSON.stringify(edgeStr);
      const idx = text.indexOf(edgeJson);
      if (idx < 0) return;
      editor.focus();
      editor.selectionStart = idx;
      editor.selectionEnd = idx + edgeJson.length;
      const before = text.slice(0, idx);
      const line = before.split('\n').length;
      const lineHeight = 13 * 1.6;
      editor.scrollTop = Math.max(0, (line - 3) * lineHeight);
      syncLineNumberScroll();
    }

    function scheduleDeferredEdgeRender(jsonText) {
      clearTimeout(deferredEdgeRenderTimer);
      deferredEdgeRenderTimer = setTimeout(() => {
        deferredEdgeRenderTimer = null;
        if (editor.value !== jsonText) return;
        const statusBeforeRender = statusText.textContent;
        scheduleRenderWaveform(jsonText, (ok) => {
          if (ok) vwdMark('commitEdgeInsert:deferredRenderDone');
          if (statusBeforeRender && statusBeforeRender.includes('Add Connection')) {
            setStatus(true, statusBeforeRender);
          }
        });
      }, 220);
    }

    function getLaneCenterSvgY(svg, lane) {
      if (!svg || !lane || !lane.getScreenCTM || !svg.getScreenCTM) return null;
      let localY = null;
      const hoverRect = lane.querySelector('rect.lane-hover-bg');
      if (hoverRect) {
        const y = parseFloat(hoverRect.getAttribute('y'));
        const height = parseFloat(hoverRect.getAttribute('height'));
        if (Number.isFinite(y) && Number.isFinite(height)) localY = y + height / 2;
      }
      if (!Number.isFinite(localY)) {
        try {
          const bbox = lane.getBBox();
          localY = bbox.y + bbox.height / 2;
        } catch (e) {
          return null;
        }
      }
      const lanePoint = svg.createSVGPoint();
      lanePoint.x = 0;
      lanePoint.y = localY;
      const screenPoint = lanePoint.matrixTransform(lane.getScreenCTM());
      return screenPoint.matrixTransform(svg.getScreenCTM().inverse()).y;
    }

    function getOptimisticEdgePoint(point, sourceMap) {
      const svg = waveContainer.querySelector('svg');
      if (!svg || !point) return null;
      const lane = getWaveLaneGroups(svg)[point.rowIndex];
      if (!lane) return null;
      const laneCenterY = getLaneCenterSvgY(svg, lane);
      if (Number.isFinite(point.svgX) && Number.isFinite(point.svgY)) {
        return {
          x: point.svgX,
          y: Number.isFinite(laneCenterY) ? laneCenterY : point.svgY
        };
      }
      const drawGroup = lane.querySelector('[id^="wavelane_draw_"]');
      const coordinateGroup = drawGroup || lane;
      if (!coordinateGroup.getCTM) return null;

      const signal = sourceMap && sourceMap[point.rowIndex] && sourceMap[point.rowIndex].signal;
      const wave = signal ? (signal.wave || '') : '';
      const unitWidth = getWaveUnitWidth(editor.value);
      const x = drawGroup
        ? getBoundaryXForColumn(drawGroup, wave, point.colIndex, unitWidth, getConnectionPickBoundaryIndex(sourceMap))
        : point.colIndex * getWaveColumnWidth(unitWidth);

      let y = 10;
      try {
        const bbox = coordinateGroup.getBBox();
        y = bbox.y + bbox.height / 2;
      } catch (e) { /* keep fallback */ }

      const svgPoint = svg.createSVGPoint();
      svgPoint.x = x;
      svgPoint.y = y;
      const resolved = svgPoint.matrixTransform(coordinateGroup.getCTM());
      return {
        x: resolved.x,
        y: Number.isFinite(laneCenterY) ? laneCenterY : resolved.y
      };
    }

    function buildOptimisticEdgePath(edgeStr, fromPt, toPt) {
      const parsed = parseEdgeString(edgeStr);
      const dx = toPt.x - fromPt.x;
      const dy = toPt.y - fromPt.y;
      if (parsed.arrow.includes('~')) {
        return 'M ' + fromPt.x + ',' + fromPt.y
          + ' c ' + (0.7 * dx) + ',0 ' + (0.3 * dx) + ',' + dy + ' ' + dx + ',' + dy;
      }
      if (parsed.arrow.includes('|')) {
        return 'm ' + fromPt.x + ',' + fromPt.y + ' ' + dx + ',0 0,' + dy;
      }
      return 'M ' + fromPt.x + ',' + fromPt.y + ' ' + toPt.x + ',' + toPt.y;
    }

    function optimisticEdgeStyle(edgeStr, lineStyle, arrowStyle) {
      const parsed = parseEdgeString(edgeStr);
      const parts = ['stroke:#0041c4', 'stroke-width:1', 'fill:none'];
      const effectiveArrow = arrowStyle || (parsed.arrow.includes('<') ? 'both' : 'end');
      if (effectiveArrow === 'end' || effectiveArrow === 'both') parts.push('marker-end:url(#arrowhead)');
      if (effectiveArrow === 'start' || effectiveArrow === 'both') parts.push('marker-start:url(#arrowtail)');
      if (lineStyle === 'dashed') parts.push('stroke-dasharray:6 4');
      if (parsed.arrow === '+') parts.push('marker-end:url(#tee)', 'marker-start:url(#tee)', 'stroke:#00F');
      return parts.join(';');
    }

    function appendOptimisticEdge(edgeStr, fromPoint, toPoint, edgeIndex, sourceMap, lineStyle, arrowStyle) {
      const svg = waveContainer.querySelector('svg');
      if (!svg) return;
      const fromSvg = getOptimisticEdgePoint(fromPoint, sourceMap);
      const toSvg = getOptimisticEdgePoint(toPoint, sourceMap);
      if (!fromSvg || !toSvg) return;
      if (fromPoint.rowIndex === toPoint.rowIndex) {
        const sharedY = (fromSvg.y + toSvg.y) / 2;
        fromSvg.y = sharedY;
        toSvg.y = sharedY;
      }

      let arcGroup = svg.querySelector('#vwd-optimistic-edges');
      if (!arcGroup) {
        arcGroup = document.createElementNS('http://www.w3.org/2000/svg', 'g');
        arcGroup.setAttribute('id', 'vwd-optimistic-edges');
        svg.appendChild(arcGroup);
      }

      const parsed = parseEdgeString(edgeStr);
      const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
      path.setAttribute('id', 'gmark_' + parsed.from + '_' + parsed.to);
      path.setAttribute('d', buildOptimisticEdgePath(edgeStr, fromSvg, toSvg));
      path.setAttribute('style', optimisticEdgeStyle(edgeStr, lineStyle, arrowStyle));
      path.classList.add('wave-edge-interactive');
      path.dataset.vwdEdgeBound = '1';
      path.addEventListener('click', (e) => selectEdgeFromWaveform(edgeIndex, edgeStr, e));
      arcGroup.appendChild(path);
      ensureEdgeHitTarget(path, edgeIndex, edgeStr);

      if (parsed.label) {
        const label = document.createElementNS('http://www.w3.org/2000/svg', 'text');
        label.setAttribute('x', (fromSvg.x + toSvg.x) / 2);
        label.setAttribute('y', (fromSvg.y + toSvg.y) / 2 - 4);
        label.setAttribute('text-anchor', 'middle');
        label.setAttribute('class', 'info');
        label.textContent = parsed.label;
        arcGroup.appendChild(label);
      }
    }

    function commitEdgeInsert(template, lineStyle) {
      if (isInsertingEdge) return;

      const endpoints = resolveConnectionEndpoints();
      if (!endpoints) return;

      isInsertingEdge = true;
      setStatus(true, '正在插入连接…');
      vwdMark('commitEdgeInsert:start');

      requestAnimationFrame(() => {
        vwdMark('commitEdgeInsert:raf');
        const fromPickFlow = connectionAddSessionActive && connectionPickActive;
        let statusMsg = '';
        let deferCompletion = false;

        try {
          let text = editor.value;
          const sourceMap = buildSignalSourceMap(text);
          const currentFromPoint = Object.assign({}, endpoints.from, {
            entry: sourceMap[endpoints.from.rowIndex]
          });
          const currentToPoint = Object.assign({}, endpoints.to, {
            entry: sourceMap[endpoints.to.rowIndex]
          });
          const prepared = prepareEdgeEndpointsFast(text, currentFromPoint, currentToPoint) || (() => {
            let parsed;
            try { parsed = JSON.parse(text); } catch (e) { return { error: 'JSON parse failed' }; }
            return prepareEdgeEndpoints(parsed, endpoints.from, endpoints.to, sourceMap);
          })();
          if (prepared.error) {
            setStatus(false, prepared.error);
            return;
          }

          const insertLabel = selectedEdgeIndex < 0 ? getConnectionLabelInputValue() : '';
          const edgeStr = buildEdgeFromTemplate(template, prepared.fromNode, prepared.toNode, insertLabel);
          text = applySignalUpdatesInText(text, prepared.updates, sourceMap);

          const ensured = ensureEdgeArrayInText(text);
          if (!ensured) {
            setStatus(false, '未找到 signal 数组，无法插入 edge');
            return;
          }
          text = ensured.text;
          const bounds = ensured.bounds;

          if (text.length <= 500000) pushUndoBeforeChange();
          const indent = getIndentAt(text, bounds.arrStart) || '  ';
          const itemIndent = indent + '  ';
          const edgeJson = JSON.stringify(edgeStr);
          const needsComma = hasNonWhitespaceBetween(text, bounds.arrStart, bounds.insertBefore);
          const insertion = (needsComma ? ',\n' : '\n') + itemIndent + edgeJson;
          const insertPos = bounds.insertBefore;
          let newText = text.slice(0, insertPos) + insertion + text.slice(insertPos);
          let updatedSource = JSON.parse(newText);
          const newEdgeIndex = Math.max(0, (updatedSource.edge || []).length - 1);
          setEdgeLineStyleOption(
            updatedSource,
            newEdgeIndex,
            lineStyle || connectionLineStyle,
            connectionArrowStyle
          );
          newText = JSON.stringify(updatedSource, null, 2);
          const newEdgePos = findEdgePositionInText(newText, newEdgeIndex);
          if (!newEdgePos) {
            setStatus(false, '连接写入失败：无法定位新连接');
            return;
          }
          const selStart = newEdgePos.absStart;
          const selEnd = newEdgePos.absEnd;
          statusMsg = '已插入连接: ' + edgeStr + '（node ' + prepared.fromNode + ' → ' + prepared.toNode + '）';

          try {
            JSON.parse(newText);
          } catch (error) {
            vwdDebugLog('connection', { phase: 'insert-validation-error', message: error && error.message ? error.message : String(error) });
            setStatus(false, '连接写入失败：JSON 校验未通过');
            return;
          }

          vwdMark('commitEdgeInsert:beforeApply');
          deferCompletion = true;

          applyEdgeInsertTextFast(newText, selStart, selEnd, fromPickFlow);

          appendOptimisticEdge(
            edgeStr,
            endpoints.from,
            endpoints.to,
            newEdgeIndex,
            sourceMap,
            lineStyle || connectionLineStyle,
            connectionArrowStyle
          );
          renderConnectionEdgeList();
          vwdMark('commitEdgeInsert:optimisticEdge');

          if (fromPickFlow) {
            finishConnectionAddSessionFast();
          } else {
            requestAnimationFrame(() => scrollEditorToEdge(newText, edgeStr));
          }

          setStatus(true, statusMsg);
          vwdDebugLog('connection', {
            phase: 'inserted',
            edgeIndex: newEdgeIndex,
            edge: edgeStr,
            arrowStyle: connectionArrowStyle,
            lineStyle: lineStyle || connectionLineStyle,
            from: endpoints.from,
            to: endpoints.to
          });
          setWaveformRenderingBusy(false);
          isInsertingEdge = false;
          // 新增连接时避免立即完整重绘大波形；现有 SVG 已追加轻量链路。 JSON 和列表已同步。
          clearTimeout(deferredEdgeRenderTimer);
          deferredEdgeRenderTimer = null;
        } catch (e) {
          const message = e && e.message ? e.message : String(e);
          vwdDebugLog('connection', { phase: 'insert-error', message, stack: e && e.stack ? String(e.stack) : '' });
          setStatus(false, '连接生成失败: ' + message);
        } finally {
          if (!deferCompletion) {
            isInsertingEdge = false;
          }
        }
      });
    }

    function insertEdgeFromTemplate(template, lineStyle) {
      if (isInsertingEdge) return;

      const endpoints = resolveConnectionEndpoints();
      if (!endpoints) {
        if (connectionAddSessionActive) {
          setStatus(false, '请先在波形上选择起点与终点');
        }
        return;
      }

      commitEdgeInsert(template, lineStyle || connectionLineStyle);
    }

    function parseEdgeArraySlice(text) {
      const bounds = findEdgeArrayBounds(text);
      if (!bounds) return { bounds: null, edges: [] };
      try {
        const edges = JSON.parse('[' + text.slice(bounds.arrStart, bounds.arrEnd) + ']');
        return { bounds, edges: Array.isArray(edges) ? edges : [] };
      } catch (e) {
        return { bounds, edges: [] };
      }
    }

    function getNodeIdsFromEdges(edges) {
      const used = new Set();
      (edges || []).forEach((edgeStr) => {
        const edge = parseEdgeString(edgeStr);
        if (edge.from) used.add(edge.from);
        if (edge.to) used.add(edge.to);
      });
      return used;
    }

    function cleanupDeletedEdgeEndpointUpdates(parsed, removedEdge) {
      const edge = parseEdgeString(removedEdge);
      const endpoints = new Set([edge.from, edge.to].filter(Boolean));
      const remainingUsedNodes = getNodeIdsFromEdges(parsed.edge || []);
      const removableNodes = new Set([...endpoints].filter((nodeId) => !remainingUsedNodes.has(nodeId)));
      const updates = [];

      if (removableNodes.size) {
        flattenSignals(parsed.signal || []).forEach((sig, rowIndex) => {
          if (!sig.node) return;
          let changed = false;
          let node = String(sig.node).split('').map((ch) => {
            if (removableNodes.has(ch)) {
              changed = true;
              return '.';
            }
            return ch;
          }).join('');
          if (!changed) return;
          node = node.replace(/\.+$/, '');
          const updatedSignal = Object.assign({}, sig);
          if (node) updatedSignal.node = node;
          else delete updatedSignal.node;
          updates.push({ rowIndex, signal: updatedSignal });
        });
      }

      return {
        updates,
        removedNodes: [...removableNodes],
        retainedNodes: [...endpoints].filter((nodeId) => remainingUsedNodes.has(nodeId))
      };
    }

    function cleanupOrphanedNodeUpdates(parsed) {
      const used = getNodeIdsFromEdges(parsed.edge || []);
      const updates = [];
      flattenSignals(parsed.signal || []).forEach((sig, rowIndex) => {
        if (!sig.node) return;
        let node = String(sig.node);
        let changed = false;
        node = node.split('').map((ch) => {
          if (ch !== '.' && !used.has(ch)) {
            changed = true;
            return '.';
          }
          return ch;
        }).join('');
        if (!changed) return;
        node = node.replace(/\.+$/, '');
        const updatedSignal = Object.assign({}, sig);
        if (node) updatedSignal.node = node;
        else delete updatedSignal.node;
        updates.push({ rowIndex, signal: updatedSignal });
      });
      return updates;
    }

    function removeEdgeFromText(text, index) {
      const { bounds, edges } = parseEdgeArraySlice(text);
      if (!bounds || index < 0 || index >= edges.length) return text;

      const target = edges[index];
      const edgeJson = JSON.stringify(target);
      const inner = text.slice(bounds.arrStart, bounds.arrEnd);

      let occurrence = 0;
      for (let i = 0; i < index; i++) {
        if (edges[i] === target) occurrence++;
      }

      let pos = 0;
      let found = -1;
      while (pos < inner.length) {
        const idx = inner.indexOf(edgeJson, pos);
        if (idx < 0) break;
        if (occurrence === 0) {
          found = idx;
          break;
        }
        occurrence--;
        pos = idx + edgeJson.length;
      }
      if (found < 0) return text;

      const absStart = bounds.arrStart + found;
      const absEnd = absStart + edgeJson.length;
      const before = text.slice(bounds.arrStart, absStart);
      const after = text.slice(absEnd, bounds.arrEnd);

      let start = absStart;
      let end = absEnd;
      const trailingComma = after.match(/^\s*,\s*/);
      const leadingComma = before.match(/,\s*$/);
      if (trailingComma) {
        end = absEnd + trailingComma[0].length;
      } else if (leadingComma) {
        start = absStart - leadingComma[0].length;
      }
      return text.slice(0, start) + text.slice(end);
    }

    function deleteEdgeAtIndex(index) {
      let parsed;
      try {
        parsed = JSON.parse(editor.value);
      } catch (e) {
        setStatus(false, '未找到要删除的连接');
        return;
      }

      const edges = parsed.edge || [];
      if (index < 0 || index >= edges.length) return;

      const removed = edges[index];
      const wasSelected = selectedEdgeIndex === index;
      let text = removeEdgeFromText(editor.value, index);
      if (text === editor.value) {
        setStatus(false, '未找到要删除的连接');
        return;
      }

      parsed.edge = edges.filter((_, i) => i !== index);
      if (Array.isArray(parsed.edgeOptions)) {
        parsed.edgeOptions.splice(index, 1);
        while (parsed.edgeOptions.length && !parsed.edgeOptions[parsed.edgeOptions.length - 1]) {
          parsed.edgeOptions.pop();
        }
        if (!parsed.edgeOptions.some(Boolean)) delete parsed.edgeOptions;
      }
      const endpointCleanup = cleanupDeletedEdgeEndpointUpdates(parsed, removed);
      if (endpointCleanup.updates.length) {
        text = applySignalUpdatesInText(text, endpointCleanup.updates);
      }

      try {
        const normalized = JSON.parse(text);
        if (parsed.edgeOptions) normalized.edgeOptions = parsed.edgeOptions;
        else delete normalized.edgeOptions;
        text = JSON.stringify(normalized, null, 2);
      } catch (e) {
        setStatus(false, '删除连接后 JSON 校验失败');
        return;
      }

      pushUndoBeforeChange();
      applyEditorChange(text, editor.selectionStart, editor.selectionEnd);
      if (wasSelected) {
        clearEdgeSelection();
      } else if (selectedEdgeIndex > index) {
        selectedEdgeIndex--;
        renderConnectionEdgeList();
      }
      updateLegendAvailability();
      setStatus(true, '已删除连接: ' + removed);
      vwdDebugLog('connection', {
        phase: 'edge-deleted',
        index,
        edge: removed,
        removedNodes: endpointCleanup.removedNodes,
        retainedNodes: endpointCleanup.retainedNodes
      });
    }

    function renderConnectionEdgeList(parsedSource) {
      const list = document.getElementById('connection-edge-list');
      if (!list) return;
      list.innerHTML = '';

      let parsed = parsedSource;
      try {
        if (!parsed) parsed = JSON.parse(editor.value);
      } catch (e) {
        const empty = document.createElement('div');
        empty.className = 'connection-edge-empty';
        empty.textContent = '暂无连接';
        list.appendChild(empty);
        updateConnectionPresetSelection();
        return;
      }

      const edges = parsed.edge || [];
      if (selectedEdgeIndex >= edges.length) {
        selectedEdgeIndex = -1;
        updateEdgeLabelEditUI();
      }
      if (!edges.length) {
        const empty = document.createElement('div');
        empty.className = 'connection-edge-empty';
        empty.textContent = '暂无连接';
        list.appendChild(empty);
        if (selectedEdgeIndex >= 0) {
          selectedEdgeIndex = -1;
          updateEdgeLabelEditUI();
          highlightSelectedEdgeInSvg();
        }
        updateConnectionPresetSelection();
        return;
      }

      const focusConnectionLabelTextBox = () => {
        const input = document.getElementById('connection-label-input');
        if (!input || input.disabled) return false;
        input.focus();
        input.select();
        return true;
      };

      edges.forEach((edgeStr, index) => {
        const row = document.createElement('div');
        row.className = 'connection-edge-row';
        if (index === selectedEdgeIndex) row.classList.add('selected');

        const textEl = document.createElement('div');
        textEl.className = 'connection-edge-text';
        textEl.textContent = edgeStr;
        textEl.title = '点击进入选择连接线模式并显示属性';

        row.addEventListener('click', (e) => {
          if (e.target.closest('.connection-edge-delete')) return;
          if (!connectionSelectActive) beginEdgeSelectSession();
          selectEdge(index);
          scrollEditorToEdge(editor.value, edgeStr);
          if (isTextEditModeActive() && e.target.closest('.connection-edge-text')) {
            focusConnectionLabelTextBox();
          }
        });

        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'connection-edge-delete';
        btn.title = '删除此连接';
        btn.textContent = '删';
        btn.addEventListener('click', (e) => {
          e.stopPropagation();
          deleteEdgeAtIndex(index);
        });

        row.appendChild(textEl);
        row.appendChild(btn);
        list.appendChild(row);
      });
      highlightSelectedEdgeInSvg();
      updateConnectionPresetSelection();
    }

    function selectEdgeFromWaveform(index, edgeStr, event) {
      if (inlineEditActive || app.classList.contains('reading-mode')) return;
      const clickedText = !!(event
        && event.target
        && typeof event.target.closest === 'function'
        && event.target.closest('text'));
      const editLabel = isTextEditModeActive() && clickedText;
      if (!connectionSelectActive && !editLabel) return;
      if (!connectionSelectActive) beginEdgeSelectSession();
      if (event) event.stopPropagation();
      selectEdge(index);
      scrollEditorToEdge(editor.value, edgeStr);
      if (editLabel) {
        const input = document.getElementById('connection-label-input');
        if (input && !input.disabled) {
          input.focus();
          input.select();
        }
      }
    }

    function applyEdgeLineVisual(edgeElement, presentation) {
      const targets = edgeElement.matches && edgeElement.matches('path, line, polyline')
        ? [edgeElement]
        : [...edgeElement.querySelectorAll('path, line, polyline')];
      targets.forEach((target) => {
        target.style.strokeDasharray = presentation.lineStyle === 'dashed' ? '6 4' : '';
        target.style.markerStart = presentation.arrowStyle === 'start' || presentation.arrowStyle === 'both'
          ? 'url(#arrowtail)'
          : '';
        target.style.markerEnd = presentation.arrowStyle === 'end' || presentation.arrowStyle === 'both'
          ? 'url(#arrowhead)'
          : '';
      });
    }

    function ensureEdgeHitTarget(edgeElement, index, edgeStr) {
      if (!edgeElement || !edgeElement.parentNode || !edgeElement.cloneNode) return;
      if (!(edgeElement.matches && edgeElement.matches('path, line, polyline'))) return;
      const owner = edgeElement.id || ('edge-' + index);
      const existing = edgeElement.parentNode.querySelector('.wave-edge-hit-target[data-vwd-edge-owner="' + owner + '"]');
      if (existing) return;
      const hit = edgeElement.cloneNode(false);
      hit.removeAttribute('id');
      hit.removeAttribute('marker-start');
      hit.removeAttribute('marker-end');
      hit.setAttribute('style', 'fill:none;stroke:transparent;stroke-width:12;pointer-events:stroke');
      hit.setAttribute('class', 'wave-edge-hit-target');
      hit.dataset.vwdEdgeOwner = owner;
      hit.dataset.vwdEdgeIndex = String(index);
      hit.addEventListener('click', (event) => selectEdgeFromWaveform(index, edgeStr, event));
      edgeElement.parentNode.insertBefore(hit, edgeElement.nextSibling);
    }

    function attachEdgeLabelTextInteractivity(edgeElement, index, edgeStr, usedLabels) {
      const parsedEdge = parseEdgeString(edgeStr);
      const label = String(parsedEdge.label || '').trim();
      const parent = edgeElement && edgeElement.parentNode;
      if (!label || !parent) return;

      const candidates = Array.from(parent.children).flatMap((child) => {
        if (!child || String(child.tagName || '').toLowerCase() !== 'g') return [];
        return Array.from(child.children).filter((item) => {
          return String(item.tagName || '').toLowerCase() === 'text'
            && String(item.textContent || '').trim() === label
            && !(usedLabels && usedLabels.has(item));
        });
      });
      if (!candidates.length) return;

      let edgeCenter = null;
      try {
        const rect = edgeElement.getBoundingClientRect();
        edgeCenter = { x: rect.left + rect.width / 2, y: rect.top + rect.height / 2 };
      } catch (_e) { /* use source order fallback */ }
      const labelText = edgeCenter
        ? candidates.map((candidate) => {
            const rect = candidate.getBoundingClientRect();
            const x = rect.left + rect.width / 2;
            const y = rect.top + rect.height / 2;
            return { candidate, distance: Math.hypot(x - edgeCenter.x, y - edgeCenter.y) };
          }).sort((a, b) => a.distance - b.distance)[0].candidate
        : candidates[0];

      if (usedLabels) usedLabels.add(labelText);
      labelText.classList.add('wave-edge-label-text');
      labelText.dataset.vwdEdgeIndex = String(index);
      labelText.setAttribute('pointer-events', 'all');
      labelText.addEventListener('click', (event) => {
        if (!isTextEditModeActive() && !connectionSelectActive) return;
        event.preventDefault();
        selectEdgeFromWaveform(index, edgeStr, event);
      });
    }

    function attachEdgeInteractivity(jsonText, parsedSource) {
      const svg = waveContainer.querySelector('svg');
      if (!svg) return;

      let parsed = parsedSource;
      try {
        if (!parsed) parsed = JSON.parse(jsonText);
      } catch (e) {
        return;
      }

      const edges = parsed.edge || [];
      const usedEdgeLabelTexts = new Set();

      svg.querySelectorAll('.wave-edge-hit-target').forEach((el) => el.remove());

      svg.querySelectorAll('[id^="gmark_"]').forEach((el) => {
        const match = el.id.match(/^gmark_([a-zA-Z0-9])_([a-zA-Z0-9])/);
        if (!match) return;

        const from = match[1];
        const to = match[2];
        const idx = findEdgeIndexByNodes(from, to, edges);
        if (idx < 0) return;

        el.classList.add('wave-edge-interactive');
        const presentation = getEdgePresentation(edges[idx], parsed, idx);
        applyEdgeLineVisual(el, presentation);
        ensureEdgeHitTarget(el, idx, edges[idx]);
        attachEdgeLabelTextInteractivity(el, idx, edges[idx], usedEdgeLabelTexts);
        if (el.dataset.vwdEdgeBound === '1') return;
        el.dataset.vwdEdgeBound = '1';
        el.addEventListener('click', (e) => {
          selectEdgeFromWaveform(idx, edges[idx], e);
        });
      });

      highlightSelectedEdgeInSvg();
    }

    function scrollEditorToSignal(entry) {
      if (app.classList.contains('reading-mode')) return;
      const text = editor.value;
      editor.focus();
      editor.selectionStart = entry.start;
      editor.selectionEnd = entry.end;
      const before = text.slice(0, entry.start);
      const line = before.split('\n').length;
      const lineHeight = 13 * 1.6;
      editor.scrollTop = Math.max(0, (line - 3) * lineHeight);
      syncLineNumberScroll();
      setStatus(true, '已定位: ' + entry.signal.name);
    }

    function scrollEditorToGroup(entry) {
      if (app.classList.contains('reading-mode')) return;
      const text = editor.value;
      editor.focus();
      editor.selectionStart = entry.start;
      editor.selectionEnd = entry.end;
      const before = text.slice(0, entry.start);
      const line = before.split('\n').length;
      const lineHeight = 13 * 1.6;
      editor.scrollTop = Math.max(0, (line - 3) * lineHeight);
      syncLineNumberScroll();
      setStatus(true, '已定位分组: ' + (entry.label || '分组'));
    }

    function getWaveLaneGroups(svg) {
      return [...svg.querySelectorAll('g[id^="wavelane_"]')]
        .filter(g => /^wavelane_\d+_\d+$/.test(g.id))
        .sort((a, b) => {
          const ai = parseInt(a.id.match(/^wavelane_(\d+)_/)[1], 10);
          const bi = parseInt(b.id.match(/^wavelane_(\d+)_/)[1], 10);
          return ai - bi;
        });
    }

    function addLaneHoverRect(lane, maxBoundaryIndex, unitWidth) {
      if (lane.querySelector('rect.lane-hover-bg')) return;
      try {
        const bbox = lane.getBBox();
        const rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
        rect.setAttribute('class', 'lane-hover-bg');
        rect.setAttribute('x', bbox.x - 4);
        rect.setAttribute('y', bbox.y - 2);
        let width = bbox.width + 8;
        const drawGroup = lane.querySelector('[id^="wavelane_draw_"]');
        if (maxBoundaryIndex) {
          const waveStartX = drawGroup ? drawGroup.getBBox().x : 0;
          width = Math.max(width, (waveStartX - bbox.x) + maxBoundaryIndex * getWaveColumnWidth(unitWidth) + 8);
        }
        rect.setAttribute('width', width);
        rect.setAttribute('height', Math.max(20, bbox.height + 4));
        rect.setAttribute('fill', 'transparent');
        rect.setAttribute('pointer-events', 'all');
        lane.insertBefore(rect, lane.firstChild);
      } catch (e) { /* getBBox may fail if hidden */ }
    }

    const MIN_NAME_CLICK_ZONE_WIDTH = 72;

    function hasVisibleSvgText(textEl) {
      if (!textEl) return false;
      try {
        const bbox = textEl.getBBox();
        return bbox.width > 0.5 && bbox.height > 0.5;
      } catch (e) {
        return false;
      }
    }

    function ensureSignalNameClickZone(lane, nameText) {
      let zone = lane.querySelector('rect.wave-name-click-zone');
      const drawGroup = lane.querySelector('[id^="wavelane_draw_"]');
      let x;
      let y;
      let width;
      let height;

      try {
        const laneBbox = lane.getBBox();
        const drawX = drawGroup ? drawGroup.getBBox().x : 0;
        x = laneBbox.x;
        width = drawX - laneBbox.x;
        if (width < MIN_NAME_CLICK_ZONE_WIDTH) {
          const textX = parseFloat(nameText.getAttribute('x') || '-10');
          x = textX - MIN_NAME_CLICK_ZONE_WIDTH + 8;
          width = MIN_NAME_CLICK_ZONE_WIDTH;
        }
        y = laneBbox.y;
        height = Math.max(laneBbox.height, 20);
      } catch (e) {
        const textX = parseFloat(nameText.getAttribute('x') || '-10');
        const textY = parseFloat(nameText.getAttribute('y') || '15');
        x = textX - MIN_NAME_CLICK_ZONE_WIDTH + 8;
        y = textY - 14;
        width = MIN_NAME_CLICK_ZONE_WIDTH;
        height = 20;
      }

      if (!zone) {
        zone = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
        zone.setAttribute('class', 'wave-name-click-zone');
        zone.setAttribute('fill', 'transparent');
        zone.setAttribute('pointer-events', 'all');
        if (drawGroup) lane.insertBefore(zone, drawGroup);
        else lane.appendChild(zone);
      }

      zone.setAttribute('x', x);
      zone.setAttribute('y', y);
      zone.setAttribute('width', width);
      zone.setAttribute('height', height);
      return zone;
    }

    function attachSignalNameEdit(lane, entry, handleLanePointSelect) {
      const nameText = lane.querySelector('text.info');
      if (!nameText) return;
      if (nameText.dataset.vwdNameBound === '1') return;

      if (entry.signal.name === '') {
        nameText.textContent = '';
      }

      const openNameEdit = (anchorEl) => {
        startInlineEdit(nameText, entry, 'name', undefined, anchorEl || nameText);
      };

      const onNameClick = (e, anchorEl) => {
        e.stopPropagation();
        if (e.vwdLanePickHandled) return;
        if (!isTextEditModeActive()) {
          handleLanePointSelect(e);
          return;
        }
        openNameEdit(anchorEl);
      };

      if (hasVisibleSvgText(nameText)) {
        nameText.dataset.vwdNameBound = '1';
        nameText.addEventListener('click', (e) => onNameClick(e, nameText));
        return;
      }

      const zone = ensureSignalNameClickZone(lane, nameText);
      nameText.dataset.vwdNameBound = '1';
      zone.dataset.vwdNameBound = '1';
      zone.addEventListener('click', (e) => onNameClick(e, zone));
      nameText.addEventListener('click', (e) => onNameClick(e, nameText));
    }

    function getWaveDataSlots(wave) {
      const slots = [];
      const value = String(wave || '');
      for (let col = 0; col < value.length; col++) {
        const ch = value[col];
        if (!/[2-9=]/.test(ch)) continue;
        slots.push({ dataIdx: slots.length, col });
      }
      return slots;
    }

    function getWaveDataSlotAtColumn(wave, col) {
      const value = String(wave || '');
      if (col < 0 || col >= value.length) return null;
      let slotCol = col;
      if (value[slotCol] === '.') {
        while (slotCol > 0 && value[slotCol] === '.') slotCol--;
      }
      if (!/[2-9=]/.test(value[slotCol])) return null;
      return getWaveDataSlots(value).find((slot) => slot.col === slotCol) || null;
    }

    function attachDataLabelTextEditHandler(drawGroup, entry, svg) {
      if (drawGroup.dataset.vwdDataTextEditBound === '1') return;
      drawGroup.dataset.vwdDataTextEditBound = '1';
      drawGroup.addEventListener('click', (e) => {
        if (!isTextEditModeActive()) return;
        const targetText = e.target && typeof e.target.closest === 'function'
          ? e.target.closest('text.wave-data-text')
          : null;
        const explicitDataIdx = Number.parseInt(targetText?.dataset.vwdDataIndex || '', 10);
        if (Number.isInteger(explicitDataIdx) && explicitDataIdx >= 0) {
          e.stopPropagation();
          e.preventDefault();
          vwdDebugLog('data-label', {
            phase: 'open-editor-by-index',
            signal: entry.signal.name || '',
            dataIdx: explicitDataIdx
          });
          startInlineEdit(targetText, entry, 'data', explicitDataIdx, targetText);
          return;
        }
        const wave = entry.signal.wave || '';
        const col = columnIndexFromClick(drawGroup, wave, svg, e.clientX, getWaveUnitWidth(editor.value));
        const slot = getWaveDataSlotAtColumn(wave, col);
        const data = Array.isArray(entry.signal.data) ? entry.signal.data : [];
        const isEmpty = !!slot && (data[slot.dataIdx] === undefined || data[slot.dataIdx] === '');
        vwdDebugLog('data-label', {
          phase: 'draw-text-edit-click',
          signal: entry.signal.name || '',
          col,
          waveChar: wave[col] || '',
          slotStart: slot ? slot.col : -1,
          dataIdx: slot ? slot.dataIdx : -1,
          isEmpty,
          target: (e.target && e.target.tagName) || ''
        });
        if (!slot) return;
        e.stopPropagation();
        e.preventDefault();
        const anchor = e.target || drawGroup;
        vwdDebugLog('data-label', { phase: 'open-editor', dataIdx: slot.dataIdx, col });
        startInlineEdit(anchor, entry, 'data', slot.dataIdx, anchor);
      }, true);
    }

    function attachSignalDescribeInteractivity(lane, entry, handleLanePointSelect) {
      const anchorText = lane.querySelector('text.info');
      if (!anchorText) return;
      lane.querySelectorAll('text.wave-describe-text').forEach((existing) => existing.remove());

      if (entry.signal === null || typeof entry.signal !== 'object') return;
      const descValue = getSignalDescribeOldValue(entry.signal);
      const displayDesc = descValue || '';

      const drawGroup = lane.querySelector('[id^="wavelane_draw_"]');
      if (app.classList.contains('reading-mode')) return;

      let x = parseFloat(anchorText.getAttribute('x') || '-10');
      let waveLeft = Number.NaN;
      const isFiniteNum = (value) => Number.isFinite(value);
      const setWaveLeftIfFinite = (value) => {
        if (isFiniteNum(value)) {
          waveLeft = value;
        }
      };

      const parseTransformX = (el) => {
        if (!el || typeof el.getAttribute !== 'function') return Number.NaN;
        const transform = el.getAttribute('transform');
        if (!transform) return Number.NaN;
        const translateMatch = transform.match(/translate\(\s*(-?(?:\d+(?:\.\d+)?|\.\d+)(?:[eE][+-]?\d+)?)\s*(?:,\s*|\s+)\s*(-?(?:\d+(?:\.\d+)?|\.\d+)(?:[eE][+-]?\d+)?)?\s*\)/i);
        if (translateMatch && Number.isFinite(parseFloat(translateMatch[1]))) {
          return parseFloat(translateMatch[1]);
        }
        const matrixMatch = transform.match(/matrix\(\s*(-?(?:\d+(?:\.\d+)?|\.\d+)(?:[eE][+-]?\d+)?)\s*,\s*(-?(?:\d+(?:\.\d+)?|\.\d+)(?:[eE][+-]?\d+)?)\s*,\s*(-?(?:\d+(?:\.\d+)?|\.\d+)(?:[eE][+-]?\d+)?)\s*,\s*(-?(?:\d+(?:\.\d+)?|\.\d+)(?:[eE][+-]?\d+)?)\s*,\s*(-?(?:\d+(?:\.\d+)?|\.\d+)(?:[eE][+-]?\d+)?)\s*,\s*(-?(?:\d+(?:\.\d+)?|\.\d+)(?:[eE][+-]?\d+)?)\s*\)/i);
        if (matrixMatch && Number.isFinite(parseFloat(matrixMatch[5]))) {
          return parseFloat(matrixMatch[5]);
        }
        return Number.NaN;
      };

      const ensureWaveLeft = () => {
        if (!drawGroup) return;
        try {
          if (drawGroup.getCTM) {
            const ctmX = drawGroup.getCTM()?.e;
            setWaveLeftIfFinite(ctmX);
          }
          const transformX = parseTransformX(drawGroup);
          setWaveLeftIfFinite(transformX);
        } catch (_e) {
          // ignore and continue to bbox fallback
        }
      };

      ensureWaveLeft();
      try {
        if (drawGroup && drawGroup.getBBox) {
          const drawBbox = drawGroup.getBBox();
          if (isFiniteNum(drawBbox.x)) {
            waveLeft = drawBbox.x;
          }
          if (!Number.isFinite(waveLeft)) {
            const firstShape = drawGroup.querySelector('path, rect, polyline, line, text');
            if (firstShape && firstShape.getBBox) {
              const firstBbox = firstShape.getBBox();
              if (Number.isFinite(firstBbox.x)) {
                waveLeft = firstBbox.x;
              }
            }
          }
          if (!Number.isFinite(waveLeft)) {
            const firstShape = drawGroup.querySelector('path, rect, polyline, line, text');
            if (firstShape && firstShape.getCTM && firstShape.getBBox) {
              const shapeBox = firstShape.getBBox();
              const pt = lane.ownerSVGElement ? lane.ownerSVGElement.createSVGPoint() : null;
              if (pt && isFiniteNum(shapeBox.x) && isFiniteNum(shapeBox.width) && isFiniteNum(shapeBox.y)) {
                pt.x = shapeBox.x;
                pt.y = shapeBox.y;
                const matrix = firstShape.getCTM ? firstShape.getCTM() : null;
                const p = matrix ? pt.matrixTransform(matrix) : pt;
                if (p && isFiniteNum(p.x)) setWaveLeftIfFinite(p.x);
              }
            }
          }
          if (!Number.isFinite(waveLeft)) {
            const allShapes = [...drawGroup.querySelectorAll('path, rect, polyline, line, text, use')];
            let minX = Number.POSITIVE_INFINITY;
            allShapes.forEach((shape) => {
              if (!shape || !shape.getBBox) return;
              try {
                const box = shape.getBBox();
                if (isFiniteNum(box.x)) {
                  minX = Math.min(minX, box.x);
                }
              } catch (_e) {
                // ignore
              }
            });
            if (minX !== Number.POSITIVE_INFINITY) setWaveLeftIfFinite(minX);
          }
        }
      } catch (_e) {
        // fallback to name text x
      }
      if (Number.isFinite(waveLeft)) {
        x = waveLeft;
      }
      const nameX = parseFloat(anchorText.getAttribute('x') || '0');
      if (!Number.isFinite(x) && Number.isFinite(nameX)) {
        x = nameX;
      }
      let y = parseFloat(anchorText.getAttribute('y') || '15');
      let height;
      try {
        const anchorBbox = anchorText.getBBox();
        y = anchorBbox.y + anchorBbox.height;
        height = Math.max(10, anchorBbox.height);
      } catch (_e) {
        // keep fallback
      }

      const describeText = document.createElementNS('http://www.w3.org/2000/svg', 'text');
      describeText.setAttribute('class', 'wave-describe-text');
      const anchorTextX = parseFloat(anchorText.getAttribute('x') || '0');
      const describeTextX = Number.isFinite(x) ? Math.max(0, SIGNAL_DESCRIPTION_X_OFFSET - x) : SIGNAL_DESCRIPTION_X_OFFSET;
      describeText.setAttribute('x', describeTextX + '');
      describeText.setAttribute('y', (y + (height || 16) + 5) + '');
      describeText.setAttribute('data-vwdDescribeBound', '1');
      describeText.setAttribute('text-anchor', 'start');
      if (!descValue) describeText.classList.add('empty');
      renderMultilineSvgText(describeText, displayDesc);
      vwdDebugLog('signal-description-layout', {
        phase: 'positioned',
        signal: entry.signal && entry.signal.name ? entry.signal.name : '',
        drawX: Number.isFinite(x) ? x : null,
        anchorX: anchorTextX,
        finalX: describeTextX,
        offset: SIGNAL_DESCRIPTION_X_OFFSET
      });
      if (drawGroup && drawGroup.parentNode) {
        drawGroup.parentNode.insertBefore(describeText, drawGroup.nextSibling);
      } else {
        lane.appendChild(describeText);
      }

      describeText.addEventListener('click', (e) => {
        e.stopPropagation();
        if (e.vwdLanePickHandled) return;
        if (!isTextEditModeActive()) {
          handleLanePointSelect(e);
          return;
        }
        startInlineEdit(describeText, entry, 'description', undefined, describeText);
      });
    }

    function fitWaveSvgToContent() {
      const svg = waveContainer.querySelector('svg');
      if (!svg) return;
      if (waveContainer) {
        waveContainer.style.paddingBottom = '';
      }
      svg.setAttribute('overflow', 'visible');
      svg.style.overflow = 'visible';
      svg.setAttribute('preserveAspectRatio', 'xMinYMin meet');

      const describeEls = [
        ...svg.querySelectorAll('text.wave-describe-text'),
        svg.querySelector('#vwd-global-describe')
      ].filter(Boolean);
      if (!describeEls.length) return;

      try {
        const svgRect = svg.getBoundingClientRect();
        let maxBottom = -Infinity;
        describeEls.forEach((el) => {
          try {
            const elRect = el.getBoundingClientRect();
            if (!elRect || !Number.isFinite(elRect.bottom) || !Number.isFinite(elRect.top)) return;
            maxBottom = Math.max(maxBottom, elRect.bottom);
          } catch (_e) {
            // ignore
          }
        });
        if (!Number.isFinite(maxBottom) || !Number.isFinite(svgRect.bottom)) return;
        const extraBottom = Math.max(0, Math.ceil(maxBottom - svgRect.bottom + 12));
        if (extraBottom > 0 && waveContainer) {
          waveContainer.style.paddingBottom = extraBottom + 'px';
        }
      } catch (_e) {
        // ignore sizing failures
      }
    }

    function handleWavePanelWheelPaging(e) {
      if (!wavePanel || !e) return;
      if (inlineEditActive) return;
      if (Math.abs(e.deltaY) <= Math.abs(e.deltaX)) return;
      const hasScrollY = wavePanel.scrollHeight > wavePanel.clientHeight + 4;
      if (!hasScrollY) return;

      const target = e.target;
      if (!target || !(target instanceof Element)) return;
      if (!wavePanel.contains(target)) return;
      if (target.closest && target.closest('.wave-text-edit-overlay')) return;

      if (e.ctrlKey || e.metaKey) return;
      e.preventDefault();

      const pageHeight = Math.max(1, Math.floor((wavePanel.clientHeight - 32) * 0.9));
      const delta = e.deltaY > 0 ? 1 : -1;
      const nextTop = wavePanel.scrollTop + delta * pageHeight;
      const maxTop = Math.max(0, wavePanel.scrollHeight - wavePanel.clientHeight);
      const clampedTop = Math.max(0, Math.min(maxTop, nextTop));
      wavePanel.scrollTo({
        top: clampedTop,
        left: wavePanel.scrollLeft,
        behavior: 'smooth'
      });
    }

    function startGroupLabelInlineEdit(textEl, group, anchorEl, groupIndex, inputEvent) {
      if (!isTextEditModeActive()) return;
      exitWavePaintMode('group-label');
      const oldText = String(textEl && textEl.textContent || '');
      if (inlineEditActive) {
        vwdDebugLog('group-label', {
          phase: 'inline-open-blocked',
          reason: 'inline-edit-active',
          groupIndex,
          oldText
        });
        return;
      }
      if (!group) {
        vwdDebugLog('group-label', {
          phase: 'inline-open-blocked',
          reason: 'group-missing',
          groupIndex,
          oldText
        });
        return;
      }
      const anchor = anchorEl || textEl;
      if (!anchor || typeof anchor.getBoundingClientRect !== 'function') {
        vwdDebugLog('group-label', {
          phase: 'inline-open-blocked',
          reason: 'anchor-missing',
          groupIndex,
          oldText
        });
        return;
      }
      vwdDebugLog('group-label', {
        phase: 'inline-start',
        groupIndex,
        oldLabel: group && group.label,
        text: oldText
      });
      inlineEditActive = true;
      const idx = Number.isFinite(groupIndex) ? groupIndex : -1;

      const oldValue = group.label === undefined ? '分组' : group.label;
      const rect = anchor.getBoundingClientRect();
      const panelRect = wavePanel.getBoundingClientRect();
      const fallbackByEvent = inputEvent && Number.isFinite(inputEvent.clientX) && Number.isFinite(inputEvent.clientY);
      let left = rect.left;
      let top = rect.top;
      let width = rect.width;
      let height = rect.height;

      if (!Number.isFinite(width) || width <= 0 || !Number.isFinite(height) || height <= 0) {
        if (fallbackByEvent) {
          left = inputEvent.clientX - 90;
          top = inputEvent.clientY - 12;
          width = 64;
          height = 22;
        } else {
          vwdDebugLog('group-label', {
            phase: 'inline-open-blocked',
            reason: 'invalid-anchor-rect',
            rect: {
              left: rect.left,
              top: rect.top,
              width: rect.width,
              height: rect.height
            },
            fallbackByEvent,
            groupIndex
          });
          inlineEditActive = false;
          return;
        }
      }

      if (!Number.isFinite(left) || !Number.isFinite(top) || !Number.isFinite(width) || !Number.isFinite(height)) {
        vwdDebugLog('group-label', {
          phase: 'inline-open-blocked',
          reason: 'invalid-overlay-rect',
          rect: {
            left: rect.left,
            top: rect.top,
            width: rect.width,
            height: rect.height
          },
          groupIndex
        });
        inlineEditActive = false;
        return;
      }

      const overlayLeft = Math.round(left - panelRect.left + wavePanel.scrollLeft);
      const overlayTop = Math.round(top - panelRect.top + wavePanel.scrollTop);
      const overlayWidth = Math.max(width + 16, 64);
      const overlayHeight = Math.max(height + 4, 22);

      const overlay = document.createElement('input');
      overlay.className = 'wave-text-edit-overlay';
      overlay.type = 'text';
      overlay.value = oldValue;
      overlay.autocomplete = 'off';
      overlay.setAttribute('autocomplete', 'off');
      overlay.spellcheck = false;
      overlay.style.left = overlayLeft + 'px';
      overlay.style.top = overlayTop + 'px';
      overlay.style.position = 'absolute';
      overlay.style.zIndex = '10000';
      overlay.style.width = overlayWidth + 'px';
      overlay.style.height = overlayHeight + 'px';
      overlay.style.boxSizing = 'border-box';

      // Remove stale inline editors if any before opening a new one.
      document.querySelectorAll('.wave-text-edit-overlay').forEach((prev) => {
        if (prev !== overlay && prev.parentElement) prev.remove();
      });
      document.body.appendChild(overlay);
      attachInlineTextInputAutoWidth(overlay, {
        minWidth: overlayWidth,
        left: overlayLeft
      });
      requestAnimationFrame(() => {
        overlay.focus();
      });
      overlay.select();

      const openedAt = performance.now();
      let blurCommitArmed = false;
      let committed = false;
      let outsideClick = null;

      requestAnimationFrame(() => {
        blurCommitArmed = true;
      });

      const commit = () => {
        if (committed) return;
        committed = true;
        const newVal = overlay.value;
        if (outsideClick) {
          document.removeEventListener('mousedown', outsideClick, true);
        }
        vwdDebugLog('group-label', {
          phase: 'inline-commit',
          groupIndex: idx,
          newVal
        });
        overlay.remove();
        inlineEditActive = false;
        if (newVal === oldValue) return;

        const explicitRangeFromGroup = (() => {
          const labelStart = Number.isFinite(group.labelStart) ? group.labelStart : Number.NaN;
          const labelEnd = Number.isFinite(group.labelEnd) ? group.labelEnd : Number.NaN;
          if (!Number.isFinite(labelStart) || !Number.isFinite(labelEnd)) return null;
          return { start: labelStart, end: labelEnd };
        })();

        let replaceText = null;
        let newCaretPos = null;
        let directRangeUsed = false;

        if (explicitRangeFromGroup) {
          const direct = replaceGroupLabelInSourceByAbsoluteRange(editor.value, explicitRangeFromGroup, newVal);
          if (direct) {
            replaceText = direct.text;
            newCaretPos = direct.end;
            directRangeUsed = true;
          }
        }
        if (directRangeUsed) {
          if (!isValidJsonText(replaceText)) {
            setStatus(false, '分组标签更新失败，请重试');
            return;
          }
          pushUndoBeforeChange();
          if (!Number.isFinite(newCaretPos)) {
            newCaretPos = explicitRangeFromGroup.start + JSON.stringify(newVal || '分组').length;
          }
          applyEditorChange(replaceText, newCaretPos, newCaretPos);
          setStatus(true, '已更新分组标签：' + newVal);
          return;
        }

        const groupMap = buildGroupSourceMap(editor.value);
        let currentGroup = null;
        if (explicitRangeFromGroup) {
          const exact = groupMap.find((g) => Number.isFinite(g.labelStart)
            && Number.isFinite(g.labelEnd)
            && g.labelStart === explicitRangeFromGroup.start
            && g.labelEnd === explicitRangeFromGroup.end);
          if (exact) {
            currentGroup = exact;
          }
        }
        if (idx >= 0 && groupMap[idx]) {
          currentGroup = groupMap[idx];
        }
        if (!currentGroup && group && typeof group.start === 'number' && typeof group.end === 'number') {
          const passedLabel = getGroupLabelText(editor.value, group);
          const matched = groupMap.find((g) => g.start === group.start && g.end === group.end);
          if (!matched || passedLabel === null || passedLabel === oldValue) {
            currentGroup = matched || group;
          }
        }
        if (!currentGroup) {
          if (group && Array.isArray(group.path)) {
            currentGroup = group;
          }
        }
        if (!currentGroup) {
          const byLabel = groupMap.find((g) => {
            if (typeof g.start !== 'number' || typeof g.end !== 'number') return false;
            const parsedLabel = getGroupLabelText(editor.value, g);
            return parsedLabel === oldValue;
          });
          if (byLabel) currentGroup = byLabel;
        }
        if (!currentGroup) {
          setStatus(false, '分组标签位置未定位，无法更新');
          return;
        }
        const seen = new Set();
        const candidates = [];
        const pushCandidate = (candidate) => {
          if (!candidate || typeof candidate.start !== 'number' || typeof candidate.end !== 'number') return;
          const key = candidate.start + ':' + candidate.end;
          if (seen.has(key)) return;
          seen.add(key);
          candidates.push(candidate);
        };
        pushCandidate(currentGroup);
        if (group !== currentGroup) pushCandidate(group);

        for (let i = 0; i < candidates.length && !replaceText; i++) {
          const candidate = candidates[i];
          const replaceResult = replaceGroupLabelInSourceByRange(editor.value, candidate, newVal);
          if (replaceResult) {
            replaceText = replaceResult.text;
            newCaretPos = replaceResult.end;
          }
        }

        if (!replaceText) {
          for (let i = 0; i < candidates.length && !replaceText; i++) {
            const candidate = candidates[i];
            const fallbackText = replaceGroupLabelInSource(editor.value, candidate, newVal);
            if (fallbackText !== editor.value) {
              replaceText = fallbackText;
              if (typeof candidate.labelStart === 'number' && typeof candidate.labelEnd === 'number') {
                newCaretPos = candidate.labelStart + JSON.stringify(newVal || '分组').length;
              }
            }
          }
        }
        if (!replaceText || replaceText === editor.value) {
          if (currentGroup && Array.isArray(currentGroup.path)) {
            const byPath = replaceGroupLabelInSourceByPath(editor.value, currentGroup.path, newVal);
            if (byPath && byPath.text && byPath.text !== editor.value) {
              replaceText = byPath.text;
            }
          }
          if (!replaceText || replaceText === editor.value) {
            setStatus(false, '未能定位该分组，无法更新');
            return;
          }
        }
        if (!isValidJsonText(replaceText)) {
          setStatus(false, '分组标签更新失败，请重试');
          return;
        }
        pushUndoBeforeChange();
        if (!Number.isFinite(newCaretPos)) {
          if (typeof currentGroup.labelStart === 'number' && typeof currentGroup.labelEnd === 'number') {
            newCaretPos = currentGroup.labelStart + JSON.stringify(newVal || '分组').length;
          } else {
            const lineText = editor.value.slice(currentGroup.start, currentGroup.end);
            newCaretPos = currentGroup.start + Math.min(lineText.length, 2);
          }
        }
        applyEditorChange(replaceText, newCaretPos, newCaretPos);
        setStatus(true, '已更新分组标签：' + newVal);
      };

      overlay.addEventListener('blur', () => {
        if (!blurCommitArmed && performance.now() - openedAt < 80) {
          vwdDebugLog('group-label', {
            phase: 'inline-blur-suppressed',
            groupIndex: idx,
            sinceOpenMs: Math.round(performance.now() - openedAt)
          });
          overlay.focus();
          return;
        }
        vwdDebugLog('group-label', {
          phase: 'inline-blur-commit',
          groupIndex: idx
        });
        commit();
      });
      outsideClick = (e) => {
        if (committed) return;
        if (overlay.contains(e.target)) return;
        if (e.target.classList && e.target.classList.contains('wave-text-edit-overlay')) return;
        vwdDebugLog('group-label', {
          phase: 'inline-outside-commit',
          groupIndex: idx
        });
        commit();
      };
      document.addEventListener('mousedown', outsideClick, true);
      overlay.addEventListener('keydown', (e) => {
        if (handleUndoRedoShortcut(e)) return;
        e.stopPropagation();
        vwdDebugLog('group-label', {
          phase: 'inline-keydown',
          groupIndex: idx,
          key: e.key,
          code: e.code
        });
        if (e.key === 'Enter' || e.key === 'NumpadEnter') { e.preventDefault(); commit(); }
        if (e.key === 'Escape') {
          committed = true;
          overlay.remove();
          if (outsideClick) {
            document.removeEventListener('mousedown', outsideClick, true);
          }
          inlineEditActive = false;
        }
      });
      overlay.addEventListener('keyup', (e) => {
        if (e.key === 'Enter' || e.key === 'NumpadEnter') {
          e.preventDefault();
          commit();
        }
      });
      overlay.addEventListener('change', commit);
    }

    function refreshGroupSelection(svg, groupMap) {
      const lanes = getWaveLaneGroups(svg);
      groupMap = groupMap || buildGroupSourceMap(editor.value || '');
      const selected = Number.isFinite(selectedGroupIndex) ? selectedGroupIndex : -1;
      const selectedGroup = groupMap[selected];

      lanes.forEach((lane) => {
        lane.classList.remove('wave-group-selected-lane', 'wave-group-range-start', 'wave-group-range-end');
      });
      [...svg.querySelectorAll('text')].forEach((textEl) => {
        textEl.classList.remove('wave-group-label-selected');
      });

      if (!selectedGroup) return;

      for (let i = selectedGroup.rowStart; i <= selectedGroup.rowEnd; i++) {
        const lane = lanes[i];
        if (!lane) continue;
        lane.classList.add('wave-group-selected-lane');
        if (i === selectedGroup.rowStart) lane.classList.add('wave-group-range-start');
        if (i === selectedGroup.rowEnd) lane.classList.add('wave-group-range-end');
      }

      const labelText = (selectedGroup.label || '分组');
      const labelEl = [...svg.querySelectorAll('text')].find((textEl) => {
        const cls = textEl.getAttribute('class') || '';
        if (cls.includes('wave-name-click-zone')) return false;
        const text = String(textEl.textContent || '').trim();
        if (text !== labelText) return false;
        const idx = parseInt(textEl.dataset && textEl.dataset.vwdGroupIndex, 10);
        if (!Number.isFinite(idx)) return false;
        return idx === selected;
      });
      if (labelEl) {
        labelEl.classList.add('wave-group-label-selected');
      }
    }

    function attachGroupInteractivity(jsonText) {
      const svg = waveContainer.querySelector('svg');
      if (!svg) return;
      vwdDebugLog('group-label', {
        phase: 'attach-start',
        hasText: typeof editor.value === 'string',
        jsonTextLength: jsonText ? jsonText.length : 0
      });

      const groupMap = buildGroupSourceMap(jsonText);
      const lanes = getWaveLaneGroups(svg);
      if (!groupMap.length) {
        refreshGroupSelection(svg, groupMap);
        vwdDebugLog('group-label', { phase: 'attach-empty', groupCount: 0 });
        return;
      }

      svg.querySelectorAll('[data-vwd-group-label]').forEach((el) => {
        const tag = (el.tagName || '').toLowerCase();
        if (tag === 'rect' && el.classList.contains('wave-group-label-fallback')) {
          el.remove();
          return;
        }
        el.classList.remove('wave-group-label-hit');
        el.classList.remove('wave-group-label-fallback');
        delete el.dataset.vwdGroupIndex;
        delete el.dataset.vwdGroupLabel;
        delete el.dataset.vwdGroupLabelStart;
        delete el.dataset.vwdGroupLabelEnd;
        delete el.dataset.vwdGroupPath;
        delete el.dataset.vwdGroupBound;
      });

      const laneBoxes = lanes.map((lane) => {
        try {
          const rect = lane.getBBox();
          return { y0: rect.y, y1: rect.y + rect.height };
        } catch (e) {
          return null;
        }
      });

      const candidates = [...svg.querySelectorAll('text')].map((textEl) => {
        const value = String(textEl.textContent || '').trim();
        if (!value) return null;
        const cls = textEl.getAttribute('class') || '';
        if (cls.includes('wave-data-text')) return null;
        const y = parseFloat(textEl.getAttribute('y') || '0');
        return { textEl, value, y };
      }).filter(Boolean);

      const openGroupLabelEditor = (inputEvent, idx, explicitStart, explicitEnd, labelEl, fallbackGroupIndex) => {
        vwdDebugLog('group-label', {
          phase: 'open-editor',
          idx,
          explicitStart,
          explicitEnd,
          fallbackGroupIndex,
          label: labelEl ? String((labelEl.textContent || '').trim()) : ''
        });
        const currentGroupMap = buildGroupSourceMap(editor.value || '');
        let selectableGroupIndex = Number.isFinite(fallbackGroupIndex) ? fallbackGroupIndex : idx;
        if ((!Number.isFinite(selectableGroupIndex) || selectableGroupIndex < 0 || selectableGroupIndex >= currentGroupMap.length)
          && Number.isFinite(explicitStart)
          && Number.isFinite(explicitEnd)) {
          const byRange = currentGroupMap.find((g) => g.labelStart === explicitStart && g.labelEnd === explicitEnd);
          if (byRange) selectableGroupIndex = currentGroupMap.indexOf(byRange);
        }
        if (!Number.isFinite(selectableGroupIndex) || selectableGroupIndex < 0 || currentGroupMap.length === 0 || selectableGroupIndex >= currentGroupMap.length) {
          vwdDebugLog('group-label', {
            phase: 'open-editor-abort',
            reason: 'index-out-of-range',
            selectableGroupIndex,
            fallbackGroupIndex,
            idx,
            count: currentGroupMap.length
          });
          return;
        }
        if (inputEvent && inputEvent.type) {
          vwdDebugLog('group-label', {
            phase: 'open-editor-ok',
            selectableGroupIndex,
            inputType: inputEvent.type,
            count: currentGroupMap.length
          });
        }

        const selectedGroup = currentGroupMap[selectableGroupIndex];
        const editableGroup = selectedGroup && Number.isFinite(explicitStart) && Number.isFinite(explicitEnd)
          ? Object.assign({}, selectedGroup, {
            labelStart: explicitStart,
            labelEnd: explicitEnd
          })
          : selectedGroup;
        if (!editableGroup) {
          vwdDebugLog('group-label', {
            phase: 'open-editor-abort',
            reason: 'editable-group-missing',
            selectableGroupIndex,
            explicitStart,
            explicitEnd,
            count: currentGroupMap.length
          });
          return;
        }

        selectedGroupIndex = selectableGroupIndex;
        setGroupDeleteShortcutActive(true, 'open-group-editor');
        setWaveClipboardShortcutActive(false, 'group-selected');
        selectedSignalIndex = -1;
        selectedWaveColumnIndex = -1;
        const svg = waveContainer.querySelector('svg');
        if (svg) {
          refreshGroupSelection(svg, currentGroupMap);
          const groupForHint = currentGroupMap[selectableGroupIndex];
          requestAnimationFrame(() => {
            if (!groupForHint || app.classList.contains('reading-mode')) return;
            const sourceText = editor.value || '';
            const before = sourceText.slice(0, groupForHint.start);
            const line = before.split('\n').length;
            const lineHeight = 13 * 1.6;
            editor.scrollTop = Math.max(0, (line - 3) * lineHeight);
            syncLineNumberScroll();
          });
        }
        updateLegendAvailability();

        inputEvent?.preventDefault?.();
        inputEvent?.stopPropagation?.();
        startGroupLabelInlineEdit(labelEl, editableGroup, labelEl, selectableGroupIndex, inputEvent);
      };

      const resolveGroupIndexForLabelClick = (rawIndex, explicitStart, explicitEnd, labelEl) => {
        const currentGroupMap = buildGroupSourceMap(editor.value || '');
        if (Number.isFinite(explicitStart) && Number.isFinite(explicitEnd)) {
          const byRange = currentGroupMap.find((g) => g.labelStart === explicitStart && g.labelEnd === explicitEnd);
          if (byRange) {
            const matchIndex = currentGroupMap.indexOf(byRange);
            vwdDebugLog('group-label', {
              phase: 'resolve',
              method: 'range',
              rawIndex,
              explicitStart,
              explicitEnd,
              resolvedIndex: matchIndex
            });
            return matchIndex;
          }
        }

        if (labelEl && labelEl.dataset && typeof labelEl.dataset.vwdGroupPath === 'string') {
          const pathText = labelEl.dataset.vwdGroupPath;
          const path = pathText.split(',').map((n) => {
            const idx = parseInt(n, 10);
            return Number.isFinite(idx) ? idx : -1;
          }).filter((idx) => idx >= 0);
          if (path.length) {
            const byPath = currentGroupMap.find((g) => Array.isArray(g.path)
              && g.path.length === path.length
              && g.path.every((value, i) => value === path[i]));
            if (byPath) {
              const matchIndex = currentGroupMap.indexOf(byPath);
              vwdDebugLog('group-label', {
                phase: 'resolve',
                method: 'path',
                rawIndex,
                resolvedIndex: matchIndex,
                path
              });
              return matchIndex;
            }
          }
        }

        if (Number.isFinite(rawIndex) && rawIndex >= 0 && rawIndex < currentGroupMap.length) {
          return rawIndex;
        }

        const labelText = String((labelEl && labelEl.textContent) || '').trim();
        if (labelText) {
          const byText = currentGroupMap.find((g) => String(g.label || '').trim() === labelText);
          if (byText) {
            const matchIndex = currentGroupMap.indexOf(byText);
            vwdDebugLog('group-label', {
              phase: 'resolve',
              method: 'text',
              rawIndex,
              resolvedIndex: matchIndex,
              labelText
            });
            return matchIndex;
          }
        }

        vwdDebugLog('group-label', {
          phase: 'resolve',
          method: 'fallback-fail',
          rawIndex,
          explicitStart,
          explicitEnd,
          labelText: String((labelEl && labelEl.textContent) || '').trim()
        });
        return -1;
      };

      const handleGroupLabelAction = (inputEvent, idx, explicitStart, explicitEnd, labelEl, forceOpen) => {
        if (inlineEditActive || app.classList.contains('reading-mode')) return;
        if (groupPickActive) {
          clearSelectedGroupState();
        }
        if (forceOpen === undefined) forceOpen = false;

        const resolvedIndex = resolveGroupIndexForLabelClick(idx, explicitStart, explicitEnd, labelEl);
        if (!Number.isFinite(resolvedIndex) || resolvedIndex < 0) {
          setStatus(false, '未定位到当前分组，请先选中分组标签或重渲染');
          vwdDebugLog('group-label', {
            phase: 'action',
            step: 'resolve-failed',
            idx,
            explicitStart,
            explicitEnd
          });
          return;
        }

        const freshGroupMap = buildGroupSourceMap(editor.value || '');
        if (resolvedIndex < 0 || resolvedIndex >= freshGroupMap.length) return;
        vwdDebugLog('group-label', {
          phase: 'action',
          step: 'selected',
          idx,
          resolvedIndex,
          forceOpen,
          groupLabel: freshGroupMap[resolvedIndex] ? freshGroupMap[resolvedIndex].label : ''
        });

        const shouldOpenEditor = !!forceOpen && isTextEditModeActive();
        selectedGroupIndex = resolvedIndex;
        setGroupDeleteShortcutActive(true, 'group-label-click');
        setWaveClipboardShortcutActive(false, 'group-selected');
        selectedSignalIndex = -1;
        selectedWaveColumnIndex = -1;
        const svg = waveContainer.querySelector('svg');
        if (svg) {
          refreshGroupSelection(svg, freshGroupMap);
          requestAnimationFrame(() => scrollEditorToGroup(freshGroupMap[resolvedIndex]));
        }
        updateLegendAvailability();
        if (!shouldOpenEditor) {
          setStatus(true, '已选中分组：' + (freshGroupMap[resolvedIndex].label || '分组'));
        }
        if (!shouldOpenEditor) return;

        vwdDebugLog('group-label', {
          phase: 'action',
          step: 'open-inline',
          idx,
          resolvedIndex
        });
        if (inputEvent?.preventDefault) {
          inputEvent.preventDefault();
        }
        try {
          openGroupLabelEditor(inputEvent, idx, explicitStart, explicitEnd, labelEl, resolvedIndex);
        } catch (err) {
          vwdDebugLog('group-label', {
            phase: 'action',
            step: 'open-inline-error',
            idx,
            resolvedIndex,
            error: String(err && err.message ? err.message : err)
          });
          inlineEditActive = false;
          setStatus(false, '分组标签编辑打开失败，请重试');
        }
      };

      if (svg.__vwdGroupLabelDelegatedBound) {
        if (typeof svg.__vwdGroupLabelDelegatedClick === 'function') {
          svg.removeEventListener('click', svg.__vwdGroupLabelDelegatedClick, true);
        }
        delete svg.__vwdGroupLabelDelegatedClick;
        svg.__vwdGroupLabelDelegatedBound = false;
      }

      const allGroupLabelTargets = [];

      groupMap.forEach((group, index) => {
        const label = String(group.label || '').trim();
        if (!label) return;

        const rows = laneBoxes
          .map((box, idx) => (box ? { idx, ...box } : null))
          .slice(group.rowStart, group.rowEnd + 1)
          .filter(Boolean);
        if (!rows.length) return;

        const minY = Math.min(...rows.map((item) => item.y0));
        const maxY = Math.max(...rows.map((item) => item.y1));
        const yCenter = (minY + maxY) / 2;
        const labelCandidate = candidates.find((item) => {
          if (item.value !== label) return false;
          if (item.textEl.dataset.vwdGroupIndex != null) return false;
          return item.y >= minY - 30 && item.y <= maxY + 30;
        }) || candidates
          .map((item) => {
            const distance = Math.abs(item.y - yCenter);
            return Object.assign({}, item, { distance });
          })
          .filter((item) => item.value === label && item.y >= minY - 35 && item.y <= maxY + 35)
          .sort((a, b) => a.distance - b.distance)[0];

        const labelTargets = [];
        let popupAnchor = null;
        let fallbackRect;
        if (labelCandidate) {
          popupAnchor = labelCandidate.textEl;
          labelTargets.push(labelCandidate.textEl);
          try {
            const box = labelCandidate.textEl.getBBox();
            const hitRect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
            hitRect.setAttribute('x', box.x - 2);
            hitRect.setAttribute('y', box.y - 2);
            hitRect.setAttribute('width', Math.max(48, box.width + 8));
            hitRect.setAttribute('height', Math.max(18, box.height + 4));
            hitRect.setAttribute('fill', 'transparent');
            hitRect.setAttribute('pointer-events', 'all');
            hitRect.setAttribute('class', 'wave-group-label-fallback');
            hitRect.setAttribute('aria-label', '分组: ' + label + ' 标签');
            svg.appendChild(hitRect);
            fallbackRect = hitRect;
            labelTargets.push(hitRect);
          } catch (_e) {
            // ignore fallback rect creation failure
          }
        } else {
          const fallbackLane = lanes[group.rowStart];
          if (!fallbackLane) return;
          let laneRect;
          try {
            laneRect = fallbackLane.getBBox();
          } catch (e) {
            return;
          }
          const hitRect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
          hitRect.setAttribute('x', laneRect.x + 2);
          hitRect.setAttribute('y', minY - 8);
          hitRect.setAttribute('width', Math.min(72, Math.max(46, laneRect.width * 0.4)));
          hitRect.setAttribute('height', Math.max(14, (maxY - minY) + 8));
          hitRect.setAttribute('fill', 'transparent');
          hitRect.setAttribute('pointer-events', 'all');
          hitRect.setAttribute('class', 'wave-group-label-fallback');
          hitRect.setAttribute('aria-label', '分组: ' + label + ' 标签');
          svg.appendChild(hitRect);
          fallbackRect = hitRect;
          labelTargets.push(hitRect);
        }

        if (!labelTargets.length) return;
        const labelEditAnchor = popupAnchor || labelTargets[0];
        if (!labelEditAnchor) return;
        vwdDebugLog('group-label', {
          phase: 'attach-targets',
          index,
          label,
          targetCount: labelTargets.length,
          hasFallback: !!fallbackRect
        });
        labelTargets.forEach((targetEl) => {
          targetEl.dataset.vwdGroupIndex = String(index);
          targetEl.dataset.vwdGroupLabel = '1';
          if (Number.isFinite(group.labelStart)) {
            targetEl.dataset.vwdGroupLabelStart = String(group.labelStart);
          } else {
            delete targetEl.dataset.vwdGroupLabelStart;
          }
          if (Number.isFinite(group.labelEnd)) {
            targetEl.dataset.vwdGroupLabelEnd = String(group.labelEnd);
          } else {
            delete targetEl.dataset.vwdGroupLabelEnd;
          }
          if (Array.isArray(group.path)) {
            targetEl.dataset.vwdGroupPath = group.path.join(',');
          } else {
            delete targetEl.dataset.vwdGroupPath;
          }
          targetEl.dataset.vwdGroupBound = fallbackRect ? '1' : '0';
          targetEl.setAttribute('pointer-events', 'all');
          targetEl.classList.add('wave-group-label-hit');
          targetEl.style.removeProperty('cursor');
          allGroupLabelTargets.push(targetEl);
          targetEl.__vwdGroupLabelAnchor = labelEditAnchor;
        });
      });

      allGroupLabelTargets.forEach((targetEl) => {
        const clickHandler = (e) => {
          e.stopPropagation();
          const idx = parseInt(targetEl.dataset.vwdGroupIndex, 10);
          const explicitStart = parseInt(targetEl.dataset.vwdGroupLabelStart, 10);
          const explicitEnd = parseInt(targetEl.dataset.vwdGroupLabelEnd, 10);
          const anchorEl = targetEl.__vwdGroupLabelAnchor || targetEl;
          const shouldOpen = isTextEditModeActive();
          vwdDebugLog('group-label', {
            phase: 'click',
            idx,
            explicitStart,
            explicitEnd,
            shouldOpen,
            clickDetail: e.detail,
            eventType: e.type
          });
          handleGroupLabelAction(e, idx, explicitStart, explicitEnd, anchorEl, shouldOpen);
        };

        const previousClick = targetEl.__vwdGroupLabelDirectClick;
        if (previousClick) targetEl.removeEventListener('click', previousClick);
        targetEl.__vwdGroupLabelDirectClick = clickHandler;
        targetEl.addEventListener('click', clickHandler);
      });

      refreshGroupSelection(svg, groupMap);
    }

    function startInlineEdit(textEl, entry, field, dataIdx, anchorEl) {
      if (!isTextEditModeActive()) return;
      exitWavePaintMode(field === 'description' ? 'wave-description' : 'inline-edit');
      if (inlineEditActive) return;
      inlineEditActive = true;
      setActiveInlineEditState({
        kind: 'inline',
        field,
        dataIdx,
        entryStart: entry && entry.start,
        entryEnd: entry && entry.end
      });
      vwdDebugLog('inline-edit', {
        phase: 'open-start',
        field,
        dataIdx,
        isDescription: field === 'description',
        hasEntry: !!entry
      });

      let oldValue;
      if (field === 'name') {
        oldValue = entry.signal.name || '';
      } else if (field === 'data') {
        oldValue = (entry.signal.data && entry.signal.data[dataIdx] !== undefined
          ? entry.signal.data[dataIdx]
          : textEl.textContent);
      } else if (field === 'description') {
        oldValue = getSignalDescribeOldValue(entry.signal);
      } else {
        oldValue = textEl.textContent;
      }

      const isDescriptionField = (field === 'description');
      const anchor = anchorEl || textEl;
      const rect = anchor.getBoundingClientRect();
      const panelRect = wavePanel.getBoundingClientRect();
      const overlay = isDescriptionField
        ? document.createElement('textarea')
        : document.createElement('input');
      overlay.className = isDescriptionField
        ? 'wave-text-edit-overlay wave-description-overlay'
        : 'wave-text-edit-overlay';
      if (!isDescriptionField) overlay.type = 'text';
      overlay.value = oldValue;
      overlay.autocomplete = 'off';
      overlay.setAttribute('autocomplete', 'off');
      overlay.spellcheck = false;
      const overlayLeft = isDescriptionField
        ? 0
        : (rect.left - panelRect.left + wavePanel.scrollLeft);
      if (isDescriptionField) {
        vwdDebugLog('signal-description-layout', {
          phase: 'overlay-left',
          field,
          rectLeft: rect.left,
          panelLeft: panelRect.left,
          scrollLeft: wavePanel.scrollLeft,
          finalLeft: overlayLeft,
          offset: SIGNAL_DESCRIPTION_OVERLAY_OFFSET
        });
      }
      vwdDebugLog('inline-edit', {
        phase: 'overlay-place',
        field,
        isDescriptionField,
        panelTop: panelRect.top,
        panelLeft: panelRect.left,
        left: isDescriptionField ? 0 : overlayLeft,
        top: isDescriptionField ? rect.top : (rect.top - panelRect.top + wavePanel.scrollTop),
        parent: isDescriptionField ? 'body' : 'wavePanel',
        isFixed: isDescriptionField
      });
      const overlayTop = isDescriptionField
        ? rect.top
        : (rect.top - panelRect.top + wavePanel.scrollTop);
      overlay.style.left = isDescriptionField ? '0px' : (overlayLeft + 'px');
      overlay.style.top = overlayTop + 'px';
      if (isDescriptionField) {
        overlay.style.right = 'auto';
        overlay.style.transform = 'none';
        overlay.style.margin = '0';
        overlay.style.paddingLeft = '6px';
      }
      const descriptionBaseWidth = Math.max(180, Math.floor(Math.max(0, (window.innerWidth || document.documentElement.clientWidth || panelRect.width) - 8)));
      overlay.style.width = Math.max(rect.width + 16, isDescriptionField ? descriptionBaseWidth : 48) + 'px';
      overlay.style.height = Math.max(rect.height + 4, isDescriptionField ? 86 : 22) + 'px';

      let resizeDescriptionOverlay = null;
      if (isDescriptionField) {
        overlay.rows = 4;
        overlay.style.resize = 'vertical';
        overlay.style.whiteSpace = 'pre-wrap';
        resizeDescriptionOverlay = () => autoResizeDescriptionOverlay(overlay, {
          minHeight: 86,
          maxHeight: 360
        });
        resizeDescriptionOverlay();
        overlay.addEventListener('input', resizeDescriptionOverlay);
      }

      const overlayParent = isDescriptionField ? document.body : wavePanel;
      if (isDescriptionField) {
        overlay.style.position = 'fixed';
        overlay.style.left = '0px';
      }
      overlayParent.appendChild(overlay);
      if (!isDescriptionField) {
        attachInlineTextInputAutoWidth(overlay, {
          container: wavePanel,
          minWidth: Math.max(rect.width + 16, 48),
          left: overlayLeft
        });
      }
      if (resizeDescriptionOverlay) {
        requestAnimationFrame(() => resizeDescriptionOverlay());
      }
      overlay.focus();
      if (field === 'name' && oldValue === '') {
        overlay.setSelectionRange(0, 0);
      } else {
        overlay.select();
      }

      let committed = false;
      const commit = () => {
        if (committed) return;
        committed = true;
        const newVal = overlay.value;
        vwdDebugLog('inline-edit', {
          phase: 'commit',
          field,
          targetValueLen: newVal.length,
          oldValueLen: oldValue ? oldValue.length : 0,
          sameValue: newVal === oldValue
        });
        overlay.remove();
        inlineEditActive = false;
        setActiveInlineEditState(null);
        if (newVal !== oldValue) {
          const currentText = editor.value || '';
          if (currentText.length <= 500000) pushUndoBeforeChange();
          const mapBefore = buildSignalSourceMap(currentText);
          const laneIdx = mapBefore.findIndex(m => m.start === entry.start);
          const newText = replaceFieldInSource(currentText, entry, field, newVal, dataIdx);
          const map = buildSignalSourceMap(newText);
          const updated = laneIdx >= 0 ? map[laneIdx] : map.find(m => m.signal.name === newVal);
          applyEditorChange(newText, updated ? updated.start : editor.selectionStart, updated ? updated.end : undefined);
          if (field === 'name') setStatus(true, '已更新名称');
          else if (field === 'data') setStatus(true, '已更新数据标签');
          else if (field === 'description') setStatus(true, '已更新波形说明');
          else setStatus(true, '已更新字段');
        }
      };

      overlay.addEventListener('blur', commit);
      overlay.addEventListener('keydown', (e) => {
        if (!isDescriptionField && handleUndoRedoShortcut(e)) return;
        e.stopPropagation();
        vwdDebugLog('inline-edit', {
          phase: 'key-down',
          field,
          isDescription: isDescriptionField,
          key: e.key,
          code: e.code,
          ctrlKey: e.ctrlKey,
          metaKey: e.metaKey,
          altKey: e.altKey,
          shiftKey: e.shiftKey,
          targetValueLen: overlay.value.length
        });
        const isSubmitKey = (e.key === 'Enter' || e.key === 'NumpadEnter');
        if (isSubmitKey) {
          if (isDescriptionField && (e.ctrlKey || e.metaKey)) {
            e.preventDefault();
            insertInlineNewline(overlay, e);
            if (resizeDescriptionOverlay) {
              resizeDescriptionOverlay();
            }
            return;
          }
          e.preventDefault();
          commit();
        }
        if (e.key === 'Escape') {
          committed = true;
          overlay.remove();
          inlineEditActive = false;
          setActiveInlineEditState(null);
        }
      });
    }

    function startHeadFootInlineEdit(textEl, field) {
      if (!isTextEditModeActive()) return;
      exitWavePaintMode('head-foot');
      if (inlineEditActive) return;
      inlineEditActive = true;

      let parsed;
      try {
        parsed = JSON.parse(editor.value);
      } catch (e) {
        inlineEditActive = false;
        return;
      }

      const oldValue = getHeadFootOldValue(parsed, field);

      const rect = textEl.getBoundingClientRect();
      const panelRect = wavePanel.getBoundingClientRect();
      const overlay = document.createElement('input');
      overlay.className = 'wave-text-edit-overlay';
      overlay.type = 'text';
      overlay.value = oldValue;
      overlay.style.left = (rect.left - panelRect.left + wavePanel.scrollLeft) + 'px';
      overlay.style.top = (rect.top - panelRect.top + wavePanel.scrollTop) + 'px';
      overlay.style.width = Math.max(rect.width + 16, 120) + 'px';
      overlay.style.height = Math.max(rect.height + 4, 22) + 'px';

      wavePanel.appendChild(overlay);
      attachInlineTextInputAutoWidth(overlay, {
        container: wavePanel,
        minWidth: Math.max(rect.width + 16, 120),
        left: rect.left - panelRect.left + wavePanel.scrollLeft
      });
      overlay.focus();
      overlay.select();

      let committed = false;
      const commit = () => {
        if (committed) return;
        committed = true;
        const newVal = overlay.value;
        overlay.remove();
        inlineEditActive = false;
        if (newVal !== oldValue) {
          const currentText = editor.value || '';
          if (currentText.length <= 500000) pushUndoBeforeChange();
          const newText = replaceHeadFootTextInSource(currentText, field, newVal);
          const block = findTopLevelKeyBlock(newText, field);
          applyEditorChange(
            newText,
            block ? block.start : editor.selectionStart,
            block ? block.end : undefined
          );
          scrollEditorToHeadFoot(field);
          setStatus(true, field === 'head' ? 'Updated header text' : 'Updated footer text');
        }
      };

      overlay.addEventListener('blur', commit);
      overlay.addEventListener('keydown', (e) => {
        if (handleUndoRedoShortcut(e)) return;
        e.stopPropagation();
        if (e.key === 'Enter') { e.preventDefault(); commit(); }
        if (e.key === 'Escape') {
          committed = true;
          overlay.remove();
          inlineEditActive = false;
        }
      });
    }

    function attachHeadFootInteractivity(jsonText, parsedSource) {
      const svg = waveContainer.querySelector('svg');
      if (!svg) return;

      let parsed = parsedSource;
      try {
        if (!parsed) parsed = JSON.parse(jsonText);
      } catch (e) {
        return;
      }

      const gmarks = svg.querySelector('[id^="gmarks_"]');
      if (!gmarks) return;

      [...gmarks.querySelectorAll(':scope > text')].forEach((textEl) => {
        const y = parseFloat(textEl.getAttribute('y') || '0');
        const field = y < 0 ? 'head' : 'foot';
        if (!parsed[field]) return;

        textEl.classList.add('wave-headfoot-text');
        textEl.addEventListener('click', (e) => {
          if (!isTextEditModeActive()) return;
          e.stopPropagation();
          startHeadFootInlineEdit(textEl, field);
        });
      });
    }

    function startGlobalDescribeInlineEdit(textEl) {
      if (!isTextEditModeActive()) return;
      exitWavePaintMode('wave-description');
      if (inlineEditActive) return;
      inlineEditActive = true;
      setActiveInlineEditState({
        kind: 'global-description'
      });
      vwdDebugLog('inline-edit', { phase: 'open-start', field: 'description', kind: 'global' });

      let parsed;
      try {
        parsed = JSON.parse(editor.value);
      } catch (e) {
        inlineEditActive = false;
        return;
      }

      const oldValue = getGlobalDescribeOldValue(parsed);
      const rect = textEl.getBoundingClientRect();
      const panelRect = wavePanel.getBoundingClientRect();
      const overlay = document.createElement('textarea');
      overlay.className = 'wave-text-edit-overlay wave-description-overlay';
      overlay.value = oldValue;
      const overlayLeft = 0;
      const overlayTop = rect.top;
      vwdDebugLog('inline-edit', {
        phase: 'overlay-place',
        field: 'global-description',
        isDescriptionField: true,
        left: overlayLeft,
        top: overlayTop,
        parent: 'body',
        isFixed: true
      });
      overlay.style.position = 'fixed';
      overlay.style.left = overlayLeft + 'px';
      overlay.style.top = overlayTop + 'px';
      overlay.style.right = 'auto';
      overlay.style.transform = 'none';
      overlay.style.margin = '0';
      overlay.style.paddingLeft = '6px';
      overlay.style.width = Math.max(rect.width + 16, Math.max(180, Math.floor(Math.max(0, (window.innerWidth || document.documentElement.clientWidth || panelRect.width) - 8)))) + 'px';
      overlay.style.height = Math.max(rect.height + 4, 86) + 'px';
      overlay.rows = 4;
      overlay.style.resize = 'vertical';
      overlay.style.whiteSpace = 'pre-wrap';
      const resizeDescriptionOverlay = () => autoResizeDescriptionOverlay(overlay, {
        minHeight: 86,
        maxHeight: 360
      });
      resizeDescriptionOverlay();
      overlay.addEventListener('input', resizeDescriptionOverlay);

      document.body.appendChild(overlay);
      requestAnimationFrame(() => resizeDescriptionOverlay());
      overlay.focus();
      overlay.select();

      let committed = false;
      const commit = () => {
        if (committed) return;
        committed = true;
        const newVal = overlay.value;
        vwdDebugLog('inline-edit', {
          phase: 'commit',
          field: 'description',
          isGlobal: true,
          targetValueLen: newVal.length,
          oldValueLen: oldValue ? oldValue.length : 0,
          sameValue: newVal === oldValue
        });
        overlay.remove();
        inlineEditActive = false;
        setActiveInlineEditState(null);
        if (newVal !== oldValue) {
          const currentText = editor.value || '';
          if (currentText.length <= 500000) pushUndoBeforeChange();
          const newText = replaceGlobalDescribeInSource(currentText, newVal);
          applyEditorChange(newText, editor.selectionStart, editor.selectionEnd);
          setStatus(true, '已更新波形说明');
        }
      };

      overlay.addEventListener('blur', commit);
      overlay.addEventListener('keydown', (e) => {
        e.stopPropagation();
        vwdDebugLog('inline-edit', {
          phase: 'key-down',
          field: 'description',
          isGlobal: true,
          key: e.key,
          code: e.code,
          ctrlKey: e.ctrlKey,
          metaKey: e.metaKey,
          targetValueLen: overlay.value.length
        });
        const isSubmitKey = (e.key === 'Enter' || e.key === 'NumpadEnter');
        if (isSubmitKey) {
          if (e.ctrlKey || e.metaKey) {
            e.preventDefault();
            insertInlineNewline(overlay, e);
            resizeDescriptionOverlay();
            return;
          }
          e.preventDefault();
          commit();
        }
        if (e.key === 'Escape') {
          committed = true;
          overlay.remove();
          inlineEditActive = false;
          setActiveInlineEditState(null);
        }
      });
    }

    function attachGlobalDescribeInteractivity(jsonText, parsedSource) {
      const svg = waveContainer.querySelector('svg');
      if (!svg) return;

      // Multi-wave cards render the document description below the SVG so it
      // never overlaps WaveDrom's foot area.
      if (waveContainer.closest('.wave-document-card')) return;

      let parsed = parsedSource;
      try {
        if (!parsed) parsed = JSON.parse(jsonText);
      } catch (e) {
        return;
      }

      const existing = svg.querySelector('#vwd-global-describe');
      if (existing) existing.remove();

      const describe = getGlobalDescribeOldValue(parsed);
      const svgBox = svg.viewBox && svg.viewBox.baseVal ? svg.viewBox.baseVal : null;
      const width = svgBox && svgBox.width ? svgBox.width : parseFloat(svg.getAttribute('width') || '0');
      const height = svgBox && svgBox.height ? svgBox.height : parseFloat(svg.getAttribute('height') || '0');
      const textEl = document.createElementNS('http://www.w3.org/2000/svg', 'text');
      textEl.setAttribute('id', 'vwd-global-describe');
      const lineCount = Math.max(1, String(describe || '点击添加波形说明').split(/\r?\n/).length);
      textEl.setAttribute('x', '8');
      textEl.setAttribute('y', String(Math.max(14, height - 8 - ((lineCount - 1) * 15))));
      textEl.setAttribute('text-anchor', 'start');
      textEl.setAttribute('class', 'wave-global-describe-text' + (describe ? '' : ' empty'));
      renderMultilineSvgText(textEl, describe || '点击添加波形说明');
      textEl.addEventListener('click', (e) => {
        if (!isTextEditModeActive()) return;
        e.stopPropagation();
        startGlobalDescribeInlineEdit(textEl);
      });
      svg.appendChild(textEl);
    }

    function attachWaveInteractivity(jsonText, parsedSource) {
      const svg = waveContainer.querySelector('svg');
      if (!svg) return;

      const sourceMap = buildSignalSourceMap(jsonText);
      const lanes = getWaveLaneGroups(svg);
      const unitWidth = getWaveUnitWidth(jsonText, parsedSource);
      const maxBoundaryIndex = getConnectionPickBoundaryIndex(sourceMap);
      const maxWaveColumnCount = Math.max(1, getMaxWaveBoundaryIndex(sourceMap));
      const visibleSet = getNavVisibleRowSet();
      const hasFilter = isNavFilteringActive();

      lanes.forEach((lane, idx) => {
        const entry = sourceMap[idx];
        const visible = !hasFilter || visibleSet.has(idx);
        lane.classList.toggle('wave-lane-hidden', !visible);
        lane.style.display = visible ? '' : 'none';
        if (!entry) return;
        if (!visible) return;

        lane.classList.add('wave-lane-interactive');
        addLaneHoverRect(lane, maxBoundaryIndex, unitWidth);

        function resolveLaneColumnIndex(clientX, inPickFlow) {
          const drawGroup = lane.querySelector('[id^="wavelane_draw_"]');
          const wave = entry.signal.wave || '';
          const pickMaxBoundaryIndex = inPickFlow ? maxBoundaryIndex : 0;
          if (drawGroup) {
            return inPickFlow
              ? boundaryIndexFromClick(drawGroup, wave, svg, clientX, unitWidth, pickMaxBoundaryIndex)
              : paintColumnIndexFromClick(drawGroup, wave, svg, clientX, unitWidth, maxWaveColumnCount);
          }
          return virtualLaneIndexFromClick(
            lane,
            svg,
            clientX,
            unitWidth,
            inPickFlow ? pickMaxBoundaryIndex : maxWaveColumnCount,
            inPickFlow
          );
        }

        function handleLanePointSelect(e) {
          if (lane.dataset.vwdSuppressClick === '1') {
            delete lane.dataset.vwdSuppressClick;
            e.preventDefault();
            e.stopPropagation();
            return;
          }
          if (inlineEditActive) return;
          if (e.vwdLanePickHandled) return;
          e.vwdLanePickHandled = true;
          if (app.classList.contains('reading-mode')) return;

          if (groupPickActive) {
            beginHandleGroupPickFromRow(idx, lanes);
            return;
          }

          const drawGroup = lane.querySelector('[id^="wavelane_draw_"]');
          const wave = entry.signal.wave || '';
          const inPickFlow = isConnectionPickFlow();
          const pickMaxBoundaryIndex = inPickFlow ? maxBoundaryIndex : 0;
          const colIndex = resolveLaneColumnIndex(e.clientX, inPickFlow);
          setSelectedSignal(idx, colIndex);
          lanes.forEach((l, i) => l.classList.toggle('wave-lane-selected', i === idx));

          if (wavePaintModeActive) {
            if (!wavePaintChar) {
              setStatus(false, '请先在波形菜单中选择要绘制的波形按钮');
              vwdDebugLog('wave-paint', { phase: 'paint-blocked', rowIndex: idx, colIndex, reason: 'no-char' });
              return;
            }
            applyWavePaintCharAtColumn(idx, colIndex, wavePaintChar);
            return;
          }

          if (inPickFlow) {
            let svgPoint = null;
            const coordinateGroup = drawGroup || lane;
            if (coordinateGroup && svg && coordinateGroup.getScreenCTM && svg.getScreenCTM) {
              try {
                const boundaryX = drawGroup
                  ? getBoundaryXForColumn(drawGroup, wave, colIndex, unitWidth, pickMaxBoundaryIndex)
                  : colIndex * getWaveColumnWidth(unitWidth);
                let boundaryY = 0;
                try {
                  const coordinateBox = coordinateGroup.getBBox();
                  boundaryY = coordinateBox.y + coordinateBox.height / 2;
                } catch (_e) { /* keep row-local center fallback */ }
                const localPoint = svg.createSVGPoint();
                localPoint.x = boundaryX;
                localPoint.y = boundaryY;
                const screenPoint = localPoint.matrixTransform(coordinateGroup.getScreenCTM());
                const clientPoint = svg.createSVGPoint();
                clientPoint.x = screenPoint.x;
                clientPoint.y = screenPoint.y;
                const svgCoords = clientPoint.matrixTransform(svg.getScreenCTM().inverse());
                const laneCenterY = getLaneCenterSvgY(svg, lane);
                svgPoint = {
                  svgX: svgCoords.x,
                  svgY: Number.isFinite(laneCenterY) ? laneCenterY : svgCoords.y
                };
              } catch (err) { /* fall back to lazy SVG measurement */ }
            }
            const pickResult = handleConnectionPointClick(idx, colIndex, Object.assign({}, svgPoint || {}, { entry }));
            scheduleConnectionHighlightUpdate(lanes, sourceMap);
            if (pickResult === 'insert-queued') return;
            return;
          }

          setWaveClipboardShortcutActive(true, 'wave-click');
          setGroupDeleteShortcutActive(false, 'wave-selected');
          scheduleConnectionHighlightUpdate(lanes, sourceMap);
          requestAnimationFrame(() => scrollEditorToSignal(entry));
          setStatus(true, '已选中: ' + entry.signal.name + ' [' + colIndex + ']=' + JSON.stringify(wave[colIndex] || ''));
        }

        if (lane.dataset.vwdLaneBound !== '1') {
          lane.dataset.vwdLaneBound = '1';
          const canStartWaveRangeSelection = (e) => {
            if (e.pointerType === 'mouse' && e.button !== 0) return false;
            if (inlineEditActive || app.classList.contains('reading-mode')) return false;
            if (groupPickActive || wavePaintModeActive || isConnectionPickFlow() || connectionSelectActive) return false;
            if (isTextEditModeActive()) return false;
            const target = e.target && e.target.closest ? e.target : null;
            if (target && (target.closest('text.info')
                || target.closest('.wave-name-click-zone')
                || target.closest('.wave-describe-text'))) return false;
            return true;
          };

          const finishWaveRangeSelection = (e, cancelled) => {
            if (!waveSelectionDrag
                || waveSelectionDrag.pointerId !== e.pointerId
                || waveSelectionDrag.rowIndex !== idx) return;
            const finished = waveSelectionDrag;
            waveSelectionDrag = null;
            lane.dataset.vwdSuppressClick = '1';
            window.setTimeout(() => {
              if (lane.dataset.vwdSuppressClick === '1') delete lane.dataset.vwdSuppressClick;
            }, 0);
            try {
              if (lane.hasPointerCapture(e.pointerId)) lane.releasePointerCapture(e.pointerId);
            } catch (_e) { /* ignore */ }
            updateLegendAvailability();
            scheduleConnectionHighlightUpdate(lanes, sourceMap);
            const range = getSelectedWaveRange(idx);
            if (!cancelled && range) {
              requestAnimationFrame(() => scrollEditorToSignal(entry));
              const count = range.end - range.start + 1;
              setStatus(
                true,
                count > 1
                  ? '已选中第 ' + (range.start + 1) + ' 至 ' + (range.end + 1) + ' 格，共 ' + count + ' 格'
                  : '已选中: ' + entry.signal.name + ' [' + range.start + ']'
              );
            }
            vwdDebugLog('wave-selection', {
              phase: cancelled ? 'drag-cancel' : 'drag-end',
              rowIndex: idx,
              anchorCol: finished.anchorCol,
              currentCol: finished.currentCol,
              moved: finished.moved
            });
          };

          lane.addEventListener('pointerdown', (e) => {
            if (!canStartWaveRangeSelection(e)) return;
            setWaveClipboardShortcutActive(true, 'wave-pointerdown');
            setGroupDeleteShortcutActive(false, 'wave-selected');
            const colIndex = resolveLaneColumnIndex(e.clientX, false);
            waveSelectionDrag = {
              pointerId: e.pointerId,
              rowIndex: idx,
              anchorCol: colIndex,
              currentCol: colIndex,
              moved: false
            };
            setSelectedWaveRange(idx, colIndex, colIndex);
            lanes.forEach((currentLane, laneIndex) => {
              currentLane.classList.toggle('wave-lane-selected', laneIndex === idx);
            });
            scheduleConnectionHighlightUpdate(lanes, sourceMap);
            try { lane.setPointerCapture(e.pointerId); } catch (_e) { /* ignore */ }
            e.preventDefault();
            vwdDebugLog('wave-selection', { phase: 'drag-start', rowIndex: idx, colIndex });
          });

          lane.addEventListener('pointermove', (e) => {
            if (!waveSelectionDrag
                || waveSelectionDrag.pointerId !== e.pointerId
                || waveSelectionDrag.rowIndex !== idx) return;
            const colIndex = resolveLaneColumnIndex(e.clientX, false);
            if (colIndex === waveSelectionDrag.currentCol) return;
            waveSelectionDrag.currentCol = colIndex;
            waveSelectionDrag.moved = true;
            setSelectedWaveRange(
              idx,
              waveSelectionDrag.anchorCol,
              colIndex,
              { deferGroupRefresh: true, deferControls: true }
            );
            scheduleConnectionHighlightUpdate(lanes, sourceMap);
            e.preventDefault();
          });

          lane.addEventListener('pointerup', (e) => finishWaveRangeSelection(e, false));
          lane.addEventListener('pointercancel', (e) => finishWaveRangeSelection(e, true));
          lane.addEventListener('click', (e) => {
            const isText = e.target.closest('text') || e.target.classList.contains('wave-text-edit-overlay');
            const isNameZone = e.target.classList.contains('wave-name-click-zone');
            if ((isText || isNameZone) && !isConnectionPickFlow() && !groupPickActive) return;
            handleLanePointSelect(e);
          });
        }

        attachSignalNameEdit(lane, entry, handleLanePointSelect);
        attachSignalDescribeInteractivity(lane, entry, handleLanePointSelect);

        const drawGroup = lane.querySelector('[id^="wavelane_draw_"]');
        if (drawGroup) {
          const dataTexts = drawGroup.querySelectorAll('text');
          dataTexts.forEach((textEl, dataIdx) => {
            if (textEl.dataset.vwdDataBound === '1') return;
            textEl.dataset.vwdDataBound = '1';
            textEl.dataset.vwdDataIndex = String(dataIdx);
            textEl.classList.add('wave-data-text');
            textEl.addEventListener('click', (e) => {
              if (isTextEditModeActive()) return;
              e.stopPropagation();
              e.preventDefault();
              handleLanePointSelect(e);
            });
          });
          attachDataLabelTextEditHandler(drawGroup, entry, svg);
        }
      });

      restoreWaveSelection(lanes, sourceMap);
      attachGroupInteractivity(jsonText);
      attachEdgeInteractivity(jsonText, parsedSource);
      attachHeadFootInteractivity(jsonText, parsedSource);
      attachGlobalDescribeInteractivity(jsonText, parsedSource);

      if (pendingNameEditSignalIndex >= 0
          && pendingNameEditSignalIndex < lanes.length
          && !app.classList.contains('reading-mode')) {
        const idx = pendingNameEditSignalIndex;
        pendingNameEditSignalIndex = -1;
        const lane = lanes[idx];
        const entry = sourceMap[idx];
        const nameText = lane && lane.querySelector('text.info');
        if (nameText && entry) {
          const anchor = hasVisibleSvgText(nameText)
            ? nameText
            : ensureSignalNameClickZone(lane, nameText);
          requestAnimationFrame(() => {
            if (!inlineEditActive) {
              startInlineEdit(nameText, entry, 'name', undefined, anchor);
            }
          });
        }
      }
    }

    function restoreBackBtnPosition() {
      try {
        const saved = localStorage.getItem(BACK_BTN_POS_KEY);
        if (saved) {
          const { left, top } = JSON.parse(saved);
          backBtn.style.left = left + 'px';
          backBtn.style.top = top + 'px';
        } else {
          backBtn.style.left = '16px';
          backBtn.style.top = '16px';
        }
      } catch (e) {
        backBtn.style.left = '16px';
        backBtn.style.top = '16px';
      }
    }

    function saveBackBtnPosition() {
      localStorage.setItem(BACK_BTN_POS_KEY, JSON.stringify({
        left: parseFloat(backBtn.style.left) || 16,
        top: parseFloat(backBtn.style.top) || 16
      }));
    }

    function initBackBtnDrag() {
      backBtn.addEventListener('pointerdown', (e) => {
        if (e.button !== 0) return;
        e.preventDefault();
        backBtnDrag = {
          pointerId: e.pointerId,
          startX: e.clientX,
          startY: e.clientY,
          origLeft: parseFloat(backBtn.style.left) || 16,
          origTop: parseFloat(backBtn.style.top) || 16,
          moved: false
        };
        backBtn.classList.add('dragging');
        backBtn.setPointerCapture(e.pointerId);
      });

      backBtn.addEventListener('pointermove', (e) => {
        if (!backBtnDrag || backBtnDrag.pointerId !== e.pointerId) return;
        const dx = e.clientX - backBtnDrag.startX;
        const dy = e.clientY - backBtnDrag.startY;
        if (!backBtnDrag.moved && Math.hypot(dx, dy) < DRAG_THRESHOLD) return;
        backBtnDrag.moved = true;
        const mainEl = backBtn.parentElement;
        const btnSize = 40;
        const maxLeft = mainEl.clientWidth - btnSize;
        const maxTop = mainEl.clientHeight - btnSize;
        const newLeft = Math.min(maxLeft, Math.max(0, backBtnDrag.origLeft + dx));
        const newTop = Math.min(maxTop, Math.max(0, backBtnDrag.origTop + dy));
        backBtn.style.left = newLeft + 'px';
        backBtn.style.top = newTop + 'px';
      });

      backBtn.addEventListener('pointerup', (e) => {
        if (!backBtnDrag || backBtnDrag.pointerId !== e.pointerId) return;
        backBtn.releasePointerCapture(e.pointerId);
        backBtn.classList.remove('dragging');
        if (backBtnDrag.moved) {
          saveBackBtnPosition();
        } else {
          exitReadingMode();
        }
        backBtnDrag = null;
      });

      backBtn.addEventListener('pointercancel', () => {
        backBtnDrag = null;
        backBtn.classList.remove('dragging');
      });
    }

    function updateLineNumbers() {
      const lines = editor.value.split('\n');
      const count = Math.max(lines.length, 1);
      lineNumbersEl.innerHTML = Array.from({ length: count }, (_, i) =>
        `<span class="${jsonErrorLine === i + 1 ? 'line-error' : ''}">${jsonErrorLine === i + 1 ? '<b aria-hidden="true">×</b>' : ''}${i + 1}</span>`
      ).join('');
    }

    function getJsonErrorLine(text, error) {
      const message = error && error.message ? String(error.message) : '';
      const match = message.match(/position\s+(\d+)/i);
      if (!match) return -1;
      const pos = Math.max(0, Math.min(Number(match[1]) || 0, text.length));
      let line = 1;
      for (let i = 0; i < pos; i++) {
        if (text.charCodeAt(i) === 10) line++;
      }
      return line;
    }

    function setJsonErrorLine(line) {
      const nextLine = Number.isFinite(line) ? line : -1;
      if (jsonErrorLine === nextLine) return;
      jsonErrorLine = nextLine;
      updateLineNumbers();
    }

    function syncLineNumberScroll() {
      lineNumbersEl.scrollTop = editor.scrollTop;
    }

    function setStatus(ok, message) {
      statusDot.classList.toggle('error', !ok);
      statusText.textContent = message;
    }

    function normalizeSavedTag(raw) {
      if (!raw || typeof raw.name !== 'string') return null;
      const content = typeof raw.content === 'string' ? raw.content
        : (typeof raw.json === 'string' ? raw.json : null);
      if (content == null) return null;
      return {
        name: raw.name.trim(),
        content: content,
        hscale: raw.hscale,
        waveEditMode: raw.waveEditMode,
        savedAt: raw.savedAt || new Date().toISOString()
      };
    }

    function rebuildSavedTagIndex() {
      savedTagByName = new Map();
      savedTags.forEach((tag) => savedTagByName.set(tag.name, tag));
      const validNames = new Set(savedTagByName.keys());
      waveDocumentMetaCache.forEach((_value, key) => {
        const separator = key.indexOf(':');
        const name = separator >= 0 ? key.slice(separator + 1) : key;
        if (key !== 'adhoc' && !validNames.has(name)) waveDocumentMetaCache.delete(key);
      });
    }

    function getSavedTagByName(name) {
      return savedTagByName.get(String(name || '')) || null;
    }

    function getWaveDocumentMeta(tag, preferEditor) {
      if (!tag) return { content: '', source: null, renderSource: null, title: '', description: '', error: null };
      const useEditor = preferEditor !== false && tag.name === editingWaveDocumentName;
      const content = useEditor ? (editor.value || '') : (tag.content || '');
      const cacheKey = (useEditor ? 'editor:' : 'saved:') + tag.name;
      const cached = waveDocumentMetaCache.get(cacheKey);
      if (cached && cached.content === content) return cached;

      let source = null;
      let error = null;
      try {
        source = JSON.parse(content);
      } catch (parseError) {
        error = parseError;
      }
      const title = source && typeof source.title === 'string' ? source.title.trim() : '';
      const head = source && source.head && typeof source.head.text === 'string' ? source.head.text.trim() : '';
      const meta = {
        content,
        source,
        renderSource: source ? getWaveRenderSource(source) : null,
        title: title || head,
        description: source ? getGlobalDescribeOldValue(source) : '',
        error
      };
      waveDocumentMetaCache.set(cacheKey, meta);
      return meta;
    }

    function getWaveTitleFromJson(text) {
      try {
        const parsed = JSON.parse(text);
        const title = parsed && typeof parsed.title === 'string' ? parsed.title.trim() : '';
        const head = parsed && parsed.head && typeof parsed.head.text === 'string' ? parsed.head.text.trim() : '';
        return title || head;
      } catch (_e) {
        return '';
      }
    }

    function getWaveRenderSource(source) {
      if (!source || typeof source !== 'object') return source;
      const title = typeof source.title === 'string' ? source.title.trim() : '';
      const head = source.head && typeof source.head.text === 'string' ? source.head.text.trim() : '';
      if (!title || head) return source;
      return Object.assign({}, source, {
        head: Object.assign({}, source.head || {}, { text: title })
      });
    }

    function getSavedTagTitle(tag) {
      if (!tag) return '';
      return getWaveDocumentMeta(tag, true).title || tag.name || '未命名波形图';
    }

    function getWaveDocumentDescription(tag) {
      if (!tag || !tag.content) return '';
      const meta = getWaveDocumentMeta(tag, true);
      if (!meta.error) return meta.description;
      return getWaveDocumentMeta(tag, false).description;
    }

    function refreshWaveDocumentTitle(documentName, force) {
      if (!documentName || !navTreeState) return false;
      const tag = getSavedTagByName(documentName);
      if (!tag) return false;
      const meta = getWaveDocumentMeta(tag, true);
      if (meta.error) return false;
      const title = meta.title || tag.name || '未命名波形图';
      if (!force && navDocumentTitleCache.get(documentName) === title) return false;
      navDocumentTitleCache.set(documentName, title);
      const parent = findNavDocumentParent(navTreeState, documentName);
      const displayName = getNavDocumentDisplayName(tag, parent);
      if (navTreeEl) {
        navTreeEl.querySelectorAll('.nav-tree-document-label').forEach((button) => {
          if (button.dataset.documentName !== documentName) return;
          button.textContent = displayName;
          button.title = '打开波形图: ' + displayName;
        });
      }
      const cardEntry = waveLibraryCardCache.get(documentName);
      if (cardEntry) cardEntry.title.textContent = displayName;
      vwdDebugLog('performance', { phase: 'title-refresh-local', documentName, title });
      return true;
    }

    function scheduleNavTitleRefresh() {
      if (!editingWaveDocumentName || !navTreeState) return;
      if (navTitleRefreshTimer !== null) clearTimeout(navTitleRefreshTimer);
      navTitleRefreshTimer = setTimeout(() => {
        navTitleRefreshTimer = null;
        refreshWaveDocumentTitle(editingWaveDocumentName, false);
      }, 350);
    }

    function getCurrentWaveTitle() {
      const tag = getSavedTagByName(editingWaveDocumentName);
      if (tag) return getWaveDocumentMeta(tag, true).title || activeTagName || '';
      return getWaveTitleFromJson(editor.value || '') || activeTagName || '';
    }

    function loadSavedTagsFromStorage() {
      try {
        let raw = localStorage.getItem(WAVE_DOCUMENTS_KEY);
        let isLegacy = false;
        if (!raw) {
          raw = localStorage.getItem(LEGACY_SAVED_TAGS_KEY);
          isLegacy = !!raw;
        }
        if (!raw) return [];
        const parsed = JSON.parse(raw);
        if (!Array.isArray(parsed)) return [];
        const documents = parsed.map(normalizeSavedTag).filter(Boolean);
        if (isLegacy) {
          localStorage.setItem(WAVE_DOCUMENTS_KEY, JSON.stringify(documents));
          vwdDebugLog('wave-library', { phase: 'migrate-legacy-tags', documentCount: documents.length });
        }
        return documents;
      } catch (e) {
        return [];
      }
    }

    function flushPersistSavedTags() {
      clearTimeout(savedTagsPersistTimer);
      savedTagsPersistTimer = null;
      try {
        localStorage.setItem(WAVE_DOCUMENTS_KEY, JSON.stringify(savedTags));
      } catch (e) { /* quota / private mode */ }
      scheduleWaveLibraryServerSave();
    }

    function persistSavedTags(options) {
      const opts = options || {};
      clearTimeout(savedTagsPersistTimer);
      if (opts.immediate) {
        flushPersistSavedTags();
        return;
      }
      savedTagsPersistTimer = setTimeout(flushPersistSavedTags, SAVED_TAGS_PERSIST_DEBOUNCE_MS);
    }

    function getWaveLibraryBundle() {
      const documents = savedTags.map((tag) => Object.assign({}, tag));
      const current = documents.find((tag) => tag.name === editingWaveDocumentName);
      if (current) Object.assign(current, getCurrentStateSnapshot());
      return {
        kind: WAVE_LIBRARY_KIND,
        version: 1,
        updatedAt: new Date().toISOString(),
        documents,
        directories: collectCustomNavNodes(navTreeState || { children: [] }),
        rootDocuments: navTreeState && Array.isArray(navTreeState.documents)
          ? navTreeState.documents.slice()
          : [],
        activeDocumentName: editingWaveDocumentName || '',
        selectedDirectoryId: selectedNavNodeId || 'nav-root'
      };
    }

    function updateWaveLibraryFileStatus() {
      if (waveLibraryFileStatus) {
        waveLibraryFileStatus.textContent = waveLibraryServerMode
          ? ('波形库：' + (currentWaveLibraryFile || '未加载'))
          : ('波形库：' + (currentWaveLibraryFile || '本地浏览器数据'));
      }
      if (saveWaveLibraryLabel) saveWaveLibraryLabel.textContent = waveLibraryServerMode ? '保存波形库' : '保存波形库';
    }

    function scheduleWaveLibraryServerSave() {
      if (!waveLibraryServerMode || applyingWaveLibraryBundle || !currentWaveLibraryFile) return;
      clearTimeout(waveLibrarySaveTimer);
      waveLibrarySaveTimer = setTimeout(() => {
        waveLibrarySaveTimer = null;
        fetch('/api/wave-library?file=' + encodeURIComponent(currentWaveLibraryFile), {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(getWaveLibraryBundle())
        }).catch(() => setStatus(false, '波形库自动保存失败'));
      }, 350);
    }

    function applyWaveLibraryBundle(bundle, fileName) {
      if (!bundle || bundle.kind !== WAVE_LIBRARY_KIND || !Array.isArray(bundle.documents)) {
        setStatus(false, '波形库文件格式无效');
        return false;
      }
      applyingWaveLibraryBundle = true;
      try {
        savedTags = bundle.documents.map(normalizeSavedTag).filter(Boolean);
        rebuildSavedTagIndex();
        persistSavedTags();
        saveNavCustomTreeToStorage(
          Array.isArray(bundle.directories) ? bundle.directories : [],
          Array.isArray(bundle.rootDocuments) ? bundle.rootDocuments : []
        );
        selectedNavNodeId = bundle.selectedDirectoryId || 'nav-root';
        selectedNavDocumentName = null;
        editingWaveDocumentName = null;
        activeTagName = null;
        const preferredName = bundle.activeDocumentName || (savedTags[0] && savedTags[0].name);
        const preferred = getSavedTagByName(preferredName) || savedTags[0];
        if (preferred) {
          editor.value = preferred.content;
          setEditorHistoryBaseline(editor.value);
        }
        rebuildNavTreeStateFromJson(editor.value || getDefaultJson());
        if (preferred) openWaveDocumentForEditing(preferred.name, { immediate: true });
        else {
          renderNavTree();
          renderWaveLibrary();
        }
        currentWaveLibraryFile = fileName || currentWaveLibraryFile;
        updateWaveLibraryFileStatus();
        setStatus(true, '已导入波形库：' + (currentWaveLibraryFile || '未命名'));
        return true;
      } finally {
        applyingWaveLibraryBundle = false;
      }
    }

    function downloadWaveLibraryBundle() {
      const blob = new Blob([JSON.stringify(getWaveLibraryBundle(), null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = currentWaveLibraryFile || 'VisualWaveDrom-library.json';
      document.body.appendChild(link);
      link.click();
      link.remove();
      setTimeout(() => URL.revokeObjectURL(url), 0);
      setStatus(true, '已保存波形库文件');
    }

    function importWaveLibraryFile(file) {
      if (!file) return;
      const reader = new FileReader();
      reader.onload = () => {
        try {
          const bundle = JSON.parse(String(reader.result || ''));
          applyWaveLibraryBundle(bundle, file.name);
        } catch (e) {
          setStatus(false, '波形库文件无法解析');
        }
      };
      reader.onerror = () => setStatus(false, '波形库文件读取失败');
      reader.readAsText(file, 'utf-8');
    }

    async function loadServerWaveLibrary(fileName) {
      const response = await fetch('/api/wave-library?file=' + encodeURIComponent(fileName));
      if (!response.ok) throw new Error('load failed');
      const bundle = await response.json();
      applyWaveLibraryBundle(bundle, fileName);
    }

    async function initializeServerWaveLibrary() {
      if (!waveLibraryServerMode) {
        updateWaveLibraryFileStatus();
        return;
      }
      fetch('/api/client-connect', { method: 'POST', keepalive: true }).catch(() => {});
      window.addEventListener('pagehide', () => {
        navigator.sendBeacon('/api/client-disconnect', '');
      }, { once: true });
      try {
        const response = await fetch('/api/wave-libraries');
        const catalog = await response.json();
        const fileName = catalog.current || (catalog.files && catalog.files[0]);
        if (fileName) await loadServerWaveLibrary(fileName);
        else updateWaveLibraryFileStatus();
      } catch (e) {
        updateWaveLibraryFileStatus();
        setStatus(false, '本地波形库服务不可用');
      }
    }

    async function changeServerWaveLibrary() {
      try {
        const response = await fetch('/api/wave-libraries');
        const catalog = await response.json();
        const files = catalog.files || [];
        if (!waveLibraryPickerModal || !waveLibraryPickerOptions) return;
        waveLibraryPickerOptions.innerHTML = '';
        files.forEach((fileName) => {
          const option = document.createElement('button');
          option.type = 'button';
          option.className = 'nav-move-option';
          option.textContent = fileName;
          option.addEventListener('click', async () => {
            waveLibraryPickerModal.hidden = true;
            try {
              await loadServerWaveLibrary(fileName);
            } catch (e) {
              setStatus(false, '更换波形库失败');
            }
          });
          waveLibraryPickerOptions.appendChild(option);
        });
        waveLibraryPickerModal.hidden = false;
      } catch (e) {
        setStatus(false, '更换波形库失败');
      }
    }

    function formatTagSavedTime(iso) {
      if (!iso) return '';
      try {
        const d = new Date(iso);
        if (Number.isNaN(d.getTime())) return '';
        const pad = (n) => String(n).padStart(2, '0');
        return pad(d.getMonth() + 1) + '-' + pad(d.getDate()) + ' ' + pad(d.getHours()) + ':' + pad(d.getMinutes());
      } catch (e) {
        return '';
      }
    }

    function getCurrentStateSnapshot() {
      return {
        content: editor.value,
        hscale: hscaleInput ? clampHscale(hscaleInput.value) : 1,
        waveEditMode: waveEditMode,
        savedAt: new Date().toISOString()
      };
    }

    function findSavedTagIndex(name) {
      const trimmed = String(name || '').trim();
      if (!trimmed) return -1;
      return savedTags.findIndex(t => t.name === trimmed);
    }

    function upsertSavedTag(name, snapshot, options) {
      const opts = options || {};
      const trimmed = String(name || '').trim();
      if (!trimmed) return false;
      const entry = Object.assign({ name: trimmed }, snapshot);
      const idx = findSavedTagIndex(trimmed);
      if (idx >= 0) savedTags[idx] = entry;
      else savedTags.push(entry);
      if (!opts.skipSort) {
        savedTags.sort((a, b) => new Date(b.savedAt) - new Date(a.savedAt));
      }
      savedTagByName.set(trimmed, entry);
      persistSavedTags();
      activeTagName = trimmed;
      if (!opts.skipListRefresh) renderSavedTagsList();
      return true;
    }

    function cloneWaveLibrarySnapshotValue(value) {
      return JSON.parse(JSON.stringify(value));
    }

    function captureWaveLibrarySnapshot() {
      return {
        savedTags: cloneWaveLibrarySnapshotValue(savedTags),
        customNodes: cloneWaveLibrarySnapshotValue(collectCustomNavNodes(navTreeState || { children: [] })),
        rootDocuments: cloneWaveLibrarySnapshotValue(
          navTreeState && Array.isArray(navTreeState.documents) ? navTreeState.documents : []
        ),
        selectedNavNodeId,
        selectedNavDocumentName,
        editingWaveDocumentName,
        activeTagName,
        editorValue: editor.value,
        selectionStart: editor.selectionStart,
        selectionEnd: editor.selectionEnd
      };
    }

    function restoreWaveLibrarySnapshot(snapshot) {
      if (!snapshot) return false;
      savedTags = (snapshot.savedTags || []).map(normalizeSavedTag).filter(Boolean);
      rebuildSavedTagIndex();
      persistSavedTags();
      saveNavCustomTreeToStorage(snapshot.customNodes || [], snapshot.rootDocuments || []);

      selectedNavNodeId = snapshot.selectedNavNodeId || 'nav-root';
      selectedNavDocumentName = snapshot.selectedNavDocumentName || null;
      editingWaveDocumentName = snapshot.editingWaveDocumentName || null;
      activeTagName = snapshot.activeTagName || null;
      editor.value = snapshot.editorValue || getDefaultJson();
      setEditorHistoryBaseline(editor.value);
      editor.selectionStart = Math.min(snapshot.selectionStart || 0, editor.value.length);
      editor.selectionEnd = Math.min(snapshot.selectionEnd || 0, editor.value.length);
      updateLineNumbers();
      syncLineNumberScroll();
      saveEditorJsonToStorage(editor.value);

      rebuildNavTreeStateFromJson(editor.value);
      renderWaveform(editor.value);
      renderNavTree();
      renderWaveLibrary();
      return true;
    }

    function pushWaveLibraryHistory(before, after) {
      checkpointDirectJsonEdit('before-wave-library-change');
      waveLibraryUndoStack.push({ before, after, sequence: nextHistorySequence() });
      if (waveLibraryUndoStack.length > 20) waveLibraryUndoStack.shift();
      waveLibraryRedoStack = [];
      redoStack = [];
      updateUndoRedoButtons();
    }

    function deleteSavedTag(name) {
      const before = captureWaveLibrarySnapshot();
      const idx = findSavedTagIndex(name);
      if (idx < 0) return false;
      savedTags.splice(idx, 1);
      rebuildSavedTagIndex();
      persistSavedTags();
      if (activeTagName === name) activeTagName = null;
      if (editingWaveDocumentName === name) editingWaveDocumentName = null;
      if (selectedNavDocumentName === name) selectedNavDocumentName = null;
      renderSavedTagsList();
      if (navTreeState) {
        (function removeDocumentReference(node) {
          node.documents = (node.documents || []).filter((documentName) => documentName !== name);
          (node.children || []).forEach(removeDocumentReference);
        })(navTreeState);
        saveNavCustomNodesFromTree();
        rebuildNavTreeStateFromJson(editor.value || '');
      }
      pushWaveLibraryHistory(before, captureWaveLibrarySnapshot());
      return true;
    }

    function renderSavedTagsList() {
      if (!savedTagsListEl || !savedTagsEmptyEl) return;
      savedTagsListEl.innerHTML = '';
      const hasTags = savedTags.length > 0;
      savedTagsEmptyEl.hidden = hasTags;

      savedTags.forEach((tag) => {
        const row = document.createElement('div');
        row.className = 'saved-tag-row';
        row.dataset.documentName = tag.name;
        if (tag.name === activeTagName) row.classList.add('active');
        row.title = '打开波形图: ' + getSavedTagTitle(tag);

        const nameEl = document.createElement('div');
        nameEl.className = 'saved-tag-name';
        nameEl.textContent = tag.name;

        const metaEl = document.createElement('div');
        metaEl.className = 'saved-tag-meta';
        metaEl.textContent = formatTagSavedTime(tag.savedAt);

        const delBtn = document.createElement('button');
        delBtn.type = 'button';
        delBtn.className = 'saved-tag-delete';
        delBtn.title = '删除波形图';
        delBtn.textContent = '删';
        delBtn.addEventListener('click', (e) => {
          e.stopPropagation();
          deleteSavedTag(tag.name);
          setStatus(true, '已删除波形图: ' + getSavedTagTitle(tag));
        });

        row.addEventListener('click', () => requestLoadTag(tag.name));

        row.appendChild(nameEl);
        row.appendChild(metaEl);
        row.appendChild(delBtn);
        savedTagsListEl.appendChild(row);
      });
    }

    function refreshSavedTagsActiveState() {
      if (!savedTagsListEl) return;
      savedTagsListEl.querySelectorAll('.saved-tag-row').forEach((row) => {
        row.classList.toggle('active', row.dataset.documentName === activeTagName);
      });
    }

    function currentStateMatchesTag(tag) {
      if (editor.value !== tag.content) return false;
      if (tag.waveEditMode && tag.waveEditMode !== waveEditMode) return false;
      return true;
    }

    function requestLoadTag(name) {
      const tag = getSavedTagByName(name);
      if (!tag) return;
      openWaveDocumentForEditing(name);
    }

    function closeTagLoadModal() {
      if (tagLoadModal) tagLoadModal.hidden = true;
      pendingLoadTagName = null;
    }

    function closeNavMoveModal() {
      if (navMoveModal) navMoveModal.hidden = true;
    }

    function closeWaveLibraryPickerModal() {
      if (waveLibraryPickerModal) waveLibraryPickerModal.hidden = true;
    }

    function confirmTagLoad() {
      const name = pendingLoadTagName;
      closeTagLoadModal();
      if (name) openWaveDocumentForEditing(name);
    }

    function clearActiveTagIfModified() {
      if (!activeTagName) return;
      const tag = getSavedTagByName(activeTagName);
      if (tag && !currentStateMatchesTag(tag)) {
        activeTagName = null;
        renderSavedTagsList();
      }
    }

    function saveCurrentWaveDocumentBeforeSwitch() {
      const name = editingWaveDocumentName;
      if (!name) return true;
      const documentEntry = getSavedTagByName(name);
      if (!documentEntry || currentStateMatchesTag(documentEntry)) return true;
      const saved = upsertSavedTag(name, getCurrentStateSnapshot(), {
        skipListRefresh: true,
        skipSort: true
      });
      if (saved) {
        vwdDebugLog('wave-library', { phase: 'auto-save-before-switch', documentName: name });
      }
      return saved;
    }

    function persistEditingWaveDocumentOnExit() {
      const name = editingWaveDocumentName;
      const documentEntry = name && getSavedTagByName(name);
      if (!documentEntry || currentStateMatchesTag(documentEntry)) return;
      upsertSavedTag(name, getCurrentStateSnapshot(), { skipListRefresh: true });
      vwdDebugLog('wave-library', { phase: 'auto-save-on-exit', documentName: name });
    }

    function cancelPendingWaveDocumentOpen() {
      waveDocumentOpenSequence += 1;
      if (pendingWaveDocumentOpenRaf !== null) {
        cancelAnimationFrame(pendingWaveDocumentOpenRaf);
        pendingWaveDocumentOpenRaf = null;
      }
    }

    function activateWaveDocumentForEditing(name, previousName, startedAt) {
      const tag = getSavedTagByName(name);
      if (!tag) return false;
      snapshotActiveWavePreview(name);
      editingWaveDocumentName = name;
      activeTagName = name;
      if (previousName && previousName !== name) refreshWaveDocumentCard(previousName);
      refreshWaveDocumentCard(name);
      loadSavedTag(name);
      const now = window.performance && typeof window.performance.now === 'function'
        ? window.performance.now()
        : Date.now();
      vwdDebugLog('performance', {
        phase: 'nav-document-activated',
        documentName: name,
        elapsedMs: Math.round((now - startedAt) * 10) / 10
      });
      return true;
    }

    function scheduleWaveDocumentActivation(name, previousName, startedAt) {
      const sequence = waveDocumentOpenSequence;
      pendingWaveDocumentOpenRaf = requestAnimationFrame(() => {
        if (sequence !== waveDocumentOpenSequence) return;
        pendingWaveDocumentOpenRaf = requestAnimationFrame(() => {
          pendingWaveDocumentOpenRaf = null;
          if (sequence !== waveDocumentOpenSequence) return;
          activateWaveDocumentForEditing(name, previousName, startedAt);
        });
      });
    }

    function openWaveDocumentForEditing(name, options) {
      if (!name) return;
      const opts = options || {};
      const startedAt = window.performance && typeof window.performance.now === 'function'
        ? window.performance.now()
        : Date.now();
      cancelPendingWaveDocumentOpen();
      exitWavePaintMode('switch-wave-document');
      if (editingWaveDocumentName === name) {
        selectNavDocumentInTree(name);
        focusWaveDocument(name);
        return;
      }
      if (!saveCurrentWaveDocumentBeforeSwitch()) {
        setStatus(false, '当前波形图自动保存失败');
        return;
      }
      const previousName = editingWaveDocumentName;
      selectNavDocumentInTree(name);
      focusWaveDocument(name);
      setStatus(true, '正在打开波形图: ' + getSavedTagTitle(getSavedTagByName(name) || { name: name, content: '{}' }));
      vwdDebugLog('performance', {
        phase: 'nav-document-jump-ready',
        documentName: name,
        deferred: !opts.immediate
      });
      if (opts.immediate) {
        activateWaveDocumentForEditing(name, previousName, startedAt);
      } else {
        scheduleWaveDocumentActivation(name, previousName, startedAt);
      }
    }

    function loadSavedTag(name) {
      const tag = getSavedTagByName(name);
      if (!tag) return;

      undoStack = [];
      redoStack = [];
      undoBurstCaptured = false;
      flushUndoDebounce();

      editor.value = tag.content;
      setEditorHistoryBaseline(tag.content);
      editor.selectionStart = 0;
      editor.selectionEnd = 0;
      clearSelectedGroupState();
      updateLineNumbers();
      syncLineNumberScroll();
      renderWaveform(tag.content);
      debouncedPersistEditorJson();

      if (tag.waveEditMode === 'modify' || tag.waveEditMode === 'insert') {
        setWaveEditMode(tag.waveEditMode);
      }

      activeTagName = name;
      refreshSavedTagsActiveState();
      refreshWaveDocumentCard(name);
      refreshWaveDocumentTitle(name, false);
      updateUndoRedoButtons();
      setStatus(true, '已打开波形图: ' + getSavedTagTitle(tag));
    }

    function initSavedTags() {
      savedTags = loadSavedTagsFromStorage();
      rebuildSavedTagIndex();
      renderSavedTagsList();
    }

    function copyTextWithFallback(text) {
      const execCopy = () => new Promise((resolve, reject) => {
        try {
          copyTextWithExecCommand(text);
          resolve();
        } catch (e) {
          reject(e);
        }
      });
      if (navigator.clipboard && typeof navigator.clipboard.writeText === 'function') {
        return navigator.clipboard.writeText(text).catch(() => execCopy());
      }
      return execCopy();
    }

    function copyTextWithExecCommand(text) {
      const ta = document.createElement('textarea');
      ta.value = text;
      ta.setAttribute('readonly', '');
      ta.style.position = 'fixed';
      ta.style.left = '-9999px';
      ta.style.top = '0';
      document.body.appendChild(ta);
      ta.select();
      ta.setSelectionRange(0, text.length);
      const ok = document.execCommand('copy');
      document.body.removeChild(ta);
      if (!ok) throw new Error('execCommand copy failed');
    }

    function makeExportFileName() {
      const now = new Date();
      const pad = (n) => String(n).padStart(2, '0');
      return 'VisualWaveDrom-'
        + now.getFullYear()
        + pad(now.getMonth() + 1)
        + pad(now.getDate())
        + '-'
        + pad(now.getHours())
        + pad(now.getMinutes())
        + pad(now.getSeconds())
        + '.json';
    }

    function exportWaveJson() {
      const text = formatJsonForDisplay(editor.value);
      try {
        JSON.parse(text);
      } catch (e) {
        setStatus(false, 'JSON 错误，无法导出');
        return;
      }
      const blob = new Blob([text + '\n'], { type: 'application/json;charset=utf-8' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = makeExportFileName();
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      setTimeout(() => URL.revokeObjectURL(url), 0);
      setStatus(true, '已导出 JSON 文件');
    }

    function isWaveDromReady() {
      return typeof WaveDrom !== 'undefined'
        && typeof WaveDrom.RenderWaveForm === 'function'
        && window.WaveSkin;
    }

    function showWaveError(container, message) {
      container.innerHTML = '';
      const errDiv = document.createElement('div');
      errDiv.className = 'wave-error';
      errDiv.textContent = message;
      container.appendChild(errDiv);
    }

    function scheduleRenderWaveform(jsonText, onComplete) {
      scheduledRenderText = jsonText;
      if (onComplete) {
        scheduledRenderCallbacks = scheduledRenderCallbacks || [];
        scheduledRenderCallbacks.push(onComplete);
      }
      if (renderWaveformRaf !== null) return;
      renderWaveformRaf = requestAnimationFrame(() => {
        renderWaveformRaf = null;
        const text = scheduledRenderText;
        const callbacks = scheduledRenderCallbacks;
        scheduledRenderText = null;
        scheduledRenderCallbacks = null;
        if (text == null) return;
        vwdMark('scheduleRenderWaveform:run');
        const ok = renderWaveform(text);
        if (callbacks) {
          callbacks.forEach((cb) => {
            try { cb(ok); } catch (e) { /* ignore */ }
          });
        }
      });
    }

    function renderWaveform(jsonText) {
      if (isRenderingWaveform) {
        pendingRenderText = jsonText;
        return false;
      }
      if (lastRenderedWaveText === jsonText && waveContainer.querySelector('svg')) {
        syncHscaleInputFromJson(jsonText, lastRenderedWaveSource);
        applyNavVisibilityToWave();
        renderConnectionEdgeList(lastRenderedWaveSource);
        vwdDebugLog('performance', { phase: 'active-render-cache-hit', textLength: jsonText.length });
        return true;
      }
      isRenderingWaveform = true;
      vwdMark('renderWaveform:start');

      try {
        waveContainer.innerHTML = '';

        if (!isWaveDromReady()) {
          showWaveError(waveContainer, 'JSON 解析错误: 内容为空');
          setStatus(false, '请先在波形区点击选中一行');
          return false;
        }

        if (!jsonText || !jsonText.trim()) {
          setJsonErrorLine(-1);
          showWaveError(waveContainer, 'JSON 解析错误: 内容为空');
          setStatus(false, '请先在波形区点击选中一行');
          return false;
        }

        let source;
        try {
          source = JSON.parse(jsonText);
          source = getWaveRenderSource(source);
          setJsonErrorLine(-1);
          if (!navTreeState) rebuildNavTreeStateFromJson(jsonText);
        } catch (e) {
          setJsonErrorLine(getJsonErrorLine(jsonText, e));
          showWaveError(waveContainer, '波形渲染错误: ' + e.message);
          setStatus(false, '请先在波形区点击选中一行');
          return false;
        }

        const displayDiv = document.createElement('div');
        displayDiv.id = 'wave-display-0';
        waveContainer.appendChild(displayDiv);

        try {
          if (!displayDiv.isConnected && editingWaveDocumentName) {
            renderWaveLibrary();
          }
          if (!displayDiv.isConnected) {
            throw new Error('波形渲染容器未挂载到页面');
          }
          WaveDrom.RenderWaveForm(0, source, 'wave-display-', false);
          if (!displayDiv.querySelector('svg')) {
            showWaveError(waveContainer, '波形渲染失败: 未生成 SVG');
            setStatus(false, '渲染错误');
            return false;
          }
          syncHscaleInputFromJson(jsonText, source);
          attachWaveInteractivity(jsonText, source);
          applyNavVisibilityToWave();
          renderConnectionEdgeList(source);
          fitWaveSvgToContent();
          lastRenderedWaveText = jsonText;
          lastRenderedWaveSource = source;
          vwdMark('renderWaveform:done');
          if (!isInsertingEdge && !waveformRenderingBusy) {
            setStatus(true, '波形已更新');
          }
          return true;
        } catch (e) {
          showWaveError(waveContainer, '波形渲染错误: ' + e.message);
          setStatus(false, '请先在波形区点击选中一行');
          return false;
        }
      } finally {
        isRenderingWaveform = false;
        if (pendingRenderText !== null) {
          const nextText = pendingRenderText;
          pendingRenderText = null;
          renderWaveform(nextText);
        }
      }
    }

    function debouncedRender() {
      clearTimeout(renderTimer);
      renderTimer = setTimeout(() => {
        renderTimer = null;
        scheduleRenderWaveform(editor.value);
      }, 300);
    }

    function debouncedSaveUndo() {
      markDirectJsonEdit();
    }

    function updateUndoRedoButtons() {
      const btnUndo = document.getElementById('btn-undo');
      const btnRedo = document.getElementById('btn-redo');
      btnUndo.disabled = !directJsonEditDirty
        && undoStack.length === 0
        && waveLibraryUndoStack.length === 0;
      btnRedo.disabled = directJsonEditDirty
        || (redoStack.length === 0 && waveLibraryRedoStack.length === 0);
    }

    function isModKey(e) {
      return e.ctrlKey || e.metaKey;
    }

    function isUndoShortcut(e) {
      if (!isModKey(e) || e.altKey) return false;
      return e.key.toLowerCase() === 'z' && !e.shiftKey;
    }

    function isRedoShortcut(e) {
      if (!isModKey(e) || e.altKey) return false;
      const key = e.key.toLowerCase();
      return (key === 'z' && e.shiftKey) || key === 'y';
    }

    function handleUndoRedoShortcut(e) {
      if (isUndoShortcut(e)) {
        e.preventDefault();
        undo();
        return true;
      }
      if (isRedoShortcut(e)) {
        e.preventDefault();
        redo();
        return true;
      }
      return false;
    }

    function getLastHistorySequence(stack) {
      if (!stack.length) return -1;
      return getHistorySequence(stack[stack.length - 1]);
    }

    function getNextRedoSequence(stack) {
      if (!stack.length) return Number.POSITIVE_INFINITY;
      return getHistorySequence(stack[stack.length - 1]);
    }

    function undo() {
      checkpointDirectJsonEdit('before-undo');
      const editorSequence = getLastHistorySequence(undoStack);
      const librarySequence = getLastHistorySequence(waveLibraryUndoStack);
      if (librarySequence > editorSequence) {
        const entry = waveLibraryUndoStack.pop();
        waveLibraryRedoStack.push(entry);
        isApplyingHistory = true;
        try {
          restoreWaveLibrarySnapshot(entry.before);
        } finally {
          isApplyingHistory = false;
        }
        setStatus(true, '已撤销波形库操作');
        vwdDebugLog('history', { phase: 'undo-library-operation', sequence: getHistorySequence(entry) });
        updateUndoRedoButtons();
        return;
      }
      if (undoStack.length === 0) return;
      flushUndoDebounce();
      undoBurstCaptured = false;
      const entry = undoStack.pop();
      isApplyingHistory = true;
      try {
        redoStack.push({
          content: editor.value,
          sequence: getHistorySequence(entry),
          reason: entry && entry.reason ? entry.reason : 'editor-change'
        });
        editor.value = getEditorHistoryContent(entry);
        setEditorHistoryBaseline(editor.value);
        updateLineNumbers();
        renderWaveform(editor.value);
        saveEditorJsonToStorage(editor.value);
      } finally {
        isApplyingHistory = false;
      }
      setStatus(true, '已撤销 JSON 修改');
      vwdDebugLog('history', { phase: 'undo-editor', sequence: getHistorySequence(entry), undoDepth: undoStack.length });
      updateUndoRedoButtons();
    }

    function redo() {
      checkpointDirectJsonEdit('before-redo');
      const editorSequence = getNextRedoSequence(redoStack);
      const librarySequence = getNextRedoSequence(waveLibraryRedoStack);
      if (librarySequence < editorSequence) {
        const entry = waveLibraryRedoStack.pop();
        waveLibraryUndoStack.push(entry);
        isApplyingHistory = true;
        try {
          restoreWaveLibrarySnapshot(entry.after);
        } finally {
          isApplyingHistory = false;
        }
        setStatus(true, '已重做波形库操作');
        vwdDebugLog('history', { phase: 'redo-library-operation', sequence: getHistorySequence(entry) });
        updateUndoRedoButtons();
        return;
      }
      if (redoStack.length === 0) return;
      flushUndoDebounce();
      undoBurstCaptured = false;
      const entry = redoStack.pop();
      isApplyingHistory = true;
      try {
        undoStack.push({
          content: editor.value,
          sequence: getHistorySequence(entry),
          reason: entry && entry.reason ? entry.reason : 'editor-change'
        });
        editor.value = getEditorHistoryContent(entry);
        setEditorHistoryBaseline(editor.value);
        updateLineNumbers();
        renderWaveform(editor.value);
        saveEditorJsonToStorage(editor.value);
      } finally {
        isApplyingHistory = false;
      }
      setStatus(true, '已重做 JSON 修改');
      vwdDebugLog('history', { phase: 'redo-editor', sequence: getHistorySequence(entry), redoDepth: redoStack.length });
      updateUndoRedoButtons();
    }

    function initEditor() {
      const initialJson = formatJsonForDisplay(loadEditorJsonFromStorage());
      editor.value = initialJson;
      undoStack = [];
      redoStack = [];
      setEditorHistoryBaseline(initialJson);
      flushUndoDebounce();
      updateLineNumbers();
      renderWaveform(initialJson);
      updateUndoRedoButtons();
      startDirectJsonEditMonitor();
    }

    function renderLegendItem(item, index) {
      const div = document.createElement('div');
      div.className = 'legend-item legend-disabled';
      div.dataset.waveChar = item.char;
      div.title = item.label + ' (' + item.char + ') — ' + item.desc;
      div.addEventListener('click', () => {
        if (wavePaintModeActive) {
          selectWavePaintChar(item.char);
          return;
        }
        if (selectedSignalIndex < 0) {
          setStatus(false, '请先在波形区点击选中一行');
          return;
        }
        applyLegendCharToSelection(item.char);
      });

      const label = document.createElement('div');
      label.className = 'legend-label';
      label.textContent = item.label;

      const badge = document.createElement('span');
      badge.className = 'legend-char-badge';
      badge.textContent = item.char;
      label.appendChild(badge);

      const desc = document.createElement('div');
      desc.className = 'legend-desc';
      desc.textContent = item.desc;

      const waveDiv = document.createElement('div');
      waveDiv.className = 'legend-wave';
      waveDiv.id = 'legend-wave-' + index;

      div.appendChild(label);
      div.appendChild(desc);
      div.appendChild(waveDiv);

      return div;
    }

    function focusWaveDocument(documentName) {
      if (!waveLibraryContainer) return;
      const entry = waveLibraryCardCache.get(documentName);
      const target = entry && entry.card.isConnected ? entry.card : null;
      const previous = waveLibraryContainer.querySelector('.wave-document-card.focused');
      if (previous && previous !== target) previous.classList.remove('focused');
      if (target) target.classList.add('focused');
      if (target && typeof target.scrollIntoView === 'function') {
        target.scrollIntoView({ behavior: 'auto', block: 'start' });
      }
      vwdDebugLog('wave-library', { phase: 'focus-document', documentName: documentName, found: !!target });
    }

    function startWaveDocumentDescriptionEdit(tag, descriptionEl) {
      if (!isTextEditModeActive()) return;
      exitWavePaintMode('wave-description');
      if (!tag || !descriptionEl) return;
      if (tag.name !== editingWaveDocumentName) {
        openWaveDocumentForEditing(tag.name, { immediate: true });
        setTimeout(() => {
          const card = waveLibraryContainer && waveLibraryContainer.querySelector('.wave-document-card.focused');
          const nextDescription = card && card.querySelector('.wave-document-description');
          if (nextDescription) startWaveDocumentDescriptionEdit(tag, nextDescription);
        }, 0);
        return;
      }
      if (descriptionEl.querySelector('textarea')) return;

      const oldValue = getWaveDocumentDescription(tag);
      const editorBox = document.createElement('textarea');
      editorBox.className = 'wave-document-description-editor';
      editorBox.value = oldValue;
      editorBox.placeholder = '输入波形图说明';
      descriptionEl.innerHTML = '';
      descriptionEl.classList.remove('empty');
      descriptionEl.appendChild(editorBox);
      autoResizeDescriptionOverlay(editorBox, { minHeight: 62, maxHeight: 260 });
      editorBox.focus();
      editorBox.select();

      let committed = false;
      const closeEditor = (value) => {
        descriptionEl.textContent = value || '暂无波形图说明';
        descriptionEl.classList.toggle('empty', !value);
        descriptionEl.title = '点击编辑波形图说明';
      };
      const commit = () => {
        if (committed) return;
        committed = true;
        const nextValue = editorBox.value;
        vwdDebugLog('wave-library', { phase: 'commit-description', documentName: tag.name, changed: nextValue !== oldValue, valueLength: nextValue.length });
        if (nextValue === oldValue) {
          closeEditor(oldValue);
          return;
        }
        let newText = replaceGlobalDescribeInSource(editor.value || '', nextValue);
        try {
          const verified = JSON.parse(newText);
          if (getGlobalDescribeOldValue(verified) !== nextValue) {
            const structured = JSON.parse(editor.value || '{}');
            structured.description = nextValue;
            delete structured.describe;
            newText = JSON.stringify(structured, null, 2);
          }
        } catch (_e) {
          setStatus(false, '说明保存失败：当前 JSON 无法解析');
          vwdDebugLog('wave-library', { phase: 'commit-description-error', documentName: tag.name, reason: 'invalid-json' });
          closeEditor(oldValue);
          return;
        }
        pushUndoBeforeChange();
        // A document description is rendered outside the SVG card, so avoid a
        // costly full WaveDrom redraw for large documents.
        editor.value = newText;
        setEditorHistoryBaseline(newText);
        updateLineNumbers();
        debouncedPersistEditorJson();
        debouncedSaveUndo();
        if (editingWaveDocumentName === tag.name) {
          upsertSavedTag(tag.name, getCurrentStateSnapshot());
        }
        closeEditor(nextValue);
        setStatus(true, '已保存波形图说明');
      };
      const doneButton = document.createElement('button');
      doneButton.type = 'button';
      doneButton.className = 'wave-document-description-done';
      doneButton.textContent = '完成';
      doneButton.title = '保存说明';
      doneButton.addEventListener('mousedown', (event) => {
        event.preventDefault();
        event.stopPropagation();
      });
      doneButton.addEventListener('click', (event) => {
        event.stopPropagation();
        commit();
      });
      descriptionEl.appendChild(doneButton);
      editorBox.addEventListener('input', () => autoResizeDescriptionOverlay(editorBox, { minHeight: 62, maxHeight: 260 }));
      editorBox.addEventListener('keydown', (event) => {
        event.stopPropagation();
        if (event.key === 'Tab') {
          event.preventDefault();
          const start = editorBox.selectionStart;
          const end = editorBox.selectionEnd;
          editorBox.value = editorBox.value.slice(0, start) + '  ' + editorBox.value.slice(end);
          editorBox.selectionStart = editorBox.selectionEnd = start + 2;
          autoResizeDescriptionOverlay(editorBox, { minHeight: 62, maxHeight: 260 });
          return;
        }
        if (event.key === 'Escape') {
          event.preventDefault();
          committed = true;
          closeEditor(oldValue);
        }
      });
      vwdDebugLog('wave-library', { phase: 'open-description-editor', documentName: tag.name });
    }

    function createWaveDocumentCard(documentName) {
      const sequence = ++waveLibraryCardSequence;
      const card = document.createElement('article');
      card.className = 'wave-document-card';
      card.dataset.documentName = documentName;

      const header = document.createElement('div');
      header.className = 'wave-document-card-header';
      const title = document.createElement('h2');
      const openButton = document.createElement('button');
      openButton.type = 'button';
      openButton.className = 'wave-document-open';
      openButton.title = '打开此波形图进行编辑';
      openButton.textContent = '打开';
      openButton.addEventListener('click', () => openWaveDocumentForEditing(documentName));
      const deleteButton = document.createElement('button');
      deleteButton.type = 'button';
      deleteButton.className = 'wave-document-delete';
      deleteButton.title = '删除波形图';
      deleteButton.textContent = '×';
      deleteButton.addEventListener('click', () => {
        const tag = getSavedTagByName(documentName);
        const titleText = getSavedTagTitle(tag || { name: documentName, content: '{}' });
        if (deleteSavedTag(documentName)) {
          setStatus(true, '已删除波形图: ' + titleText);
          vwdDebugLog('wave-library', { phase: 'delete-document', documentName });
        }
      });
      header.appendChild(title);
      header.appendChild(openButton);
      header.appendChild(deleteButton);

      const canvas = document.createElement('div');
      canvas.className = 'wave-document-canvas';
      canvas.addEventListener('pointerdown', () => {
        if (documentName !== editingWaveDocumentName) exitWavePaintMode('other-wave-document');
      });
      const previewHost = document.createElement('div');
      previewHost.className = 'wave-document-preview';
      const previewDisplay = document.createElement('div');
      const prefix = 'wave-library-display-' + sequence + '-';
      previewDisplay.id = prefix + '0';
      previewHost.appendChild(previewDisplay);

      const description = document.createElement('div');
      description.className = 'wave-document-description';
      description.addEventListener('click', (event) => {
        if (event.target && typeof event.target.closest === 'function'
            && event.target.closest('.wave-document-description-editor, .wave-document-description-done')) return;
        if (documentName !== editingWaveDocumentName || !isTextEditModeActive()) return;
        const tag = getSavedTagByName(documentName);
        if (tag) startWaveDocumentDescriptionEdit(tag, description);
      });

      canvas.appendChild(previewHost);
      canvas.appendChild(description);
      card.appendChild(header);
      card.appendChild(canvas);

      return {
        documentName,
        card,
        title,
        canvas,
        previewHost,
        previewDisplay,
        description,
        prefix,
        renderedContent: null,
        queuedContent: null,
        previewQueued: false
      };
    }

    function ensureWavePreviewDisplay(entry) {
      if (entry.previewDisplay.parentNode !== entry.previewHost) {
        entry.previewHost.replaceChildren(entry.previewDisplay);
      }
      if (entry.previewDisplay.id !== entry.prefix + '0') {
        entry.previewDisplay.id = entry.prefix + '0';
      }
      return entry.previewDisplay;
    }

    function renderWaveDocumentPreview(entry, tag) {
      if (!entry || !tag || tag.name === editingWaveDocumentName || !entry.card.isConnected) return false;
      const display = ensureWavePreviewDisplay(entry);
      if (entry.renderedContent === tag.content
          && (display.querySelector('svg') || display.querySelector('.wave-error'))) {
        return true;
      }

      display.innerHTML = '';
      const meta = getWaveDocumentMeta(tag, false);
      if (meta.error || !meta.renderSource) {
        showWaveError(display, '波形图渲染失败: ' + (meta.error && meta.error.message ? meta.error.message : '无效 JSON'));
        entry.renderedContent = tag.content;
        return false;
      }
      try {
        WaveDrom.RenderWaveForm(0, meta.renderSource, entry.prefix, false);
        if (!display.querySelector('svg')) throw new Error('未生成 SVG');
        entry.renderedContent = tag.content;
        vwdDebugLog('performance', { phase: 'preview-render', documentName: tag.name, textLength: tag.content.length });
        return true;
      } catch (error) {
        showWaveError(display, '波形图渲染失败: ' + (error && error.message ? error.message : '无效 JSON'));
        entry.renderedContent = tag.content;
        vwdDebugLog('wave-library', { phase: 'document-render-error', documentName: tag.name, message: error && error.message ? error.message : String(error) });
        return false;
      }
    }

    function runWaveLibraryPreviewQueue(deadline) {
      waveLibraryPreviewWorkHandle = null;
      let processed = 0;
      while (waveLibraryPreviewQueue.length > 0) {
        if (processed > 0 && deadline && typeof deadline.timeRemaining === 'function' && deadline.timeRemaining() < 4) break;
        const entry = waveLibraryPreviewQueue.shift();
        entry.previewQueued = false;
        const tag = getSavedTagByName(entry.documentName);
        if (tag && entry.queuedContent === tag.content) renderWaveDocumentPreview(entry, tag);
        processed += 1;
        if (!deadline && processed >= 1) break;
      }
      if (waveLibraryPreviewQueue.length > 0) scheduleWaveLibraryPreviewWork();
    }

    function scheduleWaveLibraryPreviewWork() {
      if (waveLibraryPreviewWorkHandle !== null || waveLibraryPreviewQueue.length === 0) return;
      if (typeof window.requestIdleCallback === 'function') {
        const id = window.requestIdleCallback(runWaveLibraryPreviewQueue, { timeout: 250 });
        waveLibraryPreviewWorkHandle = { kind: 'idle', id };
      } else {
        const id = setTimeout(() => runWaveLibraryPreviewQueue(null), 16);
        waveLibraryPreviewWorkHandle = { kind: 'timeout', id };
      }
    }

    function queueWaveLibraryPreview(entry, tag, priority) {
      if (!entry || !tag || tag.name === editingWaveDocumentName) return;
      entry.queuedContent = tag.content;
      if (!entry.previewQueued) {
        entry.previewQueued = true;
        if (priority) waveLibraryPreviewQueue.unshift(entry);
        else waveLibraryPreviewQueue.push(entry);
      }
      scheduleWaveLibraryPreviewWork();
    }

    function ensureWaveLibraryPreviewObserver() {
      if (waveLibraryPreviewObserver || typeof window.IntersectionObserver !== 'function') {
        return waveLibraryPreviewObserver;
      }
      waveLibraryPreviewObserver = new IntersectionObserver((items) => {
        items.forEach((item) => {
          if (!item.isIntersecting) return;
          const entry = waveLibraryCardCache.get(item.target.dataset.documentName || '');
          const tag = entry && getSavedTagByName(entry.documentName);
          if (entry && tag) queueWaveLibraryPreview(entry, tag, true);
        });
      }, { root: null, rootMargin: WAVE_PREVIEW_ROOT_MARGIN, threshold: 0 });
      return waveLibraryPreviewObserver;
    }

    function snapshotActiveWavePreview(nextActiveName) {
      const currentCard = waveContainer.closest('.wave-document-card');
      const currentName = currentCard && currentCard.dataset.documentName;
      if (!currentName || currentName === nextActiveName) return;
      const entry = waveLibraryCardCache.get(currentName);
      const tag = getSavedTagByName(currentName);
      if (!entry) return;

      const activeDisplay = waveContainer.querySelector('#wave-display-0');
      const canClone = tag && activeDisplay && lastRenderedWaveText === tag.content;
      const clones = canClone
        ? Array.from(activeDisplay.childNodes).map((node) => node.cloneNode(true))
        : [];
      const display = ensureWavePreviewDisplay(entry);
      display.replaceChildren(...clones);
      entry.renderedContent = canClone ? tag.content : null;
      if (!canClone && tag) queueWaveLibraryPreview(entry, tag, true);
    }

    function mountWaveContainerOutsideLibrary() {
      if (!wavePanel || waveContainer.parentNode === wavePanel) return;
      wavePanel.insertBefore(waveContainer, waveLibraryContainer);
    }

    function updateWaveDocumentCard(entry, tag, isEditingDocument) {
      const parent = findNavDocumentParent(navTreeState, tag.name);
      entry.title.textContent = getNavDocumentDisplayName(tag, parent);
      entry.card.classList.toggle('focused', isEditingDocument);

      const descriptionText = getWaveDocumentDescription(tag);
      if (!entry.description.querySelector('textarea')) {
        entry.description.textContent = descriptionText || '暂无波形图说明';
      }
      entry.description.classList.toggle('empty', !descriptionText);
      const descriptionEditable = isEditingDocument && isTextEditModeActive();
      entry.description.classList.toggle('editable', descriptionEditable);
      entry.description.title = descriptionEditable ? '点击编辑波形图说明' : '';

      const observer = ensureWaveLibraryPreviewObserver();
      if (isEditingDocument) {
        if (observer) observer.unobserve(entry.card);
        entry.previewQueued = false;
        entry.previewHost.replaceChildren(waveContainer);
        return;
      }

      ensureWavePreviewDisplay(entry);
      const contentChanged = entry.renderedContent !== tag.content;
      if (contentChanged) {
        entry.previewDisplay.innerHTML = '';
        entry.renderedContent = null;
      }
      if (observer) {
        if (contentChanged) observer.unobserve(entry.card);
        observer.observe(entry.card);
      }
      else queueWaveLibraryPreview(entry, tag, false);
    }

    function refreshWaveDocumentCard(documentName) {
      const entry = waveLibraryCardCache.get(documentName);
      const tag = getSavedTagByName(documentName);
      if (!entry || !tag || !entry.card.isConnected) return false;
      updateWaveDocumentCard(entry, tag, documentName === editingWaveDocumentName);
      return true;
    }

    function pruneWaveLibraryCardCache() {
      waveLibraryCardCache.forEach((entry, name) => {
        if (savedTagByName.has(name)) return;
        if (waveLibraryPreviewObserver) waveLibraryPreviewObserver.unobserve(entry.card);
        entry.card.remove();
        waveLibraryCardCache.delete(name);
      });
      waveLibraryPreviewQueue = waveLibraryPreviewQueue.filter((entry) => savedTagByName.has(entry.documentName));
    }

    function renderWaveLibrary() {
      if (!waveLibraryContainer) return;
      if (!isWaveDromReady() || !navTreeState) {
        waveLibraryContainer.hidden = true;
        return;
      }

      const selected = getNavNodeById(navTreeState, selectedNavNodeId) || navTreeState;
      const documentNames = collectNavDocuments(selected, []).filter((name) => savedTagByName.has(name));
      const activeName = documentNames.includes(editingWaveDocumentName) ? editingWaveDocumentName : null;
      snapshotActiveWavePreview(activeName);
      if (!activeName) mountWaveContainerOutsideLibrary();

      const entries = documentNames.map((documentName) => {
        let entry = waveLibraryCardCache.get(documentName);
        if (!entry) {
          entry = createWaveDocumentCard(documentName);
          waveLibraryCardCache.set(documentName, entry);
        }
        updateWaveDocumentCard(entry, getSavedTagByName(documentName), documentName === activeName);
        return entry;
      });

      entries.forEach((entry, index) => {
        const current = waveLibraryContainer.children[index];
        if (current !== entry.card) waveLibraryContainer.insertBefore(entry.card, current || null);
      });
      while (waveLibraryContainer.children.length > entries.length) {
        const extra = waveLibraryContainer.lastElementChild;
        if (waveLibraryPreviewObserver) waveLibraryPreviewObserver.unobserve(extra);
        extra.remove();
      }
      pruneWaveLibraryCardCache();

      waveLibraryContainer.hidden = documentNames.length === 0;
      vwdDebugLog('performance', {
        phase: 'library-reconcile',
        selectedId: selected.id,
        documentCount: documentNames.length,
        cachedCardCount: waveLibraryCardCache.size
      });
    }

    function renderLegends() {
      const list = document.getElementById('legend-list');
      LEGEND_ITEMS.forEach((item, index) => {
        list.appendChild(renderLegendItem(item, index));
      });

      if (!isWaveDromReady()) return;

      LEGEND_ITEMS.forEach((item, index) => {
        const container = document.getElementById('legend-wave-' + index);
        if (!container) return;
        const prefix = 'legend-display-' + index + '-';
        const displayDiv = document.createElement('div');
        displayDiv.id = prefix + '0';
        container.appendChild(displayDiv);
        try {
          WaveDrom.RenderWaveForm(0, item.wave, prefix, false);
        } catch (e) {
          showWaveError(container, '图例渲染失败');
        }
      });
    }

    function renderConnectionPresets() {
      document.querySelectorAll('#connection-arrow-controls [data-arrow-style]').forEach((button) => {
        if (button.dataset.vwdBound === '1') return;
        button.dataset.vwdBound = '1';
        button.addEventListener('click', () => handleConnectionArrowStyleClick(button.dataset.arrowStyle));
      });
      document.querySelectorAll('#connection-list [data-line-style]').forEach((button) => {
        if (button.dataset.vwdBound === '1') return;
        button.dataset.vwdBound = '1';
        button.addEventListener('click', () => handleConnectionLineStyleClick(button.dataset.lineStyle));
      });
      updateConnectionPropertiesUI();
    }

    function enterReadingMode() {
      exitWavePaintMode('reading-mode');
      app.classList.add('reading-mode');
      restoreBackBtnPosition();
      renderWaveform(editor.value);
    }

    function exitReadingMode() {
      app.classList.remove('reading-mode');
    }

    editor.addEventListener('input', () => {
      updateLineNumbers();
      captureUndoIfNeeded();
      debouncedSaveUndo();
      debouncedRender();
      debouncedPersistEditorJson();
      clearActiveTagIfModified();
      scheduleNavTitleRefresh();
    });

    const editorPanel = document.getElementById('editor-panel');
    if (editorPanel) {
      editorPanel.addEventListener('pointerdown', () => exitWavePaintMode('json-panel'));
    }

    document.addEventListener('pointerdown', (e) => {
      const target = e.target && e.target.closest ? e.target : null;
      const keepsWaveClipboardContext = !!(target && (
        target.closest('.wave-lane-interactive')
        || target.closest('.legend-item')
        || target.closest('#btn-copy-wave-selection')
        || target.closest('#btn-paste-wave-selection')
      ));
      if (!keepsWaveClipboardContext) {
        setWaveClipboardShortcutActive(false, 'pointer-outside-wave-selection');
      }
      const keepsGroupDeleteContext = !!(target && (
        target.closest('.wave-group-label-hit')
        || target.closest('[data-vwd-group-label]')
      ));
      if (!keepsGroupDeleteContext) {
        setGroupDeleteShortcutActive(false, 'pointer-outside-group-label');
      }
    }, true);

    editor.addEventListener('scroll', syncLineNumberScroll);
    editor.addEventListener('blur', () => {
      flushUndoDebounce();
      finalizeUndoBurst();
    });

    document.addEventListener('keydown', (e) => {
      if (handleUndoRedoShortcut(e)) return;
      if (handleWaveClipboardShortcut(e)) return;
      handleSelectionDeleteShortcut(e);
    }, true);
    document.addEventListener('copy', handleWaveClipboardEvent, true);
    document.addEventListener('paste', handleWaveClipboardEvent, true);
    document.addEventListener('click', cancelConnectionSelectionForOtherButton, true);

    editor.addEventListener('keydown', (e) => {
      if (e.key === 'Tab') {
        e.preventDefault();
        captureUndoIfNeeded();
        const start = editor.selectionStart;
        const end = editor.selectionEnd;
        editor.value = editor.value.substring(0, start) + '  ' + editor.value.substring(end);
        editor.selectionStart = editor.selectionEnd = start + 2;
        updateLineNumbers();
        debouncedSaveUndo();
        debouncedRender();
        debouncedPersistEditorJson();
      }
    });

    window.addEventListener('beforeunload', () => {
      persistEditingWaveDocumentOnExit();
      flushPersistSavedTags();
      flushPersistEditorJson();
    });

    ensureDebugModeButton();
    ensureCopyDebugLogButton();

    document.getElementById('btn-reading-mode').addEventListener('click', enterReadingMode);
    if (toggleNavSidebarBtn) {
      toggleNavSidebarBtn.addEventListener('click', () => {
        setNavSidebarHidden(!app.classList.contains('nav-sidebar-hidden'), true);
      });
    }
    if (importWaveLibraryBtn && waveLibraryImportInput) {
      importWaveLibraryBtn.addEventListener('click', () => {
        if (waveLibraryServerMode) {
          changeServerWaveLibrary();
          return;
        }
        waveLibraryImportInput.value = '';
        waveLibraryImportInput.click();
      });
      waveLibraryImportInput.addEventListener('change', (e) => importWaveLibraryFile(e.target.files && e.target.files[0]));
    }
    if (saveWaveLibraryBtn) {
      saveWaveLibraryBtn.addEventListener('click', async () => {
        if (!waveLibraryServerMode) {
          downloadWaveLibraryBundle();
          return;
        }
        if (!currentWaveLibraryFile) return;
        try {
          const response = await fetch('/api/wave-library?file=' + encodeURIComponent(currentWaveLibraryFile), {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(getWaveLibraryBundle())
          });
          if (!response.ok) throw new Error('save failed');
          setStatus(true, '已保存波形库：' + currentWaveLibraryFile);
        } catch (e) {
          setStatus(false, '波形库保存失败');
        }
      });
    }
    if (toggleJsonPanelBtn) {
      toggleJsonPanelBtn.addEventListener('click', () => {
        setJsonPanelHidden(!app.classList.contains('json-panel-hidden'), true);
      });
    }
    document.getElementById('btn-undo').addEventListener('click', undo);
    document.getElementById('btn-redo').addEventListener('click', redo);
    const debugModeBtn = document.getElementById('btn-debug-mode');
    if (debugModeBtn) {
      debugModeBtn.addEventListener('click', toggleDebugMode);
    }
    hscaleInput.addEventListener('change', applyHscaleFromInput);
    hscaleInput.addEventListener('blur', applyHscaleFromInput);
    hscaleInput.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') {
        e.preventDefault();
        applyHscaleFromInput();
        hscaleInput.blur();
      }
    });
    document.getElementById('btn-add-signal').addEventListener('click', () => insertNewSignalRow());
    document.getElementById('btn-copy-signal').addEventListener('click', () => copySelectedSignalRow());
    document.getElementById('btn-copy-wave-selection').addEventListener('click', copySelectedWaveRange);
    document.getElementById('btn-paste-wave-selection').addEventListener('click', pasteCopiedWaveRange);
    document.getElementById('btn-delete-signal').addEventListener('click', () => deleteSelectedSignalRow());
    document.getElementById('btn-group-signal').addEventListener('click', () => groupSelectedSignalRow());
    document.getElementById('btn-move-signal-up').addEventListener('click', () => { void moveSelectedSignalRow(-1); });
    document.getElementById('btn-move-signal-down').addEventListener('click', () => { void moveSelectedSignalRow(1); });
    document.getElementById('btn-add-connection').addEventListener('click', () => {
      beginEdgeAddSession();
    });
    document.getElementById('btn-select-connection').addEventListener('click', () => {
      if (connectionSelectActive) {
        const hadSelectedEdge = selectedEdgeIndex >= 0;
        setConnectionSelectActive(false);
        setStatus(true, hadSelectedEdge ? '已取消连接线选择' : '已退出选择连接线模式');
      } else {
        beginEdgeSelectSession();
      }
    });
    bindNavControlButtons();
    document.getElementById('btn-apply-edge-label').addEventListener('click', applyEdgeLabelFromInput);
    document.getElementById('connection-label-input').addEventListener('keydown', (e) => {
      if (e.key === 'Enter') {
        e.preventDefault();
        applyEdgeLabelFromInput();
      }
    });
    if (typeof window !== 'undefined') {
      window.__vwdSetDebugMode = (enabled) => {
        setDebugMode(!!enabled);
      };
      window.__vwdGetDebugState = () => ({
        enabled: vwdDebugEnabled,
        sessionStartedAt: vwdDebugSessionStartedAt,
        totalLogs: vwdDebugLogEntries.length,
        textEditModeActive,
        inlineEditState: activeInlineEditState
      });
      window.__vwdGetDebugLogText = () => getDebugLogText();
      window.__vwdClearDebugLogs = () => {
        vwdDebugLogEntries.length = 0;
      };
      window.__vwdGetConnectionState = () => ({
        connectionPickActive,
        connectionAddSessionActive,
        connectionSelectActive,
        connectionFromPoint,
        connectionToPoint,
        pendingEdgeTemplate,
        connectionArrowStyle,
        connectionLineStyle,
        isInsertingEdge,
        isRenderingWaveform,
        waveformRenderingBusy,
        selectedEdgeIndex
      });
      window.__vwdGetWavePaintState = () => ({
        active: wavePaintModeActive,
        char: wavePaintChar,
        selectedSignalIndex,
        selectedWaveColumnIndex
      });
      window.__vwdGetWaveSelectionState = () => ({
        selectedSignalIndex,
        selectedWaveColumnIndex,
        range: getSelectedWaveRange(),
        copiedWaveSelection,
        waveClipboardShortcutActive,
        groupDeleteShortcutActive,
        drag: waveSelectionDrag
      });
      window.__vwdGetPresetHighlightIndex = () => {
        const el = document.querySelector('#connection-list [data-line-style].active');
        return el ? CONNECTION_LINE_STYLES.indexOf(el.dataset.lineStyle) : -1;
      };
      window.__vwdFindPresetIndexForEdge = findPresetIndexForEdge;
      window.__vwdGetPerf = () => vwdPerfMarks.slice();
      window.__vwdClearPerf = () => { vwdPerfMarks.length = 0; };
    }
    document.getElementById('btn-wave-edit-mode').addEventListener('click', toggleWaveEditMode);
    document.getElementById('btn-wave-paint-mode').addEventListener('click', toggleWavePaintMode);
    document.getElementById('btn-wave-text-edit-mode').addEventListener('click', toggleTextEditMode);
    document.getElementById('btn-delete-wave-col').addEventListener('click', () => {
      if (connectionSelectActive && selectedEdgeIndex >= 0) {
        deleteEdgeAtIndex(selectedEdgeIndex);
        return;
      }
      deleteSelectedWaveRange();
    });
    document.getElementById('btn-format-json').addEventListener('click', formatEditorJson);
    if (wavePanel) {
      wavePanel.addEventListener('wheel', handleWavePanelWheelPaging, { passive: false });
    }
    document.getElementById('btn-export-json').addEventListener('click', exportWaveJson);
    const copyDebugLogBtn = document.getElementById('btn-copy-debug-log');
    if (copyDebugLogBtn) {
      copyDebugLogBtn.addEventListener('click', copyDebugLogsToClipboard);
    }
    document.getElementById('tag-load-cancel').addEventListener('click', closeTagLoadModal);
    document.getElementById('tag-load-confirm').addEventListener('click', confirmTagLoad);
    if (tagLoadModal) {
      tagLoadModal.addEventListener('click', (e) => {
        if (e.target === tagLoadModal) closeTagLoadModal();
      });
    }
    const navMoveCancelBtn = document.getElementById('nav-move-cancel');
    if (navMoveCancelBtn) navMoveCancelBtn.addEventListener('click', closeNavMoveModal);
    if (navMoveModal) {
      navMoveModal.addEventListener('click', (e) => {
        if (e.target === navMoveModal) closeNavMoveModal();
      });
    }
    const moveDistanceCancelBtn = document.getElementById('move-distance-cancel');
    const moveDistanceConfirmBtn = document.getElementById('move-distance-confirm');
    if (moveDistanceCancelBtn) {
      moveDistanceCancelBtn.addEventListener('click', () => closeMoveDistanceModal(null));
    }
    if (moveDistanceConfirmBtn) {
      moveDistanceConfirmBtn.addEventListener('click', confirmMoveDistanceModal);
    }
    if (moveDistanceInput) {
      moveDistanceInput.addEventListener('input', () => {
        if (moveDistanceHint) moveDistanceHint.textContent = '';
      });
      moveDistanceInput.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' || e.key === 'NumpadEnter') {
          e.preventDefault();
          e.stopPropagation();
          confirmMoveDistanceModal();
          return;
        }
        if (e.key === 'Escape') {
          e.preventDefault();
          e.stopPropagation();
          closeMoveDistanceModal(null);
        }
      });
    }
    if (moveDistanceModal) {
      moveDistanceModal.addEventListener('click', (e) => {
        if (e.target === moveDistanceModal) closeMoveDistanceModal(null);
      });
    }
    const waveLibraryPickerCancelBtn = document.getElementById('wave-library-picker-cancel');
    if (waveLibraryPickerCancelBtn) waveLibraryPickerCancelBtn.addEventListener('click', closeWaveLibraryPickerModal);
    if (waveLibraryPickerModal) {
      waveLibraryPickerModal.addEventListener('click', (e) => {
        if (e.target === waveLibraryPickerModal) closeWaveLibraryPickerModal();
      });
    }
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && moveDistanceModal && !moveDistanceModal.hidden) {
        e.preventDefault();
        closeMoveDistanceModal(null);
        return;
      }
      if (e.key === 'Escape' && tagLoadModal && !tagLoadModal.hidden) {
        e.preventDefault();
        closeTagLoadModal();
        return;
      }
      if (e.key === 'Escape' && navMoveModal && !navMoveModal.hidden) {
        e.preventDefault();
        closeNavMoveModal();
        return;
      }
      if (e.key === 'Escape' && waveLibraryPickerModal && !waveLibraryPickerModal.hidden) {
        e.preventDefault();
        closeWaveLibraryPickerModal();
      }
    });

    initBackBtnDrag();
    initNavSidebarResize();

    window.addEventListener('load', () => {
      migrateSessionStorageToLocal(WAVE_EDIT_MODE_KEY);
      migrateSessionStorageToLocal(BACK_BTN_POS_KEY);
      migrateSessionStorageToLocal(NAV_SIDEBAR_WIDTH_KEY);
      migrateSessionStorageToLocal(NAV_SIDEBAR_HIDDEN_KEY);
      migrateSessionStorageToLocal(JSON_PANEL_HIDDEN_KEY);
      restoreJsonPanelVisibility();
      restoreNavSidebarVisibility();
      restoreNavSidebarWidth();
      loadWaveEditMode();
      initSavedTags();
      initEditor();
      seedRequestedWaveCopies();
      renderLegends();
      updateWavePaintModeUI();
      renderConnectionPresets();
      updateConnectionPresetDisabledState();
      renderConnectionEdgeList();
      updateEdgeLabelEditUI();
      restoreBackBtnPosition();
      updateConnectionPointStatusUI();
      setDebugModeUI(vwdDebugEnabled);
      setStatus(true, waveEditModeLabel());
      initializeServerWaveLibrary();
    });





